// Module-scope fallback used by the Service Inbox scanner.  Keeping this outside
// App() prevents ReferenceError if an older inner helper is removed or hidden by
// a hot-reload merge.
function safeServiceDocumentNameFromLink(link) {
  if (!link) return ''
  const clean = (value) => String(value || '')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&#39;/gi, "'")
    .replace(/&quot;/gi, '"')
    .replace(/&nbsp;/gi, ' ')
    .trim()
  const nameFromUrl = (url) => {
    try {
      const parsed = new URL(String(url || ''))
      const tail = decodeURIComponent((parsed.pathname || '').split('/').filter(Boolean).pop() || '')
      return tail && tail.includes('.') ? tail : ''
    } catch {
      return ''
    }
  }
  const candidates = [link.name, link.fileName, link.filename, link.label, nameFromUrl(link.url)]
    .map(clean)
    .filter(Boolean)
  const usable = candidates.find((value) => /\.pdf$/i.test(value))
    || candidates.find((value) => /pdf|document|download|filing|file[- ]?stamped/i.test(value) && !/^https?:/i.test(value))
    || ''
  return clean(usable)
    .replace(/download\/select the pdf to fill this from the pdf name/ig, '')
    .replace(/[\\/:*?"<>|]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 160)
}



function formatDiscoveryDateInputValue(value) {
  if (value === null || value === undefined || value === '') return ''
  const raw = String(value).trim()
  if (!raw) return ''
  if (raw.toLowerCase() === 'n/a' || raw.toLowerCase() === 'na') return 'N/A'
  const isoMatch = raw.match(/^(\d{4})-(\d{2})-(\d{2})/)
  if (isoMatch) return `${isoMatch[2]}/${isoMatch[3]}/${isoMatch[1]}`
  const slashMatch = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/)
  if (slashMatch) {
    const year = slashMatch[3].length === 2 ? `20${slashMatch[3]}` : slashMatch[3]
    return `${String(slashMatch[1]).padStart(2, '0')}/${String(slashMatch[2]).padStart(2, '0')}/${year}`
  }
  return raw
}

function normalizeDiscoveryDateInputEntry(value) {
  const raw = String(value || '').trim()
  if (!raw) return ''
  if (raw.toLowerCase() === 'n/a' || raw.toLowerCase() === 'na') return 'N/A'
  const slash = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/)
  if (slash) {
    const year = slash[3].length === 2 ? `20${slash[3]}` : slash[3]
    return `${String(slash[1]).padStart(2, '0')}/${String(slash[2]).padStart(2, '0')}/${year}`
  }
  const dash = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/)
  if (dash) return `${dash[2]}/${dash[3]}/${dash[1]}`
  return raw
}

function formatDiscoveryDateTypingValue(value) {
  const raw = String(value || '')
  if (/^n\/?a$/i.test(raw.trim()) || /^na$/i.test(raw.trim())) return 'N/A'
  const digits = raw.replace(/\D/g, '').slice(0, 8)
  if (!digits) return ''
  if (digits.length <= 2) return digits
  if (digits.length <= 4) return `${digits.slice(0, 2)}/${digits.slice(2)}`
  return `${digits.slice(0, 2)}/${digits.slice(2, 4)}/${digits.slice(4)}`
}

function DiscoveryDateInput({ value, onChange }) {
  const [draftValue, setDraftValue] = useState(() => formatDiscoveryDateInputValue(value))
  const isFocusedRef = useRef(false)

  useEffect(() => {
    if (!isFocusedRef.current) setDraftValue(formatDiscoveryDateInputValue(value))
  }, [value])

  return (
    <span style={{ display: 'inline-flex', gap: 4, alignItems: 'center', whiteSpace: 'nowrap' }}>
      <input
        type="text"
        inputMode="numeric"
        placeholder="mm/dd/yyyy"
        value={draftValue}
        onFocus={() => { isFocusedRef.current = true }}
        onChange={(e) => {
          const next = formatDiscoveryDateTypingValue(e.target.value)
          setDraftValue(next)
          onChange(next)
        }}
        onBlur={(e) => {
          isFocusedRef.current = false
          const normalized = normalizeDiscoveryDateInputEntry(e.target.value)
          setDraftValue(formatDiscoveryDateInputValue(normalized))
          onChange(normalized)
        }}
        style={{ width: 104 }}
      />
      <button
        type="button"
        onMouseDown={(e) => e.preventDefault()}
        onClick={() => {
          setDraftValue('N/A')
          onChange('N/A')
        }}
        title="Set this date to N/A"
      >N/A</button>
    </span>
  )
}

