const defaultScreenSaverSeconds = 150

function secondsToDurationText(totalSeconds) {
  const safeSeconds = Math.max(10, Math.min(600, Number(totalSeconds) || defaultScreenSaverSeconds))
  const minutes = Math.floor(safeSeconds / 60)
  const seconds = safeSeconds % 60
  if (minutes && seconds) return `${minutes}m ${seconds}s`
  if (minutes) return `${minutes}m`
  return `${seconds}s`
}

function parseDurationTextToSeconds(value, fallback = defaultScreenSaverSeconds) {
  const raw = String(value || '').trim().toLowerCase()
  if (!raw) return fallback
  const minuteMatch = raw.match(/(\d+(?:\.\d+)?)\s*(m|min|mins|minute|minutes)/)
  const secondMatch = raw.match(/(\d+)\s*(s|sec|secs|second|seconds)/)
  if (minuteMatch || secondMatch) {
    const minutes = minuteMatch ? Number(minuteMatch[1]) : 0
    const seconds = secondMatch ? Number(secondMatch[1]) : 0
    return Math.max(10, Math.min(600, Math.round(minutes * 60 + seconds)))
  }
  const colon = raw.match(/^(\d+):(\d{1,2})$/)
  if (colon) return Math.max(10, Math.min(600, Number(colon[1]) * 60 + Number(colon[2])))
  const numeric = Number(raw.replace(/[^0-9.]/g, ''))
  if (!Number.isFinite(numeric) || numeric <= 0) return fallback
  return Math.max(10, Math.min(600, Math.round(numeric)))
}

function buildDefaultScreenSaverRows(defaultSeconds = defaultScreenSaverSeconds) {
  return screenSaverBasePages.map((item) => ({
    ...item,
    selected: false,
    seconds: defaultSeconds,
    draftTime: secondsToDurationText(defaultSeconds),
    trackSlider: true
  }))
}

function normalizeScreenSaverRows(storedRows, defaultSeconds = defaultScreenSaverSeconds) {
  const storedByValue = new Map((Array.isArray(storedRows) ? storedRows : []).map((row) => [row.value, row]))
  const rows = screenSaverBasePages.map((base) => {
    const stored = storedByValue.get(base.value) || {}
    const seconds = parseDurationTextToSeconds(stored.draftTime || stored.seconds, defaultSeconds)
    return {
      ...base,
      selected: Boolean(stored.selected),
      seconds,
      draftTime: stored.draftTime || secondsToDurationText(seconds),
      trackSlider: stored.trackSlider !== false
    }
  })
  const order = Array.isArray(storedRows) ? storedRows.map((row) => row.value) : []
  if (!order.length) return rows
  return rows.sort((a, b) => {
    const aIndex = order.indexOf(a.value)
    const bIndex = order.indexOf(b.value)
    return (aIndex === -1 ? 999 : aIndex) - (bIndex === -1 ? 999 : bIndex)
  })
}


