function LabeledField({ label, children }) {
  return (
    <label style={{ display: 'flex', flexDirection: 'column', gap: 4, minWidth: 210 }}>
      <span style={{ fontWeight: 'bold', fontSize: 13 }}>{label}</span>
      {children}
    </label>
  )
}

function RichTextBox({ value = '', onChange, placeholder = '', minHeight = 110 }) {
  const editorRef = useRef(null)

  useEffect(() => {
    if (editorRef.current && editorRef.current.innerHTML !== (value || '')) {
      editorRef.current.innerHTML = value || ''
    }
  }, [value])

  function runCommand(command) {
    document.execCommand(command, false, null)
    onChange(editorRef.current?.innerHTML || '')
  }

  function handlePaste(e) {
    const imageItem = Array.from(e.clipboardData?.items || []).find((item) => item.type.startsWith('image/'))
    if (!imageItem) return

    e.preventDefault()
    const file = imageItem.getAsFile()
    const reader = new FileReader()
    reader.onload = () => {
      document.execCommand('insertImage', false, reader.result)
      onChange(editorRef.current?.innerHTML || '')
    }
    reader.readAsDataURL(file)
  }

  return (
    <div style={{ border: '1px solid #ccc', borderRadius: 4, background: 'white' }}>
      <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', borderBottom: '1px solid #ddd', padding: 6, background: '#f7f7f7' }}>
        <button type="button" onClick={() => runCommand('bold')}><strong>B</strong></button>
        <button type="button" onClick={() => runCommand('italic')}><em>I</em></button>
        <button type="button" onClick={() => runCommand('underline')}><u>U</u></button>
        <button type="button" onClick={() => runCommand('insertOrderedList')}>1.</button>
        <button type="button" onClick={() => runCommand('insertUnorderedList')}>•</button>
        <button type="button" onClick={() => runCommand('indent')}>Indent</button>
        <button type="button" onClick={() => runCommand('outdent')}>Outdent</button>
        <span style={{ fontSize: 12, color: '#666', alignSelf: 'center' }}>Paste images directly into the box</span>
      </div>
      <div
        ref={editorRef}
        contentEditable
        suppressContentEditableWarning
        data-placeholder={placeholder}
        onInput={(e) => onChange(e.currentTarget.innerHTML)}
        onPaste={handlePaste}
        style={{ minHeight, padding: 8, outline: 'none', overflow: 'auto' }}
      />
    </div>
  )
}


