function ensureRequestedReliefTableShape(table, index = 0) {
  const columns = Array.isArray(table?.columns) && table.columns.length ? table.columns.map((cell) => String(cell || '')) : ['Right/Duty', 'Both Parents', 'Only Mom', 'Only Dad', 'Notes']
  const rows = Array.isArray(table?.rows) ? table.rows.filter(Boolean).map((row, rowIndex) => {
    const rowCells = Array.isArray(row.cells) ? row.cells : []
    return {
      id: row.id || `rr-table-row-${Date.now()}-${index}-${rowIndex}`,
      cells: columns.map((_, cellIndex) => String(rowCells[cellIndex] || ''))
    }
  }) : []
  return {
    id: table?.id || `rr-table-${Date.now()}-${index}`,
    title: table?.title || `Requested Relief Table ${index + 1}`,
    collapsed: table?.collapsed !== false,
    columns,
    rows,
    is_active: table?.is_active !== false,
    sort_order: Number(table?.sort_order || index + 1)
  }
}

function ensureRequestedReliefOptionShape(option, index = 0) {
  return {
    id: option?.id || `rr-option-${Date.now()}-${index}`,
    parent_id: option?.parent_id || '',
    name: option?.name || 'Unnamed Relief Option',
    notes: option?.notes || '',
    is_active: option?.is_active !== false,
    is_relief_option: option?.is_relief_option === true,
    option_type: option?.option_type === 'exclusive' ? 'exclusive' : 'non_exclusive',
    has_text_box: option?.has_text_box === true,
    text_box_label: option?.text_box_label || '',
    sort_order: Number(option?.sort_order || index + 1)
  }
}


