function serviceEmailStatusLabel(status) {
  if (status === 'approved') return 'Approved'
  if (status === 'completed') return 'Completed'
  if (status === 'rejected') return 'Rejected'
  if (status === 'error') return 'Error'
  return 'Needs review'
}

