    if (!handle) return
    lastServiceEfileFolderHandleRef.current = handle
    if (matterId) matterEfileFolderHandlesRef.current[String(matterId)] = handle
    if (rowId) serviceEmailRowFolderHandlesRef.current[String(rowId)] = handle
