  useEffect(() => {
    if (page !== 'matter_timelines') return
    const measure = () => {
      const node = matterTimelineMainScrollRef.current
      const width = node?.clientWidth || (typeof window !== 'undefined' ? Math.max(800, window.innerWidth - 270) : 1400)
      setMatterTimelineViewportWidth(width)
    }
    measure()
    window.addEventListener('resize', measure)
    return () => window.removeEventListener('resize', measure)
  }, [page])

  useEffect(() => {
    if (page !== 'matter_timelines') return
    const timer = window.setTimeout(() => {
      const top = matterTimelineTopScrollRef.current
      const floating = matterTimelineFloatingScrollRef.current
      const main = matterTimelineMainScrollRef.current
      if (!top || !main) return

      const caseOptions = matterTimelineStatusOptions('case_status', 'case_status')
      const matterStatusOptions = matterTimelineStatusOptions('matter_status', 'matter_status')
      const rows = sortedMatterTimelineData(
        allMatterTimelineData().filter((row) => matterMatchesTimelineStatusFilters(row.matter, caseOptions, matterStatusOptions)),
        matterTimelineSortMode
      )
      const range = timelineRangeForRows(rows)
      const timelineSvgWidth = matterTimelineSvgWidthForRange(range)
      const fixedColumnsWidth = matterTimelineFixedColumnsWidth
      const totalDays = Math.max(1, daysBetweenTimelineDates(range.start, range.end))
      const today = startOfTodayTimeline()
      const todayX = Math.max(8, Math.min(timelineSvgWidth - 8, 8 + ((today - range.start) / 86400000 / totalDays) * (timelineSvgWidth - 16)))
      const targetScrollLeft = Math.max(0, todayX - 8)
      const applyTodayScroll = () => {
        const maxTop = Math.max(0, top.scrollWidth - top.clientWidth)
        const maxMain = Math.max(0, main.scrollWidth - main.clientWidth)
        top.scrollLeft = Math.min(targetScrollLeft, maxTop)
        main.scrollLeft = Math.min(targetScrollLeft, maxMain)
        if (floating) floating.scrollLeft = Math.min(targetScrollLeft, Math.max(0, floating.scrollWidth - floating.clientWidth))
      }
      applyTodayScroll()
      window.requestAnimationFrame(applyTodayScroll)
    }, 0)
    return () => window.clearTimeout(timer)
  }, [page, matterTimelineSortMode, matterTimelineCaseStatusFilters, matterTimelineMatterStatusFilters, matterTimelineOptions, matterTimelineDateAdjustments, matters, events, documents, tags, courtTimelineRules, matterTimelineViewportWidth, matterTimelineHiddenOptionKeys, matterTimelineLayoutMode])


