  function safeSetLocalStorage(key, value) {
    try {
      saveMioStateKey(key, value)
    } catch (error) {
      console.warn(`${key} was too large for localStorage. Large file contents were not saved locally.`, error)
    }
  }

  function stripLargeFileData(rows) {
    return (Array.isArray(rows) ? rows : []).map((row) => {
      const { file_data, file_url, file, ...rest } = row || {}
      return rest
    })
  }

  function stripDiscoveryFileData(request) {
    const { file_data, file_url, file, responses, ...rest } = request || {}
    return {
      ...rest,
      responses: (Array.isArray(responses) ? responses : []).map((response) => {
        const { file_data: responseFileData, file_url: responseFileUrl, file: responseFile, ...responseRest } = response || {}
        return responseRest
      })
    }
  }

  function discoveryRequestsForStorage(requests) {
    return (Array.isArray(requests) ? requests : []).map(stripDiscoveryFileData)
  }

  function localFileReference(file) {
    return {
      file_name: file.name,
      file_type: file.type,
      file_size: file.size,
      file_url: URL.createObjectURL(file)
    }
  }

  async function fetchInitialData() {
    // Keep initial Supabase reads sequential so the auth token lock is not hit by
    // several table requests at the same time immediately after login/reload.
    await fetchTeam()
    await fetchClients()
    await fetchMatters()
    await fetchCourts()
    await fetchSettings()
    await fetchAiDocumentSettings()
    await fetchEvents()
    await fetchTasks()
  }

  async function checkCurrentUserAccess(email) {
    setLoginBlockedMessage('')

    const { data, error } = await supabase
      .from('team_members')
      .select('*')
      .ilike('email', email)
      .limit(1)
      .maybeSingle()

    if (error) {
      console.log(error.message)
      setCurrentTeamMember(null)
      return
    }

    if (data && data.is_active === false) {
      setLoginBlockedMessage('Your user account is inactive. Please contact the administrator.')
      await supabase.auth.signOut()
      setSession(null)
      setCurrentTeamMember(null)
      return
    }

    setCurrentTeamMember(data || null)

    const allowed = getAllowedPages(data)
    if (data && allowed.length > 0 && !allowed.includes(page)) {
      setPage(allowed[0])
    }
  }

  function getAllowedPages(member = currentTeamMember) {
    if (!member) return appPages.map((p) => p.value)
    if (member.is_active === false) return []

    if (Array.isArray(member.page_access) && member.page_access.length > 0) {
      return Array.from(new Set([...member.page_access, 'matter_timelines', 'tasks', 'billing', 'service_inbox', 'requested_relief', 'calendar', 'checklist', 'discovery', 'documents', 'elements', 'people', 'tags', 'workflow', 'screensaver', 'ideas', 'settings']))
    }

    return appPages.map((p) => p.value)
  }

  function canOpenPage(pageName) {
    // Service Inbox is a newly added core page. Existing team-member page_access
    // records may not contain it yet, so keep it visible instead of letting the
    // legacy page-access record hide it after login finishes loading.
    if (pageName === 'service_inbox') return true
    return getAllowedPages().includes(pageName)
  }

  async function logIn(e) {
    e.preventDefault()
    setLoginBlockedMessage('')

    const { data, error } = await supabase.auth.signInWithPassword({
      email: loginEmail,
      password: loginPassword
    })

    if (error) {
      alert(error.message)
      return
    }

    setSession(data?.session || null)
  }

  async function logOut() {
    await supabase.auth.signOut()
    setTeam([])
    setClients([])
    setMatters([])
    setCourts([])
    setSettings([])
    setEvents([])
    setTasks([])
    setTaskAssignments([])
    setTaskComments([])
    setTaskFiles([])
    setTaskViews([])
    setCurrentTeamMember(null)
  }

  async function fetchTeam() {
    const { data, error } = await supabase
      .from('team_members')
      .select('*')
      .order('created_at', { ascending: false })

    if (error) alert(error.message)
    else setTeam(data || [])
  }

  async function fetchClients() {
    const { data, error } = await supabase
      .from('clients')
      .select('*')
      .order('created_at', { ascending: false })

    if (error) alert(error.message)
    else setClients(data || [])
  }

  async function fetchMatters() {
    const { data, error } = await supabase
      .from('matters')
      .select(`
        *,
        clients(first_name, last_name, email, phone, address, city, state, zip, notes, is_active),
        courts(
          court_name,
          county,
          court_phone,
          court_address,
          court_coordinator,
          court_coordinator_email,
          court_coordinator_phone,
          court_website,
          court_docket
        )
      `)
      .order('created_at', { ascending: false })

    if (error) alert(error.message)
    else setMatters(data || [])
  }

  async function fetchCourts() {
    const { data, error } = await supabase
      .from('courts')
      .select('*')
      .order('court_name', { ascending: true })

    if (error) alert(error.message)
    else setCourts(data || [])
  }

  async function fetchSettings() {
    const { data, error } = await supabase
      .from('setting_options')
      .select('*')
      .order('category', { ascending: true })
      .order('sort_order', { ascending: true, nullsFirst: false })
      .order('name', { ascending: true })

    if (error) alert(error.message)
    else setSettings(data || [])
  }

  async function fetchAiDocumentSettings() {
    if (!session?.user?.id) return
    const userId = session.user.id

    const [tagRulesResult, fieldDefinitionsResult, fieldTagRulesResult] = await Promise.all([
      supabase
        .from('document_ai_tag_rules')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false }),
      supabase
        .from('document_field_definitions')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false }),
      supabase
        .from('document_field_tag_rules')
        .select('*')
        .eq('user_id', userId)
        .order('created_at', { ascending: false })
    ])

    if (tagRulesResult.error) alert(tagRulesResult.error.message)
    else setAiTagRules(tagRulesResult.data || [])

    if (fieldDefinitionsResult.error) alert(fieldDefinitionsResult.error.message)
    else setDocumentFieldDefinitions(fieldDefinitionsResult.data || [])

    if (fieldTagRulesResult.error) alert(fieldTagRulesResult.error.message)
    else setDocumentFieldTagRules(fieldTagRulesResult.data || [])
  }

  async function fetchEvents() {
    const { data, error } = await supabase
      .from('calendar_events')
      .select(`
        *,
        matters(
          id,
          name,
          cause_number,
          case_status,
          matter_status,
          clients(first_name, last_name),
          courts(
            court_name,
            county,
            court_phone,
            court_address,
            court_coordinator,
            court_coordinator_email,
            court_coordinator_phone,
            court_website,
            court_docket
          )
        ),
        team_members(first_name, last_name)
      `)
      .order('start_date', { ascending: true })
      .order('start_time', { ascending: true })
      .range(0, 4999)

    if (error) alert(error.message)
    else setEvents(data || [])
  }

  async function fetchTasks() {
    const { data: taskData, error: taskError } = await supabase
      .from('tasks')
      .select(`
        *,
        matters(
          id,
          name,
          cause_number,
          notes,
          opposing_party,
          opposing_counsel,
          opposing_counsel_email,
          opposing_counsel_phone,
          clients(first_name, last_name, email, phone, address, city, state, zip),
          courts(
            court_name,
            county,
            court_phone,
            court_address,
            court_coordinator,
            court_coordinator_email,
            court_coordinator_phone,
            court_website,
            court_docket
          )
        )
      `)
      .order('created_at', { ascending: true })

    if (taskError) {
      alert(taskError.message)
      return
    }

    const taskIds = (taskData || []).map((task) => task.id)

    if (taskIds.length === 0) {
      setTasks([])
      setTaskAssignments([])
      setTaskComments([])
      setTaskFiles([])
      setTaskViews([])
      return
    }

    const [{ data: assignments }, { data: comments }, { data: files }, { data: views }] = await Promise.all([
      supabase.from('task_assignments').select('*, team_members(first_name, last_name, email)').in('task_id', taskIds),
      supabase.from('task_comments').select('*, team_members(first_name, last_name, email)').in('task_id', taskIds).order('created_at', { ascending: true }),
      supabase.from('task_files').select('*').in('task_id', taskIds),
      supabase.from('task_views').select('*').in('task_id', taskIds)
    ])

    setTasks(taskData || [])
    setTaskAssignments(assignments || [])
    setTaskComments(comments || [])
    setTaskFiles(files || [])
    setTaskViews(views || [])
  }


  function options(category) {
    return settings
      .filter((item) => item.category === category && item.is_active)
      .sort((a, b) => {
        const aOrder = a.sort_order ?? 999999
        const bOrder = b.sort_order ?? 999999
        if (aOrder !== bOrder) return aOrder - bOrder
        return String(a.name || '').localeCompare(String(b.name || ''))
      })
  }

  function teamPositions() {
    return settings
      .filter((item) => item.category === 'team_position' && item.is_active)
      .sort((a, b) => {
        const aOrder = a.sort_order ?? 999999
        const bOrder = b.sort_order ?? 999999
        if (aOrder !== bOrder) return aOrder - bOrder
        return String(a.name || '').localeCompare(String(b.name || ''))
      })
  }

  function subtypeOptionsForMatterType(matterType) {
    return settings.filter((item) => {
      return item.category === 'matter_subtype' && item.is_active && item.parent_name === matterType
    })
  }

  function eventSubcategoryOptionsForCategory(category) {
    return settings.filter((item) => {
      return item.category === 'event_subcategory' && item.is_active && item.parent_name === category
    })
  }

  function eventCategoryColor(categoryName, subcategoryName = '') {
    const subcategory = settings.find((item) => item.category === 'event_subcategory' && item.name === subcategoryName && item.parent_name === categoryName)
    if (subcategory?.color) return subcategory.color

    const category = settings.find((item) => item.category === 'event_category' && item.name === categoryName)
    if (category?.color) return category.color

    return '#3174ad'
  }


  function eventBlockColor(event) {
    return event.is_active === false ? '#8a8a8a' : eventCategoryColor(event.event_category, event.event_subcategory)
  }

  function clientOptionLabel(client) {
    return `${client.first_name || ''} ${client.last_name || ''}`.trim() || client.email || client.id
  }

  function matchesSmartSearch(text, optionText) {
    return String(optionText || '').toLowerCase().includes(String(text || '').toLowerCase())
  }

  function formatMatterOption(matter) {
    const clientName = `${matter.clients?.first_name || ''} ${matter.clients?.last_name || ''}`.trim()
    const cause = matter.cause_number ? ` - ${matter.cause_number}` : ''
    return `${matter.name}${clientName ? ` (${clientName})` : ''}${cause}`
  }

  function matterLabel(matterId) {
    const matter = matters.find((item) => item.id === matterId)
    return matter ? formatMatterOption(matter) : ''
  }

  function taskSubcategoryOptionsForCategory(taskCategory) {
    return settings.filter((item) => {
      return item.category === 'task_subcategory' && item.is_active && item.parent_name === taskCategory
    })
  }

  function taskTemplateMeta(option) {
    const meta = option?.default_pages
    if (meta && !Array.isArray(meta) && typeof meta === 'object') {
      return {
        assigned_user_id: meta.assigned_user_id || '',
        task_priority: meta.task_priority === 'high' ? 'high' : 'normal',
        instructions: meta.instructions || '',
        mark_review_when: meta.mark_review_when || '',
        subparts: Array.isArray(meta.subparts) ? meta.subparts : []
      }
    }

    return {
      assigned_user_id: '',
      task_priority: 'normal',
      instructions: '',
      mark_review_when: '',
      subparts: []
    }
  }

  function currentSettingTaskMeta() {
    if (settingForm.category !== 'task_subcategory') return taskTemplateMeta(null)
    return taskTemplateMeta({ default_pages: settingForm.default_pages })
  }

  function updateSettingTaskMeta(patch) {
    setSettingForm({
      ...settingForm,
      default_pages: {
        ...currentSettingTaskMeta(),
        ...patch
      }
    })
  }

  function updateSettingTaskSubpart(index, patch) {
    const meta = currentSettingTaskMeta()
    const subparts = [...meta.subparts]
    subparts[index] = { ...subparts[index], ...patch }
    updateSettingTaskMeta({ subparts })
  }

  function addSettingTaskSubpart() {
    const meta = currentSettingTaskMeta()
    updateSettingTaskMeta({ subparts: [...meta.subparts, { name: '', instructions: '' }] })
  }

  function removeSettingTaskSubpart(index) {
    const meta = currentSettingTaskMeta()
    updateSettingTaskMeta({ subparts: meta.subparts.filter((_subpart, subpartIndex) => subpartIndex !== index) })
  }

  function taskTemplateSubparts(task) {
    if (Array.isArray(task.template_subparts)) return task.template_subparts
    try {
      const saved = JSON.parse(localStorage.getItem(`taskTemplateSubparts:${task.id}`) || '[]')
      return Array.isArray(saved) ? saved : []
    } catch {
      return []
    }
  }

  function taskMarkReviewWhen(task) {
    return task.mark_review_when || localStorage.getItem(`taskMarkReviewWhen:${task.id}`) || ''
  }

  function taskPriority(task) {
    return task.task_priority || localStorage.getItem(`taskPriority:${task.id}`) || 'normal'
  }

  function completedTaskSubparts(task) {
    return taskSubpartCompletions[task.id] || {}
  }

  function taskSubpartProgress(task) {
    const subparts = taskTemplateSubparts(task)
    const completed = completedTaskSubparts(task)
    return {
      complete: subparts.filter((_subpart, index) => completed[index]).length,
      total: subparts.length
    }
  }

  function toggleTaskSubpartComplete(task, index) {
    const next = {
      ...taskSubpartCompletions,
      [task.id]: {
        ...(taskSubpartCompletions[task.id] || {}),
        [index]: !(taskSubpartCompletions[task.id] || {})[index]
      }
    }
    setTaskSubpartCompletions(next)
    saveMioStateKey('taskSubpartCompletions', JSON.stringify(next))
  }

  function templateMatterList() {
    return matterStatusSections.flatMap((section) => section.matters)
  }

  function selectedTemplateMatter() {
    return matters.find((matter) => matter.id === selectedTemplateMatterId)
  }

  function openMatterTaskTemplates(matter) {
    setSelectedTemplateMatterId(matter.id)
    setClientDashboardTab('matter_information')
    setPageState('tasks')
    if (typeof window !== 'undefined') window.history.replaceState(null, '', `#matter_dashboard:${encodeURIComponent(matter.id)}`)
  }

  function moveTemplateMatter(offset) {
    const list = templateMatterList()
    const currentIndex = list.findIndex((matter) => matter.id === selectedTemplateMatterId)
    if (currentIndex === -1) return
    const nextMatter = list[currentIndex + offset]
    if (nextMatter) setSelectedTemplateMatterId(nextMatter.id)
  }

  function openAddTaskFromTemplate(template, matter) {
    const meta = taskTemplateMeta(template)
    setEditingTaskId(null)
    setTaskForm({
      ...emptyTaskForm,
      matter_id: matter?.id || '',
      title: template.name || '',
      description: meta.instructions || '',
      assign_date: new Date().toISOString().slice(0, 10),
      task_category: template.parent_name || '',
      task_subcategory: template.name || '',
      assigned_user_ids: meta.assigned_user_id ? [meta.assigned_user_id] : [],
      template_subparts: meta.subparts || [],
      task_priority: meta.task_priority || 'normal',
      mark_review_when: meta.mark_review_when || '',
      is_active: true
    })
    setShowTaskWindow(true)
  }

  function taskTemplatesByCategory() {
    return options('task_category').map((category) => ({
      category,
      templates: taskSubcategoryOptionsForCategory(category.name)
    }))
  }

  function getLoggedInTeamMember() {
    return team.find((member) => member.email?.toLowerCase() === session?.user?.email?.toLowerCase())
  }

  function taskAssignmentsFor(taskId) {
    return taskAssignments.filter((assignment) => assignment.task_id === taskId)
  }

  function taskCommentsFor(taskId) {
    return taskComments.filter((comment) => comment.task_id === taskId)
  }

  function taskFilesFor(taskId) {
    return taskFiles.filter((file) => file.task_id === taskId && !file.comment_id)
  }

  function commentFilesFor(commentId) {
    return taskFiles.filter((file) => file.comment_id === commentId)
  }

  function assignedNames(taskId) {
    const assignments = taskAssignmentsFor(taskId)
    if (assignments.length === 0) return 'Unassigned'

    return assignments
      .map((assignment) => `${assignment.team_members?.first_name || ''} ${assignment.team_members?.last_name || ''}`.trim())
      .filter(Boolean)
      .join(', ')
  }

  function matterClientName(task) {
    const client = task.matters?.clients
    return `${client?.first_name || ''} ${client?.last_name || ''}`.trim()
  }

  function currentUserWasTaggedAndHasNotOpened(task) {
    const current = getLoggedInTeamMember()
    if (!current) return false

    const latestTaggedComment = taskCommentsFor(task.id)
      .filter((comment) => Array.isArray(comment.tagged_user_ids) && comment.tagged_user_ids.includes(current.id))
      .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0]

    if (!latestTaggedComment) return false

    const view = taskViews.find((item) => item.task_id === task.id && item.team_member_id === current.id)
    if (!view) return true

    return new Date(view.last_opened_at) < new Date(latestTaggedComment.created_at)
  }

  function businessDaysSince(dateValue) {
    if (!dateValue) return 0

    const start = new Date(dateValue)
    const today = new Date()
    start.setHours(0, 0, 0, 0)
    today.setHours(0, 0, 0, 0)

    let count = 0
    const current = new Date(start)
    current.setDate(current.getDate() + 1)

    while (current <= today) {
      const day = current.getDay()
      if (day !== 0 && day !== 6) count += 1
      current.setDate(current.getDate() + 1)
    }

    return count
  }

  function ageOutlineColor(dateValue) {
    const days = businessDaysSince(dateValue)
    if (days <= 0) return 'white'
    if (days === 1) return 'red'
    if (days === 2) return 'orange'
    if (days === 3) return 'yellow'
    if (days === 4) return 'green'
    if (days === 5) return 'blue'
    if (days === 6) return 'violet'
    return 'black'
  }

  function statusOutlineColor(task) {
    return ageOutlineColor(task.status_changed_at || task.created_at)
  }

  function taskCategoriesByCount() {
    const activeCategories = options('task_category').map((option) => option.name)
    const categoryNames = [...new Set([...activeCategories, ...tasks.map((task) => task.task_category || 'Uncategorized')])]

    return categoryNames.sort((a, b) => {
      const aCount = filteredTasks().filter((task) => (task.task_category || 'Uncategorized') === a).length
      const bCount = filteredTasks().filter((task) => (task.task_category || 'Uncategorized') === b).length
      return bCount - aCount || a.localeCompare(b)
    })
  }

  function filteredTasks() {
    let filtered = tasks.filter((task) => task.is_active !== false)

    if (taskAssignedFilter !== 'all') {
      filtered = filtered.filter((task) => taskAssignmentsFor(task.id).some((assignment) => assignment.team_member_id === taskAssignedFilter))
    }

    if (taskStatusFilter !== 'all') {
      filtered = filtered.filter((task) => task.status === taskStatusFilter)
    }

    return filtered.sort((a, b) => {
      if (taskSortBy === 'newest') return new Date(b.created_at) - new Date(a.created_at)
      return new Date(a.created_at) - new Date(b.created_at)
    })
  }

  function downloadTaskFile(file) {
    const link = document.createElement('a')
    link.href = file.file_data || '#'
    link.download = file.file_name
    link.click()
  }

  function readFileAsDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader()
      reader.onload = () => resolve({
        file_name: file.name,
        file_type: file.type,
        file_size: file.size,
        file_data: reader.result
      })
      reader.onerror = reject
      reader.readAsDataURL(file)
    })
  }


  function dataUrlToUint8Array(dataUrl = '') {
    const base64 = String(dataUrl || '').split(',')[1] || ''
    if (!base64) return new Uint8Array()
    const binary = atob(base64)
    const bytes = new Uint8Array(binary.length)
    for (let index = 0; index < binary.length; index += 1) {
      bytes[index] = binary.charCodeAt(index)
    }
    return bytes
  }

  function dataUrlToText(dataUrl = '') {
    const base64 = String(dataUrl || '').split(',')[1] || ''
    if (!base64) return ''
    try {
      return decodeURIComponent(escape(atob(base64)))
    } catch (error) {
      try {
        return atob(base64)
      } catch (innerError) {
        return ''
      }
    }
  }

  function usefulTextCharacterCount(text = '') {
    return String(text || '').replace(/\s+/g, '').length
  }

  async function loadPdfJs() {
    if (window.pdfjsLib) return window.pdfjsLib

    await new Promise((resolve, reject) => {
      const existingScript = document.querySelector('script[data-case-mio-pdfjs="true"]')
      if (existingScript) {
        existingScript.addEventListener('load', resolve, { once: true })
        existingScript.addEventListener('error', reject, { once: true })
        return
      }
      const script = document.createElement('script')
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js'
      script.async = true
      script.dataset.caseMioPdfjs = 'true'
      script.onload = resolve
      script.onerror = () => reject(new Error('Could not load PDF text extraction library.'))
      document.head.appendChild(script)
    })

    if (!window.pdfjsLib) throw new Error('PDF text extraction library did not load.')
    window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js'
    return window.pdfjsLib
  }

  async function loadTesseract() {
    if (window.Tesseract) return window.Tesseract

    await new Promise((resolve, reject) => {
      const existingScript = document.querySelector('script[data-case-mio-tesseract="true"]')
      if (existingScript) {
        existingScript.addEventListener('load', resolve, { once: true })
        existingScript.addEventListener('error', reject, { once: true })
        return
      }
      const script = document.createElement('script')
      script.src = 'https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js'
      script.async = true
      script.dataset.caseMioTesseract = 'true'
      script.onload = resolve
      script.onerror = () => reject(new Error('Could not load OCR library.'))
      document.head.appendChild(script)
    })

    if (!window.Tesseract) throw new Error('OCR library did not load.')
    return window.Tesseract
  }

  async function extractPdfEmbeddedText(fileData = '') {
    const pdfjsLib = await loadPdfJs()
    const loadingTask = pdfjsLib.getDocument({ data: dataUrlToUint8Array(fileData) })
    const pdf = await loadingTask.promise
    const pageTexts = []

    for (let pageNumber = 1; pageNumber <= pdf.numPages; pageNumber += 1) {
      const page = await pdf.getPage(pageNumber)
      const textContent = await page.getTextContent()
      const pageText = (textContent.items || []).map((item) => item.str || '').join(' ')
      pageTexts.push(pageText)
    }

    return pageTexts.join('\n\n').trim()
  }

  async function ocrPdfPages(fileData = '', maxPages = 5) {
    const [pdfjsLib, Tesseract] = await Promise.all([loadPdfJs(), loadTesseract()])
    const loadingTask = pdfjsLib.getDocument({ data: dataUrlToUint8Array(fileData) })
    const pdf = await loadingTask.promise
    const pagesToRead = Math.min(pdf.numPages, maxPages)
    const pageTexts = []

    for (let pageNumber = 1; pageNumber <= pagesToRead; pageNumber += 1) {
      const page = await pdf.getPage(pageNumber)
      const viewport = page.getViewport({ scale: 1.8 })
      const canvas = document.createElement('canvas')
      const context = canvas.getContext('2d')
      canvas.width = Math.floor(viewport.width)
      canvas.height = Math.floor(viewport.height)
      await page.render({ canvasContext: context, viewport }).promise
      const imageDataUrl = canvas.toDataURL('image/png')
      const result = await Tesseract.recognize(imageDataUrl, 'eng')
      pageTexts.push(result?.data?.text || '')
    }

    const text = pageTexts.join('\n\n').trim()
    const pageNote = pdf.numPages > pagesToRead ? ` OCR read the first ${pagesToRead} of ${pdf.numPages} pages.` : ''
    return { text, pageNote }
  }

  async function extractDocumentTextForAi(row = {}) {
    const fileType = String(row.file_type || '').toLowerCase()
    const fileName = String(row.file_name || row.name || '').toLowerCase()
    const fileData = row.file_data || ''

    if (!fileData) {
      return {
        extracted_text: '',
        extraction_method: 'no_file_data',
        text_quality: 'none',
        needs_ocr: false,
        warnings: ['No file data was available for AI analysis.']
      }
    }

    if (fileType.includes('text') || fileName.endsWith('.txt')) {
      const text = dataUrlToText(fileData)
      return {
        extracted_text: text,
        extraction_method: 'plain_text',
        text_quality: usefulTextCharacterCount(text) >= 100 ? 'usable' : 'short',
        needs_ocr: false,
        warnings: usefulTextCharacterCount(text) >= 100 ? [] : ['The text file had very little readable text.']
      }
    }

    if (fileType.includes('pdf') || fileName.endsWith('.pdf')) {
      try {
        const embeddedText = await extractPdfEmbeddedText(fileData)
        if (usefulTextCharacterCount(embeddedText) >= 100) {
          return {
            extracted_text: embeddedText,
            extraction_method: 'pdf_embedded_text',
            text_quality: 'usable',
            needs_ocr: false,
            warnings: []
          }
        }

        const ocrResult = await ocrPdfPages(fileData)
        if (usefulTextCharacterCount(ocrResult.text) >= 100) {
          return {
            extracted_text: ocrResult.text,
            extraction_method: 'browser_ocr',
            text_quality: 'usable',
            needs_ocr: false,
            warnings: [`The PDF did not have enough embedded text, so OCR was used.${ocrResult.pageNote}`]
          }
        }

        return {
          extracted_text: ocrResult.text || embeddedText || '',
          extraction_method: 'ocr_attempted',
          text_quality: 'not_enough_text',
          needs_ocr: true,
          warnings: ['The PDF did not have enough readable text after OCR. Try a clearer scan or searchable PDF.']
        }
      } catch (error) {
        return {
          extracted_text: '',
          extraction_method: 'extraction_failed',
          text_quality: 'failed',
          needs_ocr: true,
          warnings: [error.message || 'Document text extraction failed.']
        }
      }
    }

    return {
      extracted_text: '',
      extraction_method: 'unsupported_file_type',
      text_quality: 'unsupported',
      needs_ocr: false,
      warnings: ['This file type is not supported for text extraction yet. Use a PDF or text file for AI analysis.']
    }
  }

  function toggleTaskAssignedUser(userId) {
    const current = Array.isArray(taskForm.assigned_user_ids) ? taskForm.assigned_user_ids : []
    const hasUser = current.includes(userId)

    setTaskForm({
      ...taskForm,
      assigned_user_ids: hasUser ? current.filter((id) => id !== userId) : [...current, userId]
    })
  }

  function toggleCommentTaggedUser(userId) {
    const hasUser = commentTaggedUsers.includes(userId)
    setCommentTaggedUsers(hasUser ? commentTaggedUsers.filter((id) => id !== userId) : [...commentTaggedUsers, userId])
  }

  function openPageAccessEditor(member) {
    setPageAccessMember(member)
    setPageAccessDraft(Array.isArray(member.page_access) ? member.page_access : [])
    setShowPageAccessWindow(true)
  }

  function togglePageAccessDraft(pageName) {
    const hasPage = pageAccessDraft.includes(pageName)
    setPageAccessDraft(hasPage ? pageAccessDraft.filter((p) => p !== pageName) : [...pageAccessDraft, pageName])
  }

  async function savePageAccessDraft() {
    if (!pageAccessMember) return

    const { error } = await supabase
      .from('team_members')
      .update({ page_access: pageAccessDraft })
      .eq('id', pageAccessMember.id)

    if (error) alert(error.message)
    else {
      setShowPageAccessWindow(false)
      setPageAccessMember(null)
      setPageAccessDraft([])
      fetchTeam()
    }
  }



  function dateToInputValue(date) {
    const yyyy = date.getFullYear()
    const mm = String(date.getMonth() + 1).padStart(2, '0')
    const dd = String(date.getDate()).padStart(2, '0')
    return `${yyyy}-${mm}-${dd}`
  }

  function calendarMonthDays() {
    const year = calendarDate.getFullYear()
    const month = calendarDate.getMonth()
    const firstDay = new Date(year, month, 1)
    const startDate = new Date(firstDay)
    startDate.setDate(firstDay.getDate() - firstDay.getDay())

    const days = []
    for (let i = 0; i < 42; i += 1) {
      const day = new Date(startDate)
      day.setDate(startDate.getDate() + i)
      days.push(day)
    }
    return days
  }

  function changeCalendarMonth(amount) {
    const next = new Date(calendarDate)
    next.setMonth(next.getMonth() + amount)
    setCalendarDate(next)
  }

  function eventsForDate(date) {
    const dateValue = dateToInputValue(date)
    return events.filter((event) => {
      // Keep completed/passed/reset events visible on the calendar; eventBlockColor() turns inactive events grey.
      if (isUndatedEventDate(event.start_date)) return false
      if (calendarUserFilter !== 'all' && event.assigned_to !== calendarUserFilter) return false
      const start = event.start_date
      const end = isUndatedEventDate(event.end_date) ? event.start_date : (event.end_date || event.start_date)
      return start <= dateValue && end >= dateValue
    })
  }

  function formatEventTime(timeValue) {
    if (!timeValue) return ''
    const [hourText, minuteText = '00'] = String(timeValue).split(':')
    const hour = Number(hourText)
    if (Number.isNaN(hour)) return timeValue
    const suffix = hour >= 12 ? 'PM' : 'AM'
    const displayHour = hour % 12 || 12
    return `${String(displayHour).padStart(2, '0')}:${String(minuteText).padStart(2, '0')} ${suffix}`
  }

  function matterClientName(matter) {
    const client = matter?.clients
    return `${client?.first_name || ''} ${client?.last_name || ''}`.trim()
  }

  function clientEmailForMatter(matter) {
    if (!matter) return ''
    const client = matter.clients || clients.find((item) => String(item.id) === String(matter.client_id)) || {}
    return matter.client_email || client.email || ''
  }

  function clientPhoneForMatter(matter) {
    if (!matter) return ''
    const client = matter.clients || clients.find((item) => String(item.id) === String(matter.client_id)) || {}
    return matter.client_phone || client.phone || ''
  }

  function eventClientName(event) {
    return matterClientName(event.matters) || event.matters?.name || ''
  }

  function formatEventCalendarTitle(event) {
    const pieces = []
    if (event.start_time) pieces.push(formatEventTime(event.start_time))
    const clientName = eventClientName(event)
    const eventName = event.title || event.event_subcategory || event.event_category || '(No Title)'
    pieces.push(clientName ? `${clientName} - ${eventName}` : eventName)
    return pieces.join(' ')
  }

  function eventTitleDefault(category, subcategory) {
    return subcategory || category || ''
  }

  function currentEventTitleDefault() {
    return eventTitleDefault(eventForm.event_category, eventForm.event_subcategory)
  }

  function shouldReplaceEventTitle(nextDefault) {
    const currentDefault = currentEventTitleDefault()
    return !eventForm.title || eventForm.title === currentDefault || eventForm.title === eventForm.event_category || eventForm.title === eventForm.event_subcategory || eventForm.title === nextDefault
  }

  function selectedEventMatterCourt() {
    return selectedMatterForEvent()?.courts || null
  }

  function eventListDays() {
    const start = new Date(calendarDate)
    const days = []
    for (let i = 0; i < eventListRangeDays; i += 1) {
      const day = new Date(start)
      day.setDate(start.getDate() + i)
      if (eventListIncludeWeekends || (day.getDay() !== 0 && day.getDay() !== 6)) {
        days.push(day)
      }
    }
    return days
  }

  function eventListCategories() {
    const configured = options('event_category').map((category) => category.name)
    const used = events.map((event) => event.event_category).filter(Boolean)
    return Array.from(new Set([...configured, ...used])).filter(Boolean)
  }

  function eventListMonthGroups(days) {
    return days.reduce((groups, day) => {
      const label = day.toLocaleDateString('default', { month: 'long' })
      const year = day.getFullYear()
      const key = `${label}-${year}`
      const last = groups[groups.length - 1]
      if (last && last.key === key) {
        last.span += 1
      } else {
        groups.push({ key, label, span: 1 })
      }
      return groups
    }, [])
  }

  function eventListDateHeader(day) {
    const weekdayShort = day.toLocaleDateString('default', { weekday: 'short' })
    if (eventListRangeDays >= 60) return `${weekdayShort.slice(0, 1)} ${day.getDate()}`
    if (eventListRangeDays >= 30) return `${weekdayShort} ${day.getDate()}`
    return `${weekdayShort} ${day.toLocaleDateString('default', { month: 'short', day: 'numeric' })}`
  }

  function eventListDateCellLabel(day) {
    const weekdayShort = day.toLocaleDateString('default', { weekday: 'short' })
    if (eventListRangeDays >= 60) return `${weekdayShort.slice(0, 1)} ${day.getDate()}`
    if (eventListRangeDays >= 30) return `${weekdayShort} ${day.getDate()}`
    return day.toLocaleDateString('default', { weekday: 'short', month: 'short', day: 'numeric' })
  }

  function eventsForCategoryAndDate(category, date) {
    return eventsForDate(date).filter((event) => event.event_category === category)
  }

  function selectedMatterForEvent() {
    return matters.find((matter) => matter.id === eventForm.matter_id)
  }

  function checklistMatterForEvent(event) {
    return event?.checklist_matter || event?.matter || event?.matters || matters.find((matter) => matter.id === event?.matter_id) || null
  }

  function checklistCourtForEvent(event) {
    const matter = checklistMatterForEvent(event)
    return matter?.courts || event?.courts || null
  }

  function normalizedExternalUrl(value) {
    const raw = String(value || '').trim()
    if (!raw) return ''
    return /^https?:\/\//i.test(raw) ? raw : `https://${raw}`
  }

  function checklistCourtWebsite(event) {
    return normalizedExternalUrl(checklistCourtForEvent(event)?.court_website)
  }

  function checklistCourtName(event) {
    return checklistCourtForEvent(event)?.court_name || ''
  }

  function checklistCourtCoordinatorEmail(event) {
    return checklistCourtForEvent(event)?.court_coordinator_email || ''
  }

  function checklistRows() {
    return events.map((event) => ({
      ...event,
      checklist_id: `event-${event.id}`,
      checklist_source: 'calendar_event',
      checklist_source_id: event.id,
      checklist_category: event.event_category || 'Uncategorized',
      checklist_subcategory: event.event_subcategory || '',
      checklist_description: event.description || '',
      checklist_title: event.title || '(No title)',
      checklist_color: eventBlockColor(event),
      checklist_date: event.start_date || '',
      checklist_time: event.start_time || ''
    }))
  }


  function checklistEventCategories() {
    const configured = options('event_category').map((category) => category.name)
    const used = checklistRows().map((event) => event.checklist_category || event.event_category).filter(Boolean)
    return Array.from(new Set([...configured, ...used])).filter(Boolean).sort((a, b) => a.localeCompare(b))
  }

  function checklistFilterOptions(kind) {
    if (kind === 'case') return discoveryStatusOptions('case')
    if (kind === 'matter') return discoveryStatusOptions('matter')
    return checklistEventCategories().map((value) => ({ value, label: value }))
  }

  function checklistSelectedFilterValues(kind) {
    const allValues = checklistFilterOptions(kind).map((option) => option.value)
    const current = kind === 'case' ? checklistCaseStatusFilter : kind === 'matter' ? checklistMatterStatusFilter : checklistEventCategoryFilter
    if (!Array.isArray(current)) return allValues
    const clean = current.filter((value) => allValues.includes(value))
    return clean.length ? clean : allValues
  }

  function setChecklistFilter(kind, values) {
    const allValues = checklistFilterOptions(kind).map((option) => option.value)
    const clean = Array.from(new Set((values || []).filter((value) => allValues.includes(value))))
    if (kind === 'case') setChecklistCaseStatusFilter(clean)
    else if (kind === 'matter') setChecklistMatterStatusFilter(clean)
    else setChecklistEventCategoryFilter(clean)
  }

  function toggleChecklistFilter(kind, value) {
    const current = checklistSelectedFilterValues(kind)
    const next = current.includes(value) ? current.filter((item) => item !== value) : [...current, value]
    setChecklistFilter(kind, next)
  }

  function ChecklistCheckboxFilter({ kind, title }) {
    const opts = checklistFilterOptions(kind)
    const selected = checklistSelectedFilterValues(kind)
    return (
      <details style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 230 }}>
        <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>{title} <span style={{ fontWeight: 'normal', color: '#666', fontSize: 12 }}>({selected.length} of {opts.length})</span></summary>
        <div style={{ display: 'flex', gap: 6, margin: '8px 0 6px' }}>
          <button type="button" onClick={() => setChecklistFilter(kind, opts.map((option) => option.value))}>All</button>
          <button type="button" onClick={() => setChecklistFilter(kind, [])}>None</button>
        </div>
        <div style={{ maxHeight: 180, overflowY: 'auto' }}>
          {opts.map((option) => (
            <label key={option.value} style={{ display: 'block', fontSize: 12, marginBottom: 3 }}>
              <input type="checkbox" checked={selected.includes(option.value)} onChange={() => toggleChecklistFilter(kind, option.value)} />{' '}{option.label}
            </label>
          ))}
          {!opts.length && <div style={{ fontSize: 12, color: '#666' }}>No options have been set yet.</div>}
        </div>
      </details>
    )
  }

  function checklistEventDateValue(event) {
    if (event?.checklist_date instanceof Date) return dateToInputValue(event.checklist_date)
    const value = event?.checklist_date || event?.start_date || ''
    return isUndatedEventDate(value) ? '' : value
  }

  function checklistDateObj(event) {
    const value = checklistEventDateValue(event)
    if (!value) return null
    const date = value instanceof Date ? new Date(value) : new Date(`${value}T00:00:00`)
    return Number.isNaN(date.getTime()) ? null : date
  }

  function checklistEventCategoryLabel(event) {
    return [event.checklist_category || event.event_category, event.checklist_subcategory || event.event_subcategory].filter(Boolean).join(' / ') || 'Uncategorized'
  }

  function checklistMatterLabel(event) {
    const matter = checklistMatterForEvent(event)
    return matter ? formatMatterOption(matter) : 'No matter selected'
  }

  function formatChecklistDate(event) {
    const date = checklistDateObj(event)
    if (!date) return 'Needs date'
    return date.toLocaleDateString('default', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' })
  }

  function checklistRowBackground(event) {
    const date = checklistDateObj(event)
    if (!date) return 'white'
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    if (date < today) return '#e5e7eb'
    const color = event.checklist_color || eventBlockColor(event)
    if (/^#[0-9a-fA-F]{6}$/.test(color)) {
      const r = parseInt(color.slice(1, 3), 16)
      const g = parseInt(color.slice(3, 5), 16)
      const b = parseInt(color.slice(5, 7), 16)
      return `rgba(${r}, ${g}, ${b}, 0.18)`
    }
    return color || 'white'
  }

  function filteredChecklistEvents(tab = checklistTab) {
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    const selectedCase = checklistSelectedFilterValues('case')
    const selectedMatter = checklistSelectedFilterValues('matter')
    const selectedCategories = checklistSelectedFilterValues('category')

    return checklistRows()
      .filter((event) => {
        const matter = checklistMatterForEvent(event)
        if (matter && selectedCase.length > 0 && !selectedCase.includes(matter.case_status || '')) return false
        if (matter && selectedMatter.length > 0 && !selectedMatter.includes(matter.matter_status || '')) return false
        if (selectedCategories.length > 0 && !selectedCategories.includes(event.checklist_category || event.event_category || '')) return false
        const isComplete = event.is_active === false || event.completed === true || event.status === 'completed'
        const rowId = checklistNeedToSetRowId(event)
        const isSetRow = Boolean(needToSetSetRows[rowId])
        const date = checklistDateObj(event)
        if (tab === 'completed') return isComplete
        if (tab === 'set') return !isComplete && isSetRow
        if (tab === 'need_date') return !isComplete && !isSetRow && (!date || needToSetPausedRows[rowId])
        if (!date || isComplete) return false
        return true
      })
      .sort((a, b) => {
        if (tab === 'need_date') {
          const ap = needToSetPausedRows[checklistNeedToSetRowId(a)] ? 1 : 0
          const bp = needToSetPausedRows[checklistNeedToSetRowId(b)] ? 1 : 0
          if (ap !== bp) return ap - bp
          const ai = checklistNeedToSetOrder.indexOf(String(a.id || a.checklist_source_id || a.checklist_id || ''))
          const bi = checklistNeedToSetOrder.indexOf(String(b.id || b.checklist_source_id || b.checklist_id || ''))
          if (ai !== -1 || bi !== -1) return (ai === -1 ? 999999 : ai) - (bi === -1 ? 999999 : bi)
        }
        const ad = checklistEventDateValue(a) || '9999-12-31'
        const bd = checklistEventDateValue(b) || '9999-12-31'
        if (ad !== bd) return ad.localeCompare(bd)
        return String(a.start_time || '').localeCompare(String(b.start_time || ''))
      })
  }

  function checklistNeedToSetRowId(event = {}) {
    return String(event.id || event.checklist_source_id || event.checklist_id || '')
  }

  function orderedNeedToSetIdsFromVisibleRows() {
    return filteredChecklistEvents('need_date').map((event) => checklistNeedToSetRowId(event)).filter(Boolean)
  }

  function moveNeedToSetRow(dragId, targetId) {
    if (!dragId || !targetId || dragId === targetId) return
    const visibleIds = orderedNeedToSetIdsFromVisibleRows()
    const existingOrder = checklistNeedToSetOrder.length ? checklistNeedToSetOrder : visibleIds
    const merged = [...existingOrder, ...visibleIds.filter((id) => !existingOrder.includes(id))]
    const without = merged.filter((id) => id !== dragId)
    const targetIndex = Math.max(0, without.indexOf(targetId))
    without.splice(targetIndex, 0, dragId)
    setChecklistNeedToSetOrder(without)
  }

  function dateOnlyFromValue(value) {
    if (!value) return null
    if (typeof value === 'string') {
      const match = value.trim().match(/^(\d{4})-(\d{2})-(\d{2})/)
      if (match) return new Date(Number(match[1]), Number(match[2]) - 1, Number(match[3]))
    }
    const parsed = new Date(value)
    if (Number.isNaN(parsed.getTime())) return null
    parsed.setHours(0, 0, 0, 0)
    return parsed
  }

  function weekdayAgeBetween(startValue, endValue = new Date()) {
    const start = dateOnlyFromValue(startValue)
    const end = dateOnlyFromValue(endValue)
    if (!start || !end || end <= start) return 0
    let count = 0
    const cursor = new Date(start)
    cursor.setDate(cursor.getDate() + 1)
    while (cursor <= end) {
      const day = cursor.getDay()
      if (day !== 0 && day !== 6) count += 1
      cursor.setDate(cursor.getDate() + 1)
    }
    return count
  }

  function needToSetCreatedAt(event = {}) {
    const id = checklistNeedToSetRowId(event)
    return event.need_to_set_created_at || event.checklist_created_at || event.created_at || event.added_at || needToSetFirstSeenDates[id] || '2000-01-03T00:00:00.000Z'
  }

  function colorForNeedToSetAge(days) {
    const index = Math.min(Math.max(Number(days) || 0, 0), 8)
    return needToSetAgeColors[index]?.color || defaultNeedToSetAgeColors[index]?.color || '#ffffff'
  }

  function needToSetStepTiming(context = {}, step = {}, stepIndex = 0, steps = []) {
    const eventId = context.event?.id || context.event?.checklist_source_id || context.eventId
    let startAt = needToSetCreatedAt(context.event || {})
    for (let i = 0; i < stepIndex; i += 1) {
      const priorCompletion = checklistStepCompletion(eventId, steps[i]?.id)
      if (!priorCompletion?.completed) {
        return { startAt: '', endAt: '', days: null, color: '#e5e7eb', completed: false, inactive: true }
      }
      if (priorCompletion?.completed_at) startAt = priorCompletion.completed_at
    }
    const completion = checklistStepCompletion(eventId, step.id)
    const endAt = completion?.completed_at || new Date().toISOString()
    const days = weekdayAgeBetween(startAt, endAt)
    return { startAt, endAt, days, color: colorForNeedToSetAge(days), completed: !!completion?.completed, inactive: false }
  }

  function currentNeedToSetStatus(event = {}) {
    const steps = checklistStepsForEvent(event)
    const eventId = event.id || event.checklist_source_id
    const firstOpenIndex = steps.findIndex((step) => !checklistStepCompletion(eventId, step.id)?.completed)
    const stepIndex = firstOpenIndex === -1 ? Math.max(steps.length - 1, 0) : firstOpenIndex
    const step = steps[stepIndex] || null
    const rowDays = weekdayAgeBetween(needToSetCreatedAt(event))
    const rowColor = colorForNeedToSetAge(rowDays)
    const timing = step ? needToSetStepTiming({ type: 'checklist', event, eventId }, step, stepIndex, steps) : { days: null, color: '#e5e7eb' }
    const timeStatus = needToSetLastTimeEntryStatus(event)
    return { ...timing, rowDays, rowColor, stepDays: timing.days, stepColor: timing.color, stepName: step?.name || 'No step selected', timeDays: timeStatus.days, timeColor: timeStatus.color, lastTimeEntryAt: timeStatus.lastAt }
  }

  function checklistWorkspaceContextForEvent(event = {}) {
    const matter = checklistMatterForEvent(event)
    const eventId = event?.id || event?.checklist_source_id || ''
    const settingType = event?.checklist_category || event?.event_category || 'Setting'
    return {
      type: 'checklist',
      event,
      eventId,
      matter,
      matterId: matter?.id || event?.matter_id || '',
      settingType,
      billingStepName: `Need to Set - ${settingType}`,
      courtName: checklistCourtName(event),
      courtEmail: checklistCourtCoordinatorEmail(event)
    }
  }

  function checklistStepContextForEvent(event = {}, step = {}) {
    const base = checklistWorkspaceContextForEvent(event)
    return {
      ...base,
      step,
      stepName: step?.name || '',
      billingStepName: `Need to Set - ${base.settingType || step?.parent_name || 'Setting'}: ${step?.name || ''}`
    }
  }

  function workspaceEmailsForContext(context = {}) {
    return normalizeWorkspace(context).emails || []
  }

  function emailsForChecklistStep(event = {}, step = {}, stepIndex = 0) {
    const context = checklistWorkspaceContextForEvent(event)
    const stepContext = checklistStepContextForEvent(event, step)
    const stepKey = workspaceStepKey(stepContext, stepIndex)
    return workspaceEmailsForContext(context).filter((email) => String(email.step_key || email.step_id || '') === String(stepKey))
  }

  function checklistStepHasNewEmail(event = {}, step = {}, stepIndex = 0) {
    return emailsForChecklistStep(event, step, stepIndex).some((email) => email.new_email_notice || workspaceEmailHasUnreadActivity(email))
  }

  function checklistEventHasNewEmail(event = {}) {
    const context = checklistWorkspaceContextForEvent(event)
    const emails = workspaceEmailsForContext(context)
    return emails.some((email) => email.new_email_notice || workspaceEmailHasUnreadActivity(email))
  }

  function anyNeedToSetNewEmail() {
    return filteredChecklistEvents('need_date').some((event) => checklistEventHasNewEmail(event))
  }

  async function refreshAllNeedToSetEmailThreads() {
    const rows = filteredChecklistEvents('need_date')
    setRefreshingNeedSetEmails(true)
    try {
      for (const event of rows) {
        const context = checklistWorkspaceContextForEvent(event)
        const emails = workspaceEmailsForContext(context).filter((email) => email.outlook_conversation_id || email.outlook_message_id)
        for (const email of emails) {
          try { await loadWorkspaceOutlookThread(context, email) }
          catch (error) { console.warn('Could not refresh one setting email thread:', error) }
        }
      }
    } finally {
      setRefreshingNeedSetEmails(false)
    }
  }

  function needToSetBillingEntriesForEvent(event = {}) {
    const matter = checklistMatterForEvent(event)
    if (!matter?.id) return []
    const settingType = event?.checklist_category || event?.event_category || 'Setting'
    const settingPrefix = `Need to Set - ${settingType}:`
    return billingEntries.filter((entry) => {
      if (String(entry.matter_id) !== String(matter.id)) return false
      return String(entry.matter_step || '').startsWith(settingPrefix)
    })
  }

  function needToSetLastTimeEntryStatus(event = {}) {
    const entries = needToSetBillingEntriesForEvent(event)
    const lastAt = entries
      .map((entry) => entry.date || entry.created_at || '')
      .filter(Boolean)
      .sort((a, b) => new Date(b || 0) - new Date(a || 0))[0] || ''
    const startAt = lastAt || needToSetCreatedAt(event)
    const days = weekdayAgeBetween(startAt)
    return { lastAt, days, color: colorForNeedToSetAge(days) }
  }

  function nextChecklistEvent() {
    return filteredChecklistEvents('future')[0] || null
  }

  function jumpToNextChecklistEvent() {
    setChecklistTab('future')
    const next = nextChecklistEvent()
    if (!next?.id) return
    setTimeout(() => {
      const row = document.getElementById(`checklist-event-${next.checklist_id || next.id}`)
      if (row) row.scrollIntoView({ behavior: 'smooth', block: 'center' })
    }, 50)
  }

  function checklistCompletionInstruction(event) {
    const text = `${event?.checklist_category || event?.event_category || ''} ${event?.checklist_subcategory || event?.event_subcategory || ''} ${event?.checklist_title || event?.title || ''}`.toLowerCase()
    if (text.includes('mediation')) return 'Add the signed MSA or mediated settlement document for this mediation.'
    if (text.includes('deadline') || text.includes('discovery')) return 'Add the discovery responses or other deadline-completion document.'
    if (text.includes('hearing') || text.includes('trial')) return 'Add the signed order for this hearing or trial.'
    return 'Add the order, discovery response, MSA, or other document that proves this event/deadline is complete.'
  }

  function resetChecklistCompletionForm() {
    setChecklistCompletionEvent(null)
    setChecklistCompletionMode('upload')
    setChecklistCompletionFile(null)
    setChecklistCompletionSelectedDocId('')
    setChecklistCompletionDocForm({ matter_id: '', name: '', date: '', description: '', status: 'Neither', tag_ids: checklistCompletionDefaultTagId ? [checklistCompletionDefaultTagId] : [], document_field_values: {} })
    setChecklistCompletionSettingsOpen(false)
    if (checklistCompletionFileInputRef.current) checklistCompletionFileInputRef.current.value = ''
  }

  function openChecklistCompletionWindow(event) {
    const matter = checklistMatterForEvent(event)
    setChecklistCompletionEvent(event)
    setChecklistCompletionMode('upload')
    setChecklistCompletionFile(null)
    setChecklistCompletionSelectedDocId('')
    setChecklistCompletionDocForm({
      matter_id: matter?.id || event?.matter_id || '',
      name: `${event?.checklist_title || event?.title || 'Completed event'} document`,
      date: dateToInputValue(new Date()),
      description: checklistCompletionInstruction(event),
      status: 'Neither',
      tag_ids: checklistCompletionDefaultTagId ? [checklistCompletionDefaultTagId] : [],
      document_field_values: {}
    })
    setChecklistCompletionSettingsOpen(false)
    setShowDocumentWindow(false)
  }

  function toggleChecklistCompletionTag(tagId) {
    setChecklistCompletionDocForm((currentForm) => ({ ...currentForm, tag_ids: normalizeTagSelectionForToggle(currentForm.tag_ids || [], tagId) }))
  }

  async function markChecklistEventCompleted(event, options = {}) {
    if (!event) return
    const eventId = event.id || event.checklist_source_id
    if (!eventId) {
      alert('This checklist row is not linked to a calendar event, so it cannot be moved to Completed from here.')
      return
    }
    const { error } = await supabase.from('calendar_events').update({ is_active: false }).eq('id', eventId)
    if (error) alert(error.message)
    else {
      resetChecklistCompletionForm()
      fetchEvents()
      if (options.showMessage) alert('Moved to Completed.')
    }
  }

  async function completeChecklistWithDocument(e) {
    e.preventDefault()
    if (!checklistCompletionEvent) return

    if (checklistCompletionMode === 'none') {
      const ok = confirm('Are you sure you want to mark as complete without adding an order, discovery response, MSA or other document?')
      if (!ok) return
      await markChecklistEventCompleted(checklistCompletionEvent)
      return
    }

    if (checklistCompletionMode === 'select') {
      if (!checklistCompletionSelectedDocId) {
        alert('Select an existing document, or choose mark complete without document.')
        return
      }
      if (confirm('Add to completed events/deadlines?')) await markChecklistEventCompleted(checklistCompletionEvent)
      return
    }

    if (!checklistCompletionDocForm.name.trim()) {
      alert('Document name is required.')
      return
    }
    if (!checklistCompletionDocForm.matter_id) {
      alert('Select the matter the document is being added to.')
      return
    }

    const filePayload = checklistCompletionFile ? await readFileAsDataUrl(checklistCompletionFile) : {}
    const nextDocument = withEmptyDocumentAiReview({
      id: `doc-${Date.now()}-${Math.random().toString(36).slice(2)}`,
      matter_id: checklistCompletionDocForm.matter_id,
      name: checklistCompletionDocForm.name.trim(),
      date: checklistCompletionDocForm.date || '',
      description: checklistCompletionDocForm.description || '',
      status: checklistCompletionDocForm.status || 'Neither',
      tag_ids: tagAndParentIds(checklistCompletionDocForm.tag_ids || []),
      document_field_values: checklistCompletionDocForm.document_field_values || {},
      upload_date: dateToInputValue(new Date()),
      ...filePayload
    })
    setDocuments((currentDocuments) => [...currentDocuments, nextDocument])
    if (confirm('Add to completed events/deadlines?')) await markChecklistEventCompleted(checklistCompletionEvent)
    else resetChecklistCompletionForm()
  }

  async function markChecklistEventSet(event) {
    const eventId = event?.id || event?.checklist_source_id
    if (!eventId) {
      alert('This checklist row is not linked to a calendar event, so it cannot be marked as set from here.')
      return
    }
    const rawDate = prompt('Enter the set date as YYYY-MM-DD:', dateToInputValue(new Date()))
    if (!rawDate) return
    const parsed = parseTimelineDateValue(rawDate)
    if (!parsed) {
      alert('Enter a valid date in YYYY-MM-DD format.')
      return
    }
    const dateValue = dateToInputValue(parsed)
    const { error } = await supabase.from('calendar_events').update({ start_date: dateValue, end_date: dateValue, is_active: true }).eq('id', eventId)
    if (error) alert(error.message)
    else {
      setNeedToSetSetRows((current) => ({ ...current, [String(eventId)]: { set_at: new Date().toISOString(), set_date: dateValue } }))
      setChecklistTab('set')
      fetchEvents()
    }
  }

  function removeSetNeedToSetRowFromPage(event = {}) {
    const rowId = checklistNeedToSetRowId(event)
    if (!rowId) return
    setNeedToSetSetRows((current) => {
      const next = { ...current }
      delete next[String(rowId)]
      return next
    })
  }

  function toggleNeedToSetPaused(event = {}) {
    const rowId = checklistNeedToSetRowId(event)
    if (!rowId) return
    setNeedToSetPausedRows((current) => {
      const next = { ...current }
      if (next[String(rowId)]) delete next[String(rowId)]
      else next[String(rowId)] = { paused_at: new Date().toISOString() }
      return next
    })
  }

  function resetNeedToSetRowSteps(event = {}) {
    const eventId = event?.id || event?.checklist_source_id
    if (!eventId) return
    if (!confirm('Reset this Need to Set row? This will uncomplete all steps, but it will not remove billing entries or notes.')) return
    const prefix = `${eventId}::`
    setChecklistStepCompletions((current) => {
      const next = { ...current }
      Object.keys(next).forEach((key) => { if (key.startsWith(prefix)) delete next[key] })
      return next
    })
  }

  async function reactivateSetNeedToSetRow(event = {}) {
    const eventId = event?.id || event?.checklist_source_id
    const rowId = checklistNeedToSetRowId(event)
    if (!eventId) return
    const ok = confirm('Reactivating will remove event from calendar. Do you want to proceed?')
    if (!ok) return
    const original = events.find((item) => item.id === eventId) || event
    const resetRow = {
      matter_id: original.matter_id || null,
      assigned_to: original.assigned_to || null,
      event_category: original.event_category || original.checklist_category || '',
      event_subcategory: original.event_subcategory || original.checklist_subcategory || '',
      title: original.title || original.checklist_title || '',
      description: original.description || original.checklist_description || '',
      start_date: UNDATED_EVENT_DATE,
      start_time: original.start_time || '09:00',
      end_date: UNDATED_EVENT_DATE,
      end_time: original.end_time || original.start_time || '17:00',
      is_active: true
    }
    const { error: passError } = await supabase.from('calendar_events').update({ is_active: false }).eq('id', eventId)
    if (passError) { alert(passError.message); return }
    const { error: insertError } = await supabase.from('calendar_events').insert([resetRow])
    if (insertError) { alert(insertError.message); return }
    setNeedToSetSetRows((current) => { const next = { ...current }; delete next[String(rowId)]; return next })
    setChecklistTab('need_date')
    fetchEvents()
  }

  function formatChecklistBlankDay(date) {
    return date.toLocaleDateString('default', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' })
  }

  function checklistDisplayRows(tab = checklistTab) {
    let sourceEvents = filteredChecklistEvents(tab)
    if (tab === 'need_date' && checklistNewEmailOnly) sourceEvents = sourceEvents.filter((event) => checklistEventHasNewEmail(event))
    let eventRows = sourceEvents.map((event) => ({ type: 'event', event }))
    if (tab === 'need_date' && checklistNeedToSetSortMode === 'billing_oldest') {
      eventRows = [...eventRows].sort((a, b) => {
        const aLast = needToSetLastTimeEntryStatus(a.event).lastAt
        const bLast = needToSetLastTimeEntryStatus(b.event).lastAt
        const aTime = aLast ? new Date(aLast).getTime() : 0
        const bTime = bLast ? new Date(bLast).getTime() : 0
        if (aTime !== bTime) return aTime - bTime
        return String(checklistMatterLabel(a.event)).localeCompare(String(checklistMatterLabel(b.event)))
      })
    }
    if (!checklistShowBlankDays || tab === 'need_date' || eventRows.length < 2) return eventRows
    const rows = []
    for (let index = 0; index < eventRows.length; index += 1) {
      const row = eventRows[index]
      rows.push(row)
      const currentDate = checklistDateObj(row.event)
      const nextDate = checklistDateObj(eventRows[index + 1]?.event)
      if (!currentDate || !nextDate) continue
      const cursor = new Date(currentDate)
      cursor.setDate(cursor.getDate() + 1)
      let guard = 0
      while (cursor < nextDate && guard < 366) {
        rows.push({ type: 'blank_day', key: `blank-${dateToInputValue(cursor)}-${index}-${guard}`, date: new Date(cursor) })
        cursor.setDate(cursor.getDate() + 1)
        guard += 1
      }
    }
    return rows
  }


  function SmartMatterSelect({ value, onChange, placeholder = 'Type to search matters', style = {}, activeOnly = false }) {
    const listId = useRef(`matter-smart-${Math.random().toString(36).slice(2)}`)
    const [text, setText] = useState('')

    useEffect(() => {
      const matterOptions = activeOnly ? matters.filter((matter) => matter.is_active !== false) : matters
      const selected = matterOptions.find((matter) => matter.id === value)
      setText(selected ? formatMatterOption(selected) : '')
    }, [value, matters])

    function commit(nextText) {
      const matterOptions = activeOnly ? matters.filter((matter) => matter.is_active !== false) : matters
      const exact = matterOptions.find((matter) => formatMatterOption(matter).toLowerCase() === String(nextText || '').toLowerCase())
      if (exact) onChange(exact.id)
    }

    return (
      <>
        <input
          list={listId.current}
          value={text}
          placeholder={placeholder}
          onChange={(e) => {
            const nextText = e.target.value
            setText(nextText)
            const matterOptions = activeOnly ? matters.filter((matter) => matter.is_active !== false) : matters
            const exact = matterOptions.find((matter) => formatMatterOption(matter).toLowerCase() === nextText.toLowerCase())
            if (exact) onChange(exact.id)
            else if (!nextText) onChange('')
          }}
          onBlur={(e) => commit(e.target.value)}
          style={style}
        />
        <datalist id={listId.current}>
          {(activeOnly ? matters.filter((matter) => matter.is_active !== false) : matters)
            .filter((matter) => !text || matchesSmartSearch(text, formatMatterOption(matter)))
            .slice(0, 25)
            .map((matter) => (
              <option key={matter.id} value={formatMatterOption(matter)} />
            ))}
        </datalist>
      </>
    )
  }

