  function TagTreeMultiSelect({ selectedIds = [], onToggle, matterId = '' }) {
    const normalizedSelectedIds = tagAndParentIds(selectedIds || [])
    const [open, setOpen] = useState(false)
    const [expandedTagIds, setExpandedTagIds] = useState([])
    const hoverTimersRef = useRef({})
    const pickerRef = useRef(null)

    const availableTagIds = new Set(allTagsIndented().filter((tag) => isTagAvailableForMatter(tag.id, matterId)).map((tag) => tag.id))

    useEffect(() => {
      const ancestorIds = new Set()
      ;(selectedIds || []).forEach((selectedId) => {
        let current = tags.find((tag) => tag.id === selectedId)
        let guard = 0
        while (current?.parent_id && guard < 25) {
          ancestorIds.add(current.parent_id)
          current = tags.find((tag) => tag.id === current.parent_id)
          guard += 1
        }
      })
      setExpandedTagIds((current) => Array.from(new Set([...current, ...ancestorIds])))
    }, [JSON.stringify(selectedIds || []), tags.length])

    useEffect(() => {
      if (!open) return undefined
      function closeOnOutsideClick(event) {
        if (pickerRef.current && !pickerRef.current.contains(event.target)) {
          setOpen(false)
        }
      }
      document.addEventListener('mousedown', closeOnOutsideClick)
      document.addEventListener('touchstart', closeOnOutsideClick)
      return () => {
        document.removeEventListener('mousedown', closeOnOutsideClick)
        document.removeEventListener('touchstart', closeOnOutsideClick)
      }
    }, [open])

    function childrenForPicker(parentId = '') {
      return childTags(parentId).filter((tag) => availableTagIds.has(tag.id))
    }

    function hasChildren(tagId) {
      return childrenForPicker(tagId).length > 0
    }

    function selectedTagLabels() {
      return selectedTagDisplayLabels(normalizedSelectedIds || [])
    }

    function beginTagHover(tagId) {
      if (!hasChildren(tagId) || expandedTagIds.includes(tagId)) return
      clearTimeout(hoverTimersRef.current[tagId])
      hoverTimersRef.current[tagId] = setTimeout(() => {
        setExpandedTagIds((current) => current.includes(tagId) ? current : [...current, tagId])
      }, 500)
    }

    function cancelTagHover(tagId) {
      clearTimeout(hoverTimersRef.current[tagId])
    }

    function toggleExpanded(tagId) {
      setExpandedTagIds((current) => current.includes(tagId) ? current.filter((id) => id !== tagId) : [...current, tagId])
    }

    function renderTagBranch(parentId = '', level = 0) {
      const branch = childrenForPicker(parentId)
      if (branch.length === 0) return null

      return (
        <div style={{ display: 'grid', gap: 4, marginLeft: level ? 18 : 0 }}>
          {branch.map((tag) => {
            const expanded = expandedTagIds.includes(tag.id)
            const childrenExist = hasChildren(tag.id)

            return (
              <div key={tag.id} onMouseEnter={() => beginTagHover(tag.id)} onMouseLeave={() => cancelTagHover(tag.id)}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 6px', borderRadius: 6, background: normalizedSelectedIds.includes(tag.id) ? '#eaf2ff' : 'transparent' }}>
                  <button
                    type="button"
                    onClick={() => toggleExpanded(tag.id)}
                    disabled={!childrenExist}
                    title={childrenExist ? 'Open child tags' : 'No child tags'}
                    style={{ width: 22, border: '1px solid #d5dce3', borderRadius: 4, background: childrenExist ? 'white' : '#f5f5f5', cursor: childrenExist ? 'pointer' : 'default' }}
                  >
                    {childrenExist ? (expanded ? '▾' : '▸') : ''}
                  </button>

                  <label style={{ display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer', flex: 1 }}>
                    <input type="checkbox" checked={normalizedSelectedIds.includes(tag.id)} onChange={(event) => { event.stopPropagation(); onToggle(tag.id) }} onClick={(event) => event.stopPropagation()} />
                    {tag.icon_data && <img src={tag.icon_data} alt="" style={{ width: 14, height: 14 }} />}
                    <span>{tag.name}</span>
                  </label>
                </div>

                {expanded && renderTagBranch(tag.id, level + 1)}
              </div>
            )
          })}
        </div>
      )
    }

    const labels = selectedTagLabels()

    return (
      <div ref={pickerRef} onMouseDown={(event) => event.stopPropagation()} onClick={(event) => event.stopPropagation()} style={{ position: 'relative', minWidth: 240 }}>
        <button
          type="button"
          onClick={() => setOpen(!open)}
          style={{ width: '100%', textAlign: 'left', padding: '6px 8px', border: '1px solid #cbd5e1', borderRadius: 8, background: 'white' }}
        >
          {labels.length ? `${labels.length} tag${labels.length === 1 ? '' : 's'} selected` : 'Select tags'} <span style={{ float: 'right' }}>{open ? '▴' : '▾'}</span>
        </button>

        {labels.length > 0 && (
          <div style={{ marginTop: 4, fontSize: 12, color: '#4b5563', lineHeight: 1.4 }}>
            {labels.slice(0, 3).join(', ')}{labels.length > 3 ? `, +${labels.length - 3} more` : ''}
          </div>
        )}

        {open && (
          <div style={{ position: 'absolute', zIndex: 50, top: 'calc(100% + 4px)', left: 0, width: 340, maxHeight: 360, overflow: 'auto', padding: 8, border: '1px solid #cbd5e1', borderRadius: 10, background: 'white', boxShadow: '0 12px 28px rgba(15, 23, 42, 0.18)' }}>
            <div style={{ fontSize: 12, color: '#64748b', marginBottom: 8 }}>Hover over a parent tag for 0.5 seconds, or click ▸, to show child tags.</div>
            {childrenForPicker('').length ? renderTagBranch('') : <div style={{ color: '#666' }}>No tags available.</div>}
            <div style={{ marginTop: 8, borderTop: '1px solid #e5e7eb', paddingTop: 8, display: 'flex', justifyContent: 'space-between', gap: 8 }}>
              <button type="button" onClick={() => setOpen(false)}>Done</button>
              {normalizedSelectedIds.length > 0 && <button type="button" onClick={() => selectedTerminalTagIds(normalizedSelectedIds).forEach((tagId) => onToggle(tagId))}>Clear</button>}
            </div>
          </div>
        )}
      </div>
    )
  }

  function renderTagPicker(selectedIds, onToggle, matterId = '') {
    return <TagTreeMultiSelect selectedIds={selectedIds || []} onToggle={onToggle} matterId={matterId} />
  }


