  function checklistHiddenWarningForSavedEvent(event, targetTab) {
    if (!event) return ''
    const reasons = []
    const matter = checklistMatterForEvent(event)

    if (matter) {
      const caseRaw = Array.isArray(checklistCaseStatusFilter) ? checklistCaseStatusFilter : null
      const matterRaw = Array.isArray(checklistMatterStatusFilter) ? checklistMatterStatusFilter : null
      const caseOptions = checklistFilterOptions('case').map((option) => option.value)
      const matterOptions = checklistFilterOptions('matter').map((option) => option.value)
      const selectedCases = caseRaw ? caseRaw.filter((value) => caseOptions.includes(value)) : []
      const selectedMatters = matterRaw ? matterRaw.filter((value) => matterOptions.includes(value)) : []
      const caseStatus = matter.case_status || ''
      const matterStatus = matter.matter_status || ''

      if (selectedCases.length > 0 && !selectedCases.includes(caseStatus)) {
        reasons.push(`Case Status filter does not include "${caseStatus || 'blank'}".`)
      }
      if (selectedMatters.length > 0 && !selectedMatters.includes(matterStatus)) {
        reasons.push(`Matter Status filter does not include "${matterStatus || 'blank'}".`)
      }
    }

    const categoryRaw = Array.isArray(checklistEventCategoryFilter) ? checklistEventCategoryFilter : null
    if (categoryRaw) {
      const categoryOptions = checklistFilterOptions('category').map((option) => option.value)
      const selectedCategories = categoryRaw.filter((value) => categoryOptions.includes(value))
      const category = event.checklist_category || event.event_category || ''
      if (selectedCategories.length > 0 && !selectedCategories.includes(category)) {
        reasons.push(`Event Category filter does not include "${category || 'blank'}".`)
      }
    }

    const isComplete = event.is_active === false || event.completed === true || event.status === 'completed'
    const date = checklistDateObj(event)
    if (targetTab === 'need_date' && (isComplete || date)) reasons.push('This event is not undated, so it will not appear in Need to Set.')
    if (targetTab === 'future' && (isComplete || !date)) reasons.push('This event is either completed or does not have a date, so it will not appear in Upcoming.')

    if (!reasons.length) return ''
    return `Saved, but this event may be hidden by the current Checklist view/filter selections:\n\n- ${reasons.join('\n- ')}\n\nChange the Checklist filters or switch tabs to see it.`
  }

  async function saveEvent(e) {
    e.preventDefault()
    if (isEventSaving) return

    if (!eventForm.title) {
      alert('Event title is required.')
      return
    }

    const isUndatedSave = !eventForm.start_date
    const cleanForm = {
      ...eventForm,
      matter_id: eventForm.matter_id || null,
      assigned_to: eventForm.assigned_to || null,
      // calendar_events.start_date is not nullable. Blank dates are saved with
      // UNDATED_EVENT_DATE and hidden from calendars/timelines by isUndatedEventDate().
      start_date: eventForm.start_date || UNDATED_EVENT_DATE,
      end_date: eventForm.start_date ? (eventForm.end_date || eventForm.start_date) : UNDATED_EVENT_DATE,
      is_active: eventForm.is_active ?? true
    }

    const eventSelect = `
      *,
      matters(
        id,
        name,
        cause_number,
        case_status,
        matter_status,
        clients(first_name, last_name),
        courts(
          court_name,
          county,
          court_phone,
          court_address,
          court_coordinator,
          court_coordinator_email,
          court_coordinator_phone,
          court_website,
          court_docket
        )
      ),
      team_members(first_name, last_name)
    `

    setIsEventSaving(true)
    try {
      let savedEvent = null
      let error = null

      if (editingEventId) {
        const result = await supabase
          .from('calendar_events')
          .update(cleanForm)
          .eq('id', editingEventId)
          .select(eventSelect)
          .single()
        savedEvent = result.data || { ...cleanForm, id: editingEventId }
        error = result.error
      } else {
        const result = await supabase
          .from('calendar_events')
          .insert([cleanForm])
          .select(eventSelect)
          .single()
        savedEvent = result.data
        error = result.error
      }

      if (error) {
        alert(error.message)
        return
      }

      if (savedEvent) {
        setEvents((currentEvents) => {
          const withoutOldCopy = currentEvents.filter((item) => item.id !== savedEvent.id)
          return [...withoutOldCopy, savedEvent]
        })
      }

      const savedEventIsComplete = savedEvent?.is_active === false || savedEvent?.completed === true || savedEvent?.status === 'completed'
      const priorEvent = editingEventId ? events.find((item) => String(item.id) === String(editingEventId)) : null
      const shouldKeepSetEventOnNeedPage = !!(editingEventId && !isUndatedSave && priorEvent && isUndatedEventDate(priorEvent.start_date))
      if (shouldKeepSetEventOnNeedPage && savedEvent?.id) {
        setNeedToSetSetRows((current) => ({ ...current, [String(savedEvent.id)]: { set_at: new Date().toISOString(), set_date: savedEvent.start_date || eventForm.start_date } }))
      }
      const targetChecklistTab = savedEventIsComplete ? 'completed' : (isUndatedSave || shouldKeepSetEventOnNeedPage) ? 'need_date' : 'future'
      const hiddenWarning = checklistHiddenWarningForSavedEvent(savedEvent, targetChecklistTab)

      closeEventWindow()
      setChecklistTab(targetChecklistTab)

      if (hiddenWarning) alert(hiddenWarning)

      const { data: refreshedEvents, error: refreshError } = await supabase
        .from('calendar_events')
        .select(eventSelect)
        .order('start_date', { ascending: true })
        .order('start_time', { ascending: true })
        .range(0, 9999)

      if (refreshError) {
        alert(refreshError.message)
        return
      }

      const refreshList = refreshedEvents || []
      if (savedEvent && !refreshList.some((item) => item.id === savedEvent.id)) {
        setEvents([...refreshList, savedEvent])
      } else {
        setEvents(refreshList)
      }
    } finally {
      setIsEventSaving(false)
    }
  }


