  async function saveTask(e) {
    e.preventDefault()

    if (!taskForm.matter_id || !taskForm.title || !taskForm.assign_date) {
      alert('Matter, title, and assign date are required.')
      return
    }

    if (!taskForm.assigned_user_ids || taskForm.assigned_user_ids.length === 0) {
      alert('Assign the task to at least one user.')
      return
    }

    const oldTask = editingTaskId ? tasks.find((task) => task.id === editingTaskId) : null
    const statusChanged = oldTask && oldTask.status !== taskForm.status

    const cleanForm = {
      matter_id: taskForm.matter_id,
      title: taskForm.title,
      description: taskForm.description,
      assign_date: taskForm.assign_date,
      task_category: taskForm.task_category,
      task_subcategory: taskForm.task_subcategory,
      status: taskForm.status || 'open',
      status_changed_at: statusChanged || !editingTaskId ? new Date().toISOString() : oldTask?.status_changed_at,
      is_active: taskForm.is_active
    }

    const { data, error } = editingTaskId
      ? await supabase.from('tasks').update(cleanForm).eq('id', editingTaskId).select().single()
      : await supabase.from('tasks').insert([cleanForm]).select().single()

    if (error) {
      alert(error.message)
      return
    }

    const taskId = data.id
    saveMioStateKey(`taskTemplateSubparts:${taskId}`, JSON.stringify(taskForm.template_subparts || []))
    saveMioStateKey(`taskMarkReviewWhen:${taskId}`, taskForm.mark_review_when || '')
    saveMioStateKey(`taskPriority:${taskId}`, taskForm.task_priority || 'normal')
    await supabase.from('task_assignments').delete().eq('task_id', taskId)

    const assignmentRows = taskForm.assigned_user_ids.map((userId) => ({
      task_id: taskId,
      team_member_id: userId
    }))

    if (assignmentRows.length > 0) {
      const { error: assignmentError } = await supabase.from('task_assignments').insert(assignmentRows)
      if (assignmentError) {
        alert(assignmentError.message)
        return
      }
    }

    if (taskForm.files?.length > 0) {
      const preparedFiles = await Promise.all(Array.from(taskForm.files).map(readFileAsDataUrl))
      const fileRows = preparedFiles.map((file) => ({
        task_id: taskId,
        comment_id: null,
        ...file
      }))
      const { error: fileError } = await supabase.from('task_files').insert(fileRows)
      if (fileError) {
        alert(fileError.message)
        return
      }
    }

    closeTaskWindow()
    fetchTasks()
  }

