  async function saveTaskComment(e) {
    e.preventDefault()

    if (!selectedTask || !commentText.trim()) {
      alert('Comment text is required.')
      return
    }

    const current = currentTeamMember()
    const { data, error } = await supabase
      .from('task_comments')
      .insert([{
        task_id: selectedTask.id,
        user_id: current?.id || null,
        comment_text: commentText.trim(),
        tagged_user_ids: commentTaggedUsers
      }])
      .select()
      .single()

    if (error) {
      alert(error.message)
      return
    }

    if (commentFiles?.length > 0) {
      const preparedFiles = await Promise.all(Array.from(commentFiles).map(readFileAsDataUrl))
      const fileRows = preparedFiles.map((file) => ({
        task_id: selectedTask.id,
        comment_id: data.id,
        ...file
      }))

      const { error: fileError } = await supabase.from('task_files').insert(fileRows)
      if (fileError) {
        alert(fileError.message)
        return
      }
    }

    setCommentText('')
    setCommentTaggedUsers([])
    setCommentFiles([])
    fetchTasks()
  }

