  function categoryLabel(category) {
    const found = settingCategories.find((item) => item.value === category)
    return found ? found.label : category
  }

  function selectedCourt() {
    return courts.find((court) => court.id === matterForm.court_id)
  }

  function getValue(row, field) {
    if (field === 'client_name') {
      return `${row.last_name || ''} ${row.first_name || ''}`
    }

    if (field === 'matter_client_name') {
      return `${row.clients?.last_name || ''} ${row.clients?.first_name || ''}`
    }

    if (field === 'team_name') {
      return `${row.last_name || ''} ${row.first_name || ''}`
    }

    if (field && field.startsWith('clients.')) {
      return row.clients?.[field.split('.')[1]] || ''
    }

    if (field === 'court_name') {
      return row.courts?.court_name || row.court_name || ''
    }

    if (field === 'category_label') {
      return categoryLabel(row.category)
    }

    if (field === 'status_label') {
      return row.is_active ? 'Active' : 'Inactive'
    }

    if (field === 'page_access_label') {
      return pageAccessLabel(row.page_access || row.default_pages || [])
    }

    if (field === 'opposing_party_1') {
      return matterPartyOne(row.id).name || ''
    }

    if (field === 'opposing_party_1_counsel') {
      return matterPartyOneCounsel(row.id).name || ''
    }

    if (field === 'opposing_party_1_counsel_firm') {
      return matterPartyOneCounsel(row.id).firm_name || ''
    }

    return row[field] ?? ''
  }

  function sortRows(rows, sort) {
    return [...rows].sort((a, b) => {
      const aValue = String(getValue(a, sort.field)).toLowerCase()
      const bValue = String(getValue(b, sort.field)).toLowerCase()

      if (aValue < bValue) return sort.direction === 'asc' ? -1 : 1
      if (aValue > bValue) return sort.direction === 'asc' ? 1 : -1
      return 0
    })
  }

  function changeSort(currentSort, setSort, field) {
    setSort({
      field,
      direction:
        currentSort.field === field && currentSort.direction === 'asc'
          ? 'desc'
          : 'asc'
    })
  }

  function sortLabel(sort, field) {
    if (sort.field !== field) return ''
    return sort.direction === 'asc' ? ' ▲' : ' ▼'
  }

  function sortIndicator(sort, field) {
    return sort.field === field ? sortLabel(sort, field) : ' ↕'
  }

  function fileToDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader()
      reader.onload = () => resolve(reader.result)
      reader.onerror = reject
      reader.readAsDataURL(file)
    })
  }

  async function handleTeamImageUpload(file) {
    if (!file) return

    const dataUrl = await fileToDataUrl(file)

    setTeamForm({
      ...teamForm,
      image_data: dataUrl,
      image_name: file.name
    })
  }

  function filterTeamRows(rows, statusFilter, positionFilter) {
    return rows.filter((member) => {
      const statusMatches =
        statusFilter === 'all' ||
        (statusFilter === 'active' && member.is_active) ||
        (statusFilter === 'inactive' && !member.is_active)

      const positionMatches =
        positionFilter === 'all' ||
        (member.position || '') === positionFilter

      return statusMatches && positionMatches
    })
  }

  function websiteLink(url, label) {
    if (!url) return null
    const fixedUrl = url.startsWith('http://') || url.startsWith('https://') ? url : `https://${url}`

    return (
      <a href={fixedUrl} target="_blank" rel="noreferrer">
        {label}
      </a>
    )
  }


  function downloadExcel(fileName, rows, sheetName = 'Sheet1', headers = []) {
    const safeRows = Array.isArray(rows) ? rows : []
    const worksheet =
      safeRows.length > 0
        ? XLSX.utils.json_to_sheet(safeRows)
        : XLSX.utils.aoa_to_sheet([headers])

    const workbook = XLSX.utils.book_new()
    XLSX.utils.book_append_sheet(workbook, worksheet, sheetName)
    XLSX.writeFile(workbook, fileName)
  }

  function readExcelFile(file, callback) {
    const reader = new FileReader()

    reader.onload = (event) => {
      const data = new Uint8Array(event.target.result)
      const workbook = XLSX.read(data, { type: 'array' })
      const sheetName = workbook.SheetNames[0]
      const worksheet = workbook.Sheets[sheetName]
      const rows = XLSX.utils.sheet_to_json(worksheet, { defval: '' })
      callback(rows)
    }

    reader.readAsArrayBuffer(file)
  }

  function excelCell(row, names, fallback = '') {
    for (const name of names) {
      if (row[name] !== undefined && row[name] !== null && String(row[name]).trim() !== '') {
        return row[name]
      }
    }

    return fallback
  }

