  async function importEventTable(rows) {
    if (!rows.length) return

    const payload = []
    for (const row of rows) {
      const title = excelCell(row, ['title', 'Title'])
      const startDate = excelCell(row, ['start_date', 'Start Date'])
      if (!title || !startDate) continue

      const matterName = excelCell(row, ['matter_name', 'Matter Name'])
      const assignedEmail = excelCell(row, ['assigned_to_email', 'Assigned To Email'])
      const matter = matterName ? matters.find((item) => String(item.name || '').toLowerCase() === String(matterName).toLowerCase()) : null
      const assigned = assignedEmail ? team.find((item) => String(item.email || '').toLowerCase() === String(assignedEmail).toLowerCase()) : null

      payload.push({
        matter_id: matter?.id || null,
        assigned_to: assigned?.id || null,
        event_category: excelCell(row, ['event_category', 'Event Category']),
        event_subcategory: excelCell(row, ['event_subcategory', 'Event Subcategory']),
        title,
        description: excelCell(row, ['description', 'Description']),
        start_date: startDate,
        start_time: excelCell(row, ['start_time', 'Start Time']),
        end_date: excelCell(row, ['end_date', 'End Date'], startDate),
        end_time: excelCell(row, ['end_time', 'End Time']),
        is_active: String(excelCell(row, ['is_active', 'Active'], 'TRUE')).toLowerCase() !== 'false'
      })
    }

    if (payload.length === 0) {
      alert('No valid event rows found.')
      return
    }

    const { error } = await supabase.from('calendar_events').insert(payload)
    if (error) alert(error.message)
    else {
      await fetchEvents()
      alert(`Imported ${payload.length} events.`)
    }
  }

  async function importTaskTable(rows) {
    if (!rows.length) return

    let imported = 0
    for (const row of rows) {
      const title = excelCell(row, ['title', 'Title'])
      const assignDate = excelCell(row, ['assign_date', 'Assign Date'])
      if (!title || !assignDate) continue

      const matterName = excelCell(row, ['matter_name', 'Matter Name'])
      const matter = matterName ? matters.find((item) => String(item.name || '').toLowerCase() === String(matterName).toLowerCase()) : null

      const { data: task, error } = await supabase.from('tasks').insert([{
        matter_id: matter?.id || null,
        title,
        description: excelCell(row, ['description', 'Description']),
        assign_date: assignDate,
        task_category: excelCell(row, ['task_category', 'Task Main Category']),
        task_subcategory: excelCell(row, ['task_subcategory', 'Task Subcategory']),
        status: excelCell(row, ['status', 'Status'], 'open'),
        status_changed_at: new Date().toISOString(),
        is_active: String(excelCell(row, ['is_active', 'Active'], 'TRUE')).toLowerCase() !== 'false'
      }]).select().single()

      if (error) {
        alert(error.message)
        return
      }

      const emails = String(excelCell(row, ['assigned_to_emails', 'Assigned To Emails'])).split(',').map((email) => email.trim().toLowerCase()).filter(Boolean)
      const assignments = team
        .filter((member) => emails.includes(String(member.email || '').toLowerCase()))
        .map((member) => ({ task_id: task.id, team_member_id: member.id }))

      if (assignments.length > 0) {
        await supabase.from('task_assignments').insert(assignments)
      }

      imported += 1
    }

    await fetchTasks()
    alert(`Imported ${imported} tasks.`)
  }

  async function importMatterTable(rows) {
    if (!rows.length) return

    let imported = 0

    for (const row of rows) {
      const firstName = String(row.client_first_name || row.first_name || '').trim()
      const lastName = String(row.client_last_name || row.last_name || '').trim()
      const email = String(row.client_email || row.email || '').trim()

      if (!firstName && !lastName && !email) continue

      let clientId = null

      if (email) {
        const { data: existingClient } = await supabase
          .from('clients')
          .select('id')
          .ilike('email', email)
          .limit(1)
          .maybeSingle()

        clientId = existingClient?.id || null
      }

      const clientPayload = {
        first_name: firstName,
        last_name: lastName,
        email,
        phone: row.client_phone || '',
        address: row.client_address || '',
        city: row.client_city || '',
        state: row.client_state || '',
        zip: row.client_zip || '',
        notes: row.client_notes || '',
        is_active: String(row.client_active || 'TRUE').toLowerCase() !== 'false'
      }

      if (clientId) {
        await supabase.from('clients').update(clientPayload).eq('id', clientId)
      } else {
        const { data: newClient, error: clientError } = await supabase
          .from('clients')
          .insert([clientPayload])
          .select('id')
          .single()

        if (clientError) {
          alert(clientError.message)
          return
        }

        clientId = newClient.id
      }

      let courtId = null
      const courtName = String(row.court_name || '').trim()

      if (courtName) {
        const { data: existingCourt } = await supabase
          .from('courts')
          .select('id')
          .ilike('court_name', courtName)
          .limit(1)
          .maybeSingle()

        courtId = existingCourt?.id || null
      }

      const matterPayload = {
        client_id: clientId,
        name: row.matter_name || row.name || `${firstName} ${lastName}`.trim(),
        cause_number: row.cause_number || '',
        hire_date: row.hire_date || '',
        matter_type: row.matter_type || '',
        matter_subtype: row.matter_subtype || '',
        client_status: row.client_status || '',
        case_status: row.case_status || '',
        matter_status: row.matter_status || '',
        court_id: courtId,
        notes: row.matter_notes || row.notes || '',
        is_active: String(row.matter_active || 'TRUE').toLowerCase() !== 'false'
      }

      const { error: matterError } = await supabase.from('matters').insert([matterPayload])

      if (matterError) {
        alert(matterError.message)
        return
      }

      imported += 1
    }

    await fetchClients()
    await fetchMatters()
    alert(`Imported ${imported} matter rows.`)
  }

