  function pageAccessLabel(pages) {
    if (!Array.isArray(pages) || pages.length === 0) return 'All pages'

    return pages
      .map((pageName) => appPages.find((p) => p.value === pageName)?.label || pageName)
      .join(', ')
  }

  function togglePageAccess(form, setForm, pageName) {
    const currentPages = Array.isArray(form.page_access) ? form.page_access : []
    const hasPage = currentPages.includes(pageName)

    setForm({
      ...form,
      page_access: hasPage
        ? currentPages.filter((p) => p !== pageName)
        : [...currentPages, pageName]
    })
  }

  function toggleDefaultPageAccess(pageName) {
    const currentPages = Array.isArray(settingForm.default_pages) ? settingForm.default_pages : []
    const hasPage = currentPages.includes(pageName)

    setSettingForm({
      ...settingForm,
      default_pages: hasPage
        ? currentPages.filter((p) => p !== pageName)
        : [...currentPages, pageName]
    })
  }

  function applyPositionDefaults(positionName) {
    const position = teamPositions().find((item) => item.name === positionName)

    setTeamForm({
      ...teamForm,
      position: positionName,
      page_access: Array.isArray(position?.default_pages) ? position.default_pages : []
    })
  }

