  async function updateClientCell(clientId, field, value) {
    if (!clientId) return
    const { error } = await supabase.from('clients').update({ [field]: value }).eq('id', clientId)
    if (error) alert(error.message)
    else {
      fetchClients()
      fetchMatters()
    }
  }

  async function updateMatterCell(matterId, field, value) {
    if (!matterId) return

    const cleanValue = value === '' ? null : value
    const updatePayload = { [field]: cleanValue }

    if (field === 'matter_status') {
      const existingMatter = matters.find((matter) => matter.id === matterId)

      if ((existingMatter?.matter_status || '') !== (cleanValue || '')) {
        updatePayload.matter_status_changed_at = new Date().toISOString()
      }
    }

    const { error } = await supabase.from('matters').update(updatePayload).eq('id', matterId)
    if (error) alert(error.message)
    else fetchMatters()
  }

  async function updateCourtCell(courtId, field, value) {
    if (!courtId) return
    const { error } = await supabase.from('courts').update({ [field]: value }).eq('id', courtId)
    if (error) alert(error.message)
    else {
      fetchCourts()
      fetchMatters()
    }
  }
async function updateTeamCell(memberId, field, value) {
    if (!memberId) return

    let cleanValue = value

    if (field === 'page_access') {
      cleanValue = String(value || '')
        .split(',')
        .map((item) => item.trim())
        .filter(Boolean)
    }

    const { error } = await supabase.from('team_members').update({ [field]: cleanValue }).eq('id', memberId)
    if (error) alert(error.message)
    else fetchTeam()
  }

