  function shownMatterColumns() {
    return matterPageColumns.filter((column) => visibleMatterColumns[column.key])
  }

  function toggleMatterColumn(columnKey) {
    const next = {
      ...visibleMatterColumns,
      [columnKey]: !visibleMatterColumns[columnKey]
    }
    setVisibleMatterColumns(next)
    saveMioStateKey('visibleMatterColumns', JSON.stringify(next))
  }

  function matterColumnWidth(columnKey) {
    const column = matterPageColumns.find((item) => item.key === columnKey)
    return Number(matterColumnWidths[columnKey] || column?.width || 160)
  }

  function matterColumnStyle(columnKey, isHeader = false) {
    const base = {
      minWidth: matterColumnWidth(columnKey),
      width: matterColumnWidth(columnKey),
      whiteSpace: isHeader ? 'nowrap' : 'nowrap',
      verticalAlign: isHeader ? 'middle' : 'middle',
      background: isHeader ? '#f7f7f7' : 'white',
      zIndex: isHeader ? 5 : 1
    }

    if (columnKey === 'matter') {
      return {
        ...base,
        position: 'sticky',
        left: 0,
        zIndex: isHeader ? 8 : 4,
        boxShadow: '2px 0 2px rgba(0,0,0,0.12)'
      }
    }

    if (columnKey === 'client' && visibleMatterColumns.matter) {
      const firstColumn = matterPageColumns.find((item) => item.key === 'matter')
      return {
        ...base,
        position: 'sticky',
        left: matterColumnWidth('matter'),
        zIndex: isHeader ? 8 : 4,
        boxShadow: '2px 0 2px rgba(0,0,0,0.12)'
      }
    }

    if (columnKey === 'client' && !visibleMatterColumns.matter) {
      return {
        ...base,
        position: 'sticky',
        left: 0,
        zIndex: isHeader ? 8 : 4,
        boxShadow: '2px 0 2px rgba(0,0,0,0.12)'
      }
    }

    return base
  }

  function matterDataCellStyle(columnKey) {
    return {
      ...matterColumnStyle(columnKey),
      height: 34,
      maxHeight: 34,
      lineHeight: '18px',
      padding: '4px 8px',
      overflow: 'hidden',
      textOverflow: 'ellipsis',
      whiteSpace: 'nowrap'
    }
  }

  function resizeMatterColumn(columnKey, width) {
    const cleanWidth = Math.max(80, Number(width) || 80)
    const next = {
      ...matterColumnWidths,
      [columnKey]: cleanWidth
    }
    setMatterColumnWidths(next)
    saveMioStateKey('matterColumnWidths', JSON.stringify(next))
  }

  function updateMatterPageFilter(key, value) {
    if (key === 'case_status') {
      setMatterPageFilterCaseStatus(value)
      saveMioStateKey('matterPageFilterCaseStatus', value)
    }

    if (key === 'matter_status') {
      setMatterPageFilterMatterStatus(value)
      saveMioStateKey('matterPageFilterMatterStatus', value)
    }

    if (key === 'case_type') {
      setMatterPageFilterCaseType(value)
      saveMioStateKey('matterPageFilterCaseType', value)
    }
  }

  function toggleShowUnpopulatedMatterStatuses() {
    const next = !showUnpopulatedMatterStatuses
    setShowUnpopulatedMatterStatuses(next)
    saveMioStateKey('showUnpopulatedMatterStatuses', String(next))
  }

  function nextFutureTrialDateForMatter(matter) {
    if (!matter?.id) return null
    const today = startOfTodayTimeline()
    const futureTrialDates = events
      .filter((event) => event.matter_id === matter.id && event.is_active !== false && eventLooksLike(event, 'trial'))
      .map((event) => parseTimelineDate(event.start_date))
      .filter((date) => date && date >= today)
      .sort((a, b) => a - b)

    return futureTrialDates[0] || null
  }

  function formatMatterTrialDate(matter) {
    const trialDate = nextFutureTrialDateForMatter(matter)
    return trialDate ? shortTimelineDate(trialDate) : ''
  }

  function daysUntilTrialForMatter(matter) {
    const trialDate = nextFutureTrialDateForMatter(matter)
    if (!trialDate) return null
    const today = startOfTodayTimeline()
    return Math.max(0, Math.ceil((trialDate - today) / 86400000))
  }

  function formatMatterDaysUntilTrial(matter) {
    const days = daysUntilTrialForMatter(matter)
    return days === null ? '' : String(days)
  }

  function matterCaseTypeText(matter) {
    return matter.matter_subtype
      ? `${matter.matter_type || ''} - ${matter.matter_subtype}`
      : matter.matter_type || ''
  }

  function matterEditableInputStyle(columnKey) {
    return {
      width: Math.max(60, matterColumnWidth(columnKey) - 18),
      border: '1px solid #ccc',
      padding: 2,
      boxSizing: 'border-box'
    }
  }

  function MatterTextDisplay({ children }) {
    return (
      <span style={{ display: 'block', minHeight: 18, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
        {children || ''}
      </span>
    )
  }

  function MatterEditableTextCell({ matter, field, columnKey, type = 'text' }) {
    if (!matterPageFieldsEditable) {
      return <MatterTextDisplay>{matter[field]}</MatterTextDisplay>
    }

    return (
      <input
        type={type}
        defaultValue={matter[field] || ''}
        onBlur={(e) => updateMatterCell(matter.id, field, e.target.value)}
        style={matterEditableInputStyle(columnKey)}
      />
    )
  }

  function MatterEditableSelectCell({ matter, field, columnKey, displayValue, children }) {
    if (!matterPageFieldsEditable) {
      return <MatterTextDisplay>{displayValue ?? matter[field]}</MatterTextDisplay>
    }

    return (
      <select
        value={matter[field] || ''}
        onChange={(e) => updateMatterCell(matter.id, field, e.target.value)}
        style={matterEditableInputStyle(columnKey)}
      >
        {children}
      </select>
    )
  }

