  async function reorderSettingOption(dropTargetId) {
    if (!draggedSettingId || draggedSettingId === dropTargetId) return

    const currentRows = [...filteredSettings].sort((a, b) => {
      const aOrder = a.sort_order ?? 999999
      const bOrder = b.sort_order ?? 999999
      if (aOrder !== bOrder) return aOrder - bOrder
      return String(a.name || '').localeCompare(String(b.name || ''))
    })

    const draggedRow = currentRows.find((item) => item.id === draggedSettingId)
    const targetIndex = currentRows.findIndex((item) => item.id === dropTargetId)

    if (!draggedRow || targetIndex === -1) {
      setDraggedSettingId(null)
      return
    }

    const remainingRows = currentRows.filter((item) => item.id !== draggedSettingId)
    remainingRows.splice(targetIndex, 0, draggedRow)

    const updates = remainingRows.map((item, index) =>
      supabase
        .from('setting_options')
        .update({ sort_order: index + 1 })
        .eq('id', item.id)
    )

    const results = await Promise.all(updates)
    const failed = results.find((result) => result.error)

    if (failed) alert(failed.error.message)
    else fetchSettings()

    setDraggedSettingId(null)
  }

  function syncMatterTableScroll(source) {
    const top = matterTableTopScrollRef.current
    const body = matterTableBodyScrollRef.current

    if (!top || !body) return

    if (source === 'top') {
      body.scrollLeft = top.scrollLeft
    } else {
      top.scrollLeft = body.scrollLeft
    }
  }

  function settingsMatterColumnWidth(index) {
    const widths = [
      160, 160, 220, 160, 220, 150, 90, 100,
      240, 160, 140, 180, 180, 180, 170, 190, 240, 220, 220, 240, 260, 120
    ]

    return widths[index] || 160
  }

  function settingsMatterCellStyle(index, isHeader = false) {
    const base = {
      minWidth: settingsMatterColumnWidth(index),
      width: settingsMatterColumnWidth(index),
      background: isHeader ? '#f7f7f7' : 'white'
    }

    if (index === 0) {
      return {
        ...base,
        position: 'sticky',
        left: 0,
        zIndex: isHeader ? 8 : 5,
        boxShadow: '2px 0 2px rgba(0,0,0,0.12)'
      }
    }

    if (index === 1) {
      return {
        ...base,
        position: 'sticky',
        left: settingsMatterColumnWidth(0),
        zIndex: isHeader ? 8 : 5,
        boxShadow: '2px 0 2px rgba(0,0,0,0.12)'
      }
    }

    return base
  }

  function settingsMatterHeaderStyle(index) {
    return {
      ...settingsMatterCellStyle(index, true),
      position: 'sticky',
      top: 0,
      zIndex: index < 2 ? 20 : 15,
      whiteSpace: 'nowrap'
    }
  }

  async function deleteRow(table, id, refreshFn, label) {
    if (!confirm(`Delete this ${label}?`)) return

    const { error } = await supabase.from(table).delete().eq('id', id)

    if (error) alert(error.message)
    else refreshFn()
  }

  const filteredSettings = settingsFilter === 'all'
    ? settings
    : settings.filter((item) => {
        if (item.category !== settingsFilter) return false

        if (settingsFilter === 'matter_status_step') {
          const selectedMatterStatus = settingForm.parent_name || ''
          const selectedClientStatus = settingForm.default_pages?.client_status || ''

          if (selectedMatterStatus && item.parent_name !== selectedMatterStatus) return false
          if (selectedClientStatus && (item.default_pages?.client_status || '') !== selectedClientStatus) return false
        }

        if (settingsFilter === 'checklist_setting_step') {
          const selectedSettingType = settingForm.parent_name || ''
          if (selectedSettingType && item.parent_name !== selectedSettingType) return false
        }

        return true
      })
  const teamPositionSettings = settings.filter((item) => item.category === 'team_position')
  const filteredClients = clients.filter((client) => {
    if (clientFilter === 'active') return client.is_active
    if (clientFilter === 'inactive') return !client.is_active
    return true
  })

  const sortedSettings = [...filteredSettings].sort((a, b) => {
    if (settingsFilter === 'all') {
      const categoryCompare = String(categoryLabel(a.category)).localeCompare(String(categoryLabel(b.category)))
      if (categoryCompare !== 0) return categoryCompare
    }

    const aOrder = a.sort_order ?? 999999
    const bOrder = b.sort_order ?? 999999
    if (aOrder !== bOrder) return aOrder - bOrder
    return String(a.name || '').localeCompare(String(b.name || ''))
  })

  function matterStepsForMatter(matter) {
    return settings
      .filter((item) => item.category === 'matter_status_step' && item.is_active && item.parent_name === matter.matter_status && (!item.default_pages?.client_status || item.default_pages.client_status === matter.client_status))
      .sort((a, b) => (a.sort_order ?? 999999) - (b.sort_order ?? 999999) || String(a.name || '').localeCompare(String(b.name || '')))
  }

  function matterStepCompletionKey(matterId, stepId) {
    return `${matterId}::${stepId}`
  }

  function matterStepCompletion(matterId, stepId) {
    return matterStepCompletions[matterStepCompletionKey(matterId, stepId)] || null
  }

  function toggleMatterStepComplete(matterId, stepId) {
    const key = matterStepCompletionKey(matterId, stepId)
    setMatterStepCompletions((current) => {
      const existing = current[key]
      if (existing?.completed) return { ...current, [key]: { ...existing, completed: false, completed_at: '' } }
      return { ...current, [key]: { completed: true, completed_at: new Date().toISOString() } }
    })
  }

  function matterStepsRowVisible(matterId) {
    return !!matterStepsExpandedByRow[String(matterId)]
  }

  function toggleMatterStepsRow(matterId) {
    if (!matterId) return
    setMatterStepsExpandedByRow((current) => ({ ...current, [String(matterId)]: !current[String(matterId)] }))
  }

  function renderMatterStepsRow(matter) {
    const steps = matterStepsForMatter(matter)
    if (!showMatterStepsOnMatterPage || !matterStepsRowVisible(matter.id) || steps.length === 0) return null
    return (
      <tr key={`${matter.id}-steps`}>
        <td colSpan={shownMatterColumns().length + 1} style={{ background: '#f8fafc', padding: 8 }}>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'stretch' }}>
            {steps.map((step, stepIndex) => {
              const completion = matterStepCompletion(matter.id, step.id)
              const completed = completion?.completed
              return (
                <details key={step.id} style={{ border: completed ? '1px solid #cbd5e1' : '3px solid #334155', borderRadius: 8, padding: 8, minWidth: 190, background: completed ? '#e5e7eb' : (timing?.inactive ? '#e5e7eb' : 'white'), color: completed ? '#94a3b8' : '#0f172a', fontWeight: completed ? 'normal' : 'bold' }}>
                  <summary
                    style={{ cursor: 'pointer' }}
                    onClick={(e) => {
                      e.preventDefault()
                      openStepDetail({ type: 'matter', matter, matterId: matter.id, step, stepName: step.name, billingStepName: step.name, taskId: `matter-step-${matter.id}-${step.id}` })
                    }}
                  >{step.name}</summary>
                  <div style={{ marginTop: 8, fontWeight: 'normal', color: completed ? '#94a3b8' : '#334155' }}>
                    <div><strong>For:</strong> {step.parent_name} / {step.default_pages?.client_status || 'Any party type'}</div>
                    {completion?.completed_at && <div><strong>Completed:</strong> {new Date(completion.completed_at).toLocaleString()}</div>}
                    <div style={{ marginTop: 6 }}><MatterBillingButtons matter={matter} stepName={step.name} /></div>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 6 }}>
                      <button type="button" onClick={() => openStepDetail({ type: 'matter', matter, matterId: matter.id, step, stepName: step.name, billingStepName: step.name, taskId: `matter-step-${matter.id}-${step.id}` })}>Open step</button>
                      <button type="button" onClick={() => openSettingWorkspace({ type: 'matter', matter, matterId: matter.id, step, stepName: step.name, billingStepName: step.name, taskId: `matter-step-${matter.id}-${step.id}` })}>Open task</button>
                      <button type="button" onClick={() => toggleMatterStepComplete(matter.id, step.id)}>
                        {completed ? 'Mark incomplete' : 'Mark complete'}
                      </button>
                    </div>
                  </div>
                </details>
              )
            })}
          </div>
        </td>
      </tr>
    )
  }


  function checklistStepsForEvent(event) {
    const settingType = event?.checklist_category || event?.event_category || ''
    if (!settingType) return []
    return settings
      .filter((item) => item.category === 'checklist_setting_step' && item.is_active && item.parent_name === settingType)
      .sort((a, b) => (a.sort_order ?? 999999) - (b.sort_order ?? 999999) || String(a.name || '').localeCompare(String(b.name || '')))
  }

  function checklistStepCompletionKey(eventId, stepId) {
    return `${eventId}::${stepId}`
  }

  function checklistStepCompletion(eventId, stepId) {
    return checklistStepCompletions[checklistStepCompletionKey(eventId, stepId)] || null
  }

  function checklistStepsRowVisible(eventId) {
    if (!showNeedToSetSteps) return false
    return checklistStepsExpandedByRow[String(eventId)] !== false
  }

  function toggleChecklistStepsRow(eventId) {
    if (!eventId) return
    setChecklistStepsExpandedByRow((current) => ({ ...current, [String(eventId)]: current[String(eventId)] === false ? true : false }))
  }

  function toggleChecklistStepComplete(eventId, stepId) {
    const key = checklistStepCompletionKey(eventId, stepId)
    setChecklistStepCompletions((current) => {
      const existing = current[key]
      if (existing?.completed) return { ...current, [key]: { ...existing, completed: false, completed_at: '' } }
      return { ...current, [key]: { completed: true, completed_at: new Date().toISOString() } }
    })
  }

  function openChecklistStepBilling(event, stepName) {
    const matter = checklistMatterForEvent(event)
    if (!matter?.id) {
      alert('This checklist row does not have a matter selected, so a billing entry cannot be started from this step.')
      return
    }
    openBillingWindow({
      matter_id: matter.id,
      matter_status: matter.matter_status || '',
      matter_step: `Need to Set - ${event?.checklist_category || event?.event_category || 'Setting'}: ${stepName}`
    })
  }

  function renderChecklistStepsRow(event) {
    const eventId = event?.id || event?.checklist_source_id
    const steps = checklistStepsForEvent(event)
    if (!showNeedToSetSteps || !['need_date', 'set'].includes(checklistTab) || !eventId || !checklistStepsRowVisible(eventId) || steps.length === 0) return null
    return (
      <tr key={`${event.checklist_id || event.id}-need-to-set-steps`}>
        <td colSpan={checklistTab === 'need_date' ? 7 : 5} style={{ background: '#f8fafc', padding: 8, borderBottom: '1px solid #e5e7eb' }}>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'stretch' }}>
            {steps.map((step, stepIndex) => {
              const completion = checklistStepCompletion(eventId, step.id)
              const completed = completion?.completed
              const timing = needToSetStepTiming({ type: 'checklist', event, eventId }, step, stepIndex, steps)
              const stepOutline = completed ? '#e5e7eb' : '#111827'
              const stepContext = { type: 'checklist', event, eventId, matter: checklistMatterForEvent(event), matterId: checklistMatterForEvent(event)?.id || '', step, stepName: step.name, settingType: event?.checklist_category || event?.event_category || step.parent_name || 'Setting', billingStepName: `Need to Set - ${event?.checklist_category || event?.event_category || step.parent_name || 'Setting'}: ${step.name}`, courtName: checklistCourtName(event), courtEmail: checklistCourtCoordinatorEmail(event) }
              const workspace = normalizeWorkspace(stepContext)
              const stepKey = workspaceStepKey(stepContext, stepIndex)
              const stepEmails = (workspace.emails || []).filter((email) => String(email.step_key || email.step_id || '') === stepKey)
              const stepHasNewEmail = stepEmails.some((email) => email.new_email_notice || workspaceEmailHasUnreadActivity(email))
              return (
                <details key={step.id} className="need-step-card" style={{ border: `3px solid ${stepOutline}`, borderLeft: `8px solid ${completed ? '#e5e7eb' : (timing.inactive ? '#cbd5e1' : timing.color)}`, borderRadius: 8, padding: 8, minWidth: 260, background: completed ? '#f8fafc' : (timing.inactive ? '#e5e7eb' : 'white'), color: completed ? '#94a3b8' : '#0f172a', fontWeight: completed ? 'normal' : 'bold', opacity: completed ? 0.48 : 1 }}>
                  <summary
                    style={{ cursor: 'pointer', color: completed ? '#94a3b8' : '#1d4ed8', fontWeight: completed ? 'normal' : 'bold', display: 'flex', gap: 8, alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap' }}
                    onClick={(e) => {
                      e.preventDefault()
                      openStepDetail(stepContext)
                    }}
                  >
                    <span>{completed && <span title="Complete" style={{ color: '#16a34a', marginRight: 6 }}>✓</span>}{step.name}{stepHasNewEmail && <span title="New email on this step" style={{ marginLeft: 8, color: '#b91c1c' }}>📧</span>}</span>
                    <span className="need-step-hover-actions" onClick={(actionEvent) => actionEvent.stopPropagation()} style={{ display: 'none', gap: 5, flexWrap: 'wrap' }}>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); openChecklistStepBilling(event, step.name) }}>Add time on this step</button>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); openStepDetail(stepContext) }}>Open step</button>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); openSettingWorkspace(stepContext) }}>Open setting</button>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); toggleChecklistStepComplete(eventId, step.id) }}>{completed ? 'Mark incomplete' : 'Mark complete'}</button>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); addWorkspaceEmailForStep(stepContext, stepContext, null, 'attach') }}>Open existing email thread</button>
                      <button type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); addWorkspaceEmailForStep(stepContext, stepContext, null, 'compose') }}>Send email</button>
                      {stepEmails.map((email, idx) => <button key={email.id} type="button" onClick={(actionEvent) => { actionEvent.preventDefault(); openStepDetail(stepContext); patchWorkspaceEmail(stepContext, email.id, { collapsed: false }) }}>Email {idx + 1}</button>)}
                    </span>
                  </summary>
                  <div style={{ marginTop: 8, fontWeight: 'normal', color: completed ? '#94a3b8' : '#334155' }}>
                    <div><strong>For:</strong> {step.parent_name}</div>
                    {completion?.completed_at && <div><strong>Completed:</strong> {new Date(completion.completed_at).toLocaleString()}</div>}
                    <div style={{ marginTop: 6 }}>
                      <button type="button" onClick={() => openChecklistStepBilling(event, step.name)} title={`Add time for ${step.name}`} style={{ border: '1px solid #86efac', borderRadius: 999, padding: '3px 8px', background: '#f0fdf4' }}>◴ Time</button>
                    </div>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 6 }}>
                      <button type="button" onClick={() => openStepDetail(stepContext)}>Open step</button>
                      <button type="button" onClick={() => openSettingWorkspace(stepContext)}>Open setting</button>
                      <button type="button" onClick={() => toggleChecklistStepComplete(eventId, step.id)}>
                        {completed ? 'Mark incomplete' : 'Mark complete'}
                      </button>
                    </div>
                  </div>
                </details>
              )
            })}
          </div>
        </td>
      </tr>
    )
  }

  const sortedTeamPositions = sortRows(teamPositionSettings, positionsSort)
  const filteredTeam = filterTeamRows(team, teamStatusFilter, teamPositionFilter)
  const filteredTeamTable = filterTeamRows(team, teamTableStatusFilter, teamTablePositionFilter)
  const sortedTeam = sortRows(filteredTeam, teamSort)
  const sortedTeamTable = sortRows(filteredTeamTable, teamSort)
  const sortedClients = sortRows(filteredClients, clientSort)
  const sortedCourts = sortRows(courts, courtsSort)
  const sortedMatters = sortRows(matters, mattersSort)
  const normalizeMatterStatus = (value) => String(value || '').trim().toLowerCase()
  const matterStatusOptions = options('matter_status')
  const matterStatusOptionKeys = new Set(matterStatusOptions.map((status) => normalizeMatterStatus(status.name)))
  const filteredSortedMatters = sortedMatters.filter((matter) => {
    const caseStatusMatches =
      matterPageFilterCaseStatus === 'all' ||
      normalizeMatterStatus(matter.case_status) === normalizeMatterStatus(matterPageFilterCaseStatus)

    const matterStatusMatches =
      matterPageFilterMatterStatus === 'all' ||
      (matterPageFilterMatterStatus === '__blank__' && !normalizeMatterStatus(matter.matter_status)) ||
      normalizeMatterStatus(matter.matter_status) === normalizeMatterStatus(matterPageFilterMatterStatus)

    const caseTypeMatches =
      matterPageFilterCaseType === 'all' ||
      normalizeMatterStatus(matter.matter_type) === normalizeMatterStatus(matterPageFilterCaseType)

    const searchText = normalizeMatterStatus(matterPageSearch)
    const searchableMatterText = [
      matter.name,
      matter.cause_number,
      matter.matter_type,
      matter.matter_subtype,
      matter.client_status,
      matter.case_status,
      matter.matter_status,
      matter.notes,
      matter.clients?.first_name,
      matter.clients?.last_name,
      matter.clients?.email,
      matter.clients?.phone,
      matter.courts?.court_name,
      matterPartyOne(matter.id).name,
      matterPartyOneCounsel(matter.id).name,
      matterPartyOneCounsel(matter.id).firm_name,
      formatMatterOption(matter)
    ].filter(Boolean).join(' ').toLowerCase()
    const searchMatches = !searchText || searchableMatterText.includes(searchText)

    return caseStatusMatches && matterStatusMatches && caseTypeMatches && searchMatches
  })
  function matterStatusColor(statusName) {
    const status = settings.find((item) => item.category === 'matter_status' && normalizeMatterStatus(item.name) === normalizeMatterStatus(statusName))
    return status?.color || '#d9d9d9'
  }

  function sortMattersByStatusEntryOrder(rows) {
    return [...rows].sort((a, b) => {
      const aTrialDate = nextFutureTrialDateForMatter(a)
      const bTrialDate = nextFutureTrialDateForMatter(b)

      if (aTrialDate && bTrialDate) return aTrialDate - bTrialDate
      if (aTrialDate) return -1
      if (bTrialDate) return 1

      const aDate = new Date(a.matter_status_changed_at || a.created_at || 0)
      const bDate = new Date(b.matter_status_changed_at || b.created_at || 0)
      return aDate - bDate
    })
  }

  const noMatterStatusMatters = filteredSortedMatters.filter((matter) => {
    const key = normalizeMatterStatus(matter.matter_status)
    return !key || !matterStatusOptionKeys.has(key)
  })

  const allMatterStatusSections = [
    ...(noMatterStatusMatters.length > 0
      ? [{
          label: 'No Matter Status',
          matters: sortMattersByStatusEntryOrder(noMatterStatusMatters)
        }]
      : []),
    ...matterStatusOptions.map((status) => ({
      label: status.name,
      matters: sortMattersByStatusEntryOrder(filteredSortedMatters.filter((matter) => normalizeMatterStatus(matter.matter_status) === normalizeMatterStatus(status.name)))
    }))
  ]

  const matterStatusSections = showUnpopulatedMatterStatuses
    ? allMatterStatusSections
    : allMatterStatusSections.filter((section) => section.matters.length > 0)

  const settingsMatterTableRows = sortRows(
    matters.filter((matter) => {
      const caseMatches = settingsMatterTableFilters.case_status === 'all' || normalizeMatterStatus(matter.case_status) === normalizeMatterStatus(settingsMatterTableFilters.case_status)
      const matterMatches = settingsMatterTableFilters.matter_status === 'all' ||
        (settingsMatterTableFilters.matter_status === '__blank__' && !normalizeMatterStatus(matter.matter_status)) ||
        normalizeMatterStatus(matter.matter_status) === normalizeMatterStatus(settingsMatterTableFilters.matter_status)
      return caseMatches && matterMatches
    }),
    settingsMatterTableSort
  )

  const settingsMatterHeaderSortFields = [
    'clients.first_name',
    'clients.last_name',
    'clients.email',
    'clients.phone',
    'clients.address',
    'clients.city',
    'clients.state',
    'clients.zip',
    'name',
    'cause_number',
    'hire_date',
    'matter_type',
    'matter_subtype',
    'client_status',
    'case_status',
    'matter_status',
    'court_name',
    'opposing_party_1',
    'opposing_party_1_counsel',
    'opposing_party_1_counsel_firm',
    'notes',
    'status_label'
  ]

  function renderUserFieldsSettings() {
    const fieldTypeLabel = (type) => ({ date: 'Date box', time: 'Time box', text: 'Text box', long_text: 'Long text box', number: 'Number box', money: 'Money box' }[type] || type || 'Text box')
    const fieldUsageCount = (fieldId) => documentFieldTagRules.filter((rule) => rule.field_definition_id === fieldId).length
    const selectedBaseField = documentFieldDefinitions.find((field) => field.id === calculatedFieldForm.base_field_id)
    return (
      <>
        <h2>Fields</h2>
        <p>User fields are reusable fields you create. Page fields are built into Case Controller pages and can be inserted into AI rules as references.</p>
        <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, marginBottom: 18, background: '#f8fbff' }}>
          <h3>User Fields</h3>
          <h4>Create a reusable field</h4>
          <form onSubmit={saveDocumentFieldDefinition} style={{ display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'end' }}>
            <LabeledField label="Field name"><input value={documentFieldForm.label} onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, label: e.target.value })} placeholder="Example: Setting Date" /></LabeledField>
            <LabeledField label="Field type"><select value={documentFieldForm.field_type} onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, field_type: e.target.value })}><option value="date">Date box</option><option value="time">Time box</option><option value="text">Text box</option><option value="long_text">Long text box</option><option value="number">Number box</option><option value="money">Money box</option></select></LabeledField>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 5, marginBottom: 4 }}><input type="checkbox" checked={documentFieldForm.is_active} onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, is_active: e.target.checked })} /> Active</label>
            <div style={{ flexBasis: '100%' }}>
              <LabeledField label="Default AI instructions for this field">
                <FieldReferenceTextarea
                  pageRefs={pageFieldReferenceList()}
                  userRefs={userFieldReferenceList()}
                  value={documentFieldForm.default_ai_instructions || ''}
                  onValueChange={(value) => setDocumentFieldForm({ ...documentFieldForm, default_ai_instructions: value })}
                  rows={4}
                  placeholder="Example: Find the hearing or setting time. Look near the setting date. Do not use the filing stamp time."
                />
              </LabeledField>
            </div>
            <button type="submit">{documentFieldForm.id ? 'Save User Field' : 'Add User Field'}</button>
          </form>
        </section>
        <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, marginBottom: 18, background: 'white' }}>
          <h4>Existing user fields</h4>
          {documentFieldDefinitions.length === 0 && <p>No user fields yet.</p>}
          {documentFieldDefinitions.map((field) => (
            <div key={field.id} style={{ display: 'flex', gap: 10, alignItems: 'center', borderTop: '1px solid #e5e7eb', padding: '8px 0' }}>
              <strong>{field.label}</strong><span>{fieldTypeLabel(field.field_type)}</span><span style={{ color: '#64748b' }}>Used on {fieldUsageCount(field.id)} tag{fieldUsageCount(field.id) === 1 ? '' : 's'}</span>{(userFieldDefaultInstructions[field.id] || userFieldDefaultInstructions[field.field_key]) && <span style={{ color: '#64748b' }}>Default AI instructions saved</span>}<span style={{ flex: 1 }} />
              <button type="button" onClick={() => { setDocumentFieldForm({ ...field, default_ai_instructions: userFieldDefaultInstructions[field.id] || userFieldDefaultInstructions[field.field_key] || defaultExtractionInstructionsForField(field.id) }); setSettingsTab('fields') }}>Edit</button>
              <button type="button" onClick={() => deleteDocumentFieldEverywhere(field.id)}>Delete</button>
            </div>
          ))}
        </section>
        <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, marginBottom: 18, background: 'white' }}>
          <h3>Page Fields</h3>
          <p style={{ color: '#555' }}>
            These are built-in fields already on Case Controller pages. Use these codes in AI rules when the AI should compare a document to matter data, party names, opposing counsel names, the client, the court, or similar page values.
          </p>
          {Object.entries(pageFieldReferenceList().reduce((groups, field) => {
            const group = field.group || 'Other'
            groups[group] = groups[group] || []
            groups[group].push(field)
            return groups
          }, {})).map(([group, fields]) => (
            <details key={group} open={group === 'Opposing / Additional Party 1'} style={{ borderTop: '1px solid #e5e7eb', padding: '8px 0' }}>
              <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>{group}</summary>
              <div style={{ display: 'grid', gap: 6, marginTop: 8 }}>
                {fields.map((field) => (
                  <div key={field.token} style={{ display: 'grid', gridTemplateColumns: 'minmax(260px, 1fr) minmax(280px, 1.2fr)', gap: 10, alignItems: 'center' }}>
                    <span>{field.label}</span>
                    <code style={{ whiteSpace: 'normal' }}>{field.token}</code>
                  </div>
                ))}
              </div>
            </details>
          ))}
        </section>

        <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, background: '#fffaf0' }}>
          <h3>Calculated fields</h3>
          <p style={{ color: '#555' }}>Create fields calculated from existing fields, such as adding days, subtracting days, finding the difference between fields, or moving weekend/holiday dates to the next business day.</p>
          <form onSubmit={saveCalculatedUserField} style={{ display: 'grid', gap: 10 }}>
            <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'end' }}>
              <LabeledField label="Calculated field name"><input value={calculatedFieldForm.label} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, label: e.target.value })} placeholder="Example: Response Due Date" /></LabeledField>
              <LabeledField label="Result type"><select value={calculatedFieldForm.field_type} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, field_type: e.target.value })}><option value="date">Date</option><option value="number">Number</option><option value="text">Text</option></select></LabeledField>
              <LabeledField label="Start with field"><select value={calculatedFieldForm.base_field_id} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, base_field_id: e.target.value })}><option value="">Select field</option>{documentFieldDefinitions.map((field) => <option key={field.id} value={field.id}>{field.label}</option>)}</select></LabeledField>
              <LabeledField label="Calculation"><select value={calculatedFieldForm.operation} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, operation: e.target.value })}><option value="add_days">Add days</option><option value="subtract_days">Subtract days</option><option value="difference_between_dates">Difference between two date fields</option></select></LabeledField>
              {calculatedFieldForm.operation !== 'difference_between_dates' && <LabeledField label="Days"><input type="number" value={calculatedFieldForm.days} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, days: e.target.value })} placeholder="Example: 20" /></LabeledField>}
              {calculatedFieldForm.operation === 'difference_between_dates' && <LabeledField label="Second date field"><select value={calculatedFieldForm.second_field_id} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, second_field_id: e.target.value })}><option value="">Select field</option>{documentFieldDefinitions.filter((field) => field.id !== calculatedFieldForm.base_field_id).map((field) => <option key={field.id} value={field.id}>{field.label}</option>)}</select></LabeledField>}
            </div>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}><input type="checkbox" checked={calculatedFieldForm.adjust_weekend_holiday} onChange={(e) => setCalculatedFieldForm({ ...calculatedFieldForm, adjust_weekend_holiday: e.target.checked })} /> If date falls on a weekend or holiday, move to the next non-weekend/non-holiday date.</label>
            <button type="submit" style={{ width: 180 }}>{calculatedFieldForm.id ? 'Save Calculation' : 'Add Calculation'}</button>
            {selectedBaseField && <small>Starts from: {selectedBaseField.label}</small>}
          </form>
          <h4>Saved calculated fields</h4>
          {calculatedUserFields.length === 0 && <p>No calculated fields yet.</p>}
          {calculatedUserFields.map((field) => {
            const base = documentFieldDefinitions.find((item) => item.id === field.base_field_id)
            const second = documentFieldDefinitions.find((item) => item.id === field.second_field_id)
            return <div key={field.id} style={{ borderTop: '1px solid #eadfca', padding: '8px 0', display: 'flex', gap: 10, alignItems: 'center' }}><strong>{field.label}</strong><span>{field.operation === 'difference_between_dates' ? `difference between ${base?.label || 'field'} and ${second?.label || 'field'}` : `${field.operation === 'add_days' ? 'add' : 'subtract'} ${field.days || 0} days from ${base?.label || 'field'}`}</span>{field.adjust_weekend_holiday && <span>business-day adjusted</span>}<span style={{ flex: 1 }} /><button type="button" onClick={() => startEditCalculatedUserField(field)}>Edit</button><button type="button" onClick={() => deleteCalculatedUserField(field.id)}>Delete</button></div>
          })}
        </section>
      </>
    )
  }


  function aiFeedbackOutcomeLabel(outcome) {
    if (outcome === 'correct') return 'Correct'
    if (outcome === 'partial') return 'Partially correct'
    if (outcome === 'incorrect') return 'Incorrect'
    return outcome || 'Unknown'
  }

  function aiFeedbackStats(records = aiFeedbackRecords) {
    const total = records.length
    const correct = records.filter((record) => record.outcome === 'correct').length
    const partial = records.filter((record) => record.outcome === 'partial').length
    const incorrect = records.filter((record) => record.outcome === 'incorrect').length
    const score = total ? Math.round(((correct + partial * 0.5) / total) * 100) : 0
    return { total, correct, partial, incorrect, score }
  }

  function aiFeedbackStatsByTag() {
    const byTag = new Map()
    aiFeedbackRecords.forEach((record) => {
      const paths = Array.from(new Set([...(record.ai_tag_paths || []), ...(record.final_tag_paths || [])].filter(Boolean)))
      paths.forEach((path) => {
        const list = byTag.get(path) || []
        list.push(record)
        byTag.set(path, list)
      })
    })
    return Array.from(byTag.entries())
      .map(([tagPath, records]) => ({ tagPath, ...aiFeedbackStats(records) }))
      .sort((a, b) => a.tagPath.localeCompare(b.tagPath))
  }

  function renderAiGuessReviewDashboard() {
    const stats = aiFeedbackStats()
    const tagStats = aiFeedbackStatsByTag()
    return (
      <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, background: 'white', marginBottom: 14 }}>
        <h3>AI Guess Review and Accuracy</h3>
        <p style={{ color: '#555' }}>
          Review prior AI guesses, the final tags/fields you accepted, and your feedback. Use this to identify which tag rules need changes.
        </p>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', marginBottom: 12 }}>
          <strong>Overall score: {stats.total ? `${stats.score}%` : 'No feedback yet'}</strong>
          <span>Correct: {stats.correct}</span>
          <span>Partial: {stats.partial}</span>
          <span>Incorrect: {stats.incorrect}</span>
          <span>Total reviewed: {stats.total}</span>
        </div>
        <h4>Accuracy by tag</h4>
        {tagStats.length === 0 ? <p>No reviewed guesses yet.</p> : (
          <table cellPadding="5" style={{ width: '100%', borderCollapse: 'collapse', marginBottom: 14 }}>
            <thead><tr><th>Tag</th><th>Score</th><th>Correct</th><th>Partial</th><th>Incorrect</th><th>Total</th></tr></thead>
            <tbody>
              {tagStats.map((row) => (
                <tr key={row.tagPath} style={{ borderTop: '1px solid #e5e7eb' }}>
                  <td>{row.tagPath}</td><td>{row.score}%</td><td>{row.correct}</td><td>{row.partial}</td><td>{row.incorrect}</td><td>{row.total}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
        <h4>Reviewed guesses</h4>
        {aiFeedbackRecords.length === 0 ? <p>No AI feedback has been saved yet.</p> : (
          <div style={{ maxHeight: 420, overflow: 'auto', border: '1px solid #e5e7eb' }}>
            <table cellPadding="5" style={{ width: '100%', borderCollapse: 'collapse', minWidth: 1000 }}>
              <thead><tr><th>Date</th><th>Document</th><th>Result</th><th>AI tags</th><th>Final tags</th><th>Feedback</th><th>Summary / warnings</th></tr></thead>
              <tbody>
                {aiFeedbackRecords.map((record) => (
                  <tr key={record.id} style={{ borderTop: '1px solid #e5e7eb', verticalAlign: 'top' }}>
                    <td>{record.created_at ? new Date(record.created_at).toLocaleString() : ''}</td>
                    <td>{record.document_name || record.file_name || record.document_id || 'Document'}</td>
                    <td>{aiFeedbackOutcomeLabel(record.outcome)}</td>
                    <td>{(record.ai_tag_paths || []).join(', ') || 'None'}</td>
                    <td>{(record.final_tag_paths || []).join(', ') || 'None'}</td>
                    <td style={{ whiteSpace: 'pre-wrap' }}>{record.feedback || ''}</td>
                    <td style={{ whiteSpace: 'pre-wrap' }}>{[record.ai_summary, ...(record.ai_warnings || [])].filter(Boolean).join('\n')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </section>
    )
  }


  function escapeHtmlForRulesReport(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  function triggerTypeLabel(type) {
    const labels = {
      positive: 'Positive / inclusion rule',
      required: 'Required rule',
      exclusion: 'Exclusion rule',
      context: 'Context rule'
    }
    return labels[type] || labels.positive
  }

  function openAiRulesPdfReport() {
    const sortedTags = [...(tags || [])].sort((a, b) => (tagFullName(a.id) || a.name || '').localeCompare(tagFullName(b.id) || b.name || ''))
    const rulesForTag = (tagId) => (aiTagRules || [])
      .filter((rule) => rule.tag_id === tagId && rule.is_active !== false)
      .sort((a, b) => {
        const da = aiTagRuleDetails?.[a.id] || {}
        const db = aiTagRuleDetails?.[b.id] || {}
        return (da.rule_name || '').localeCompare(db.rule_name || '')
      })
    const examplesForRule = (ruleId) => (aiTagRuleDetails?.[ruleId]?.examples || [])
    const exclusivityForTag = (tagId) => (tagExclusivityRules || [])
      .filter((rule) => rule.tag_id === tagId && rule.is_active !== false)
      .flatMap((rule) => rule.incompatible_tag_ids || [])
      .map((tagId) => tagFullName(tagId) || tagId)
      .filter(Boolean)

    const rows = sortedTags.map((tag) => {
      const path = tagFullName(tag.id) || tag.name || tag.id
      const rules = rulesForTag(tag.id)
      const incompatible = exclusivityForTag(tag.id)
      const ruleHtml = rules.length ? rules.map((rule) => {
        const detail = aiTagRuleDetails?.[rule.id] || {}
        const examples = examplesForRule(rule.id)
        return `
          <div class="rule">
            <div class="rule-title">${escapeHtmlForRulesReport(detail.rule_name || 'Recognition rule')} <span>(${escapeHtmlForRulesReport(triggerTypeLabel(detail.rule_type || 'positive'))})</span></div>
            <div class="rule-text">${escapeHtmlForRulesReport(rule.rule_text || '').replace(/\n/g, '<br>')}</div>
            <div class="meta">Threshold: ${escapeHtmlForRulesReport(rule.confidence_threshold ?? 0.75)} | ${rule.is_active === false ? 'Inactive' : 'Active'} | Examples: ${examples.length}</div>
            ${examples.length ? `<ul>${examples.map((example) => `<li><strong>${escapeHtmlForRulesReport(example.example_type === 'negative' ? 'Does NOT demonstrate' : 'Demonstrates')}:</strong> ${escapeHtmlForRulesReport(example.file_name || 'Example document')} ${example.notes ? `— ${escapeHtmlForRulesReport(example.notes)}` : ''}</li>`).join('')}</ul>` : ''}
          </div>`
      }).join('') : '<p class="muted">No active recognition rules.</p>'
      return `
        <section class="tag-section">
          <h2>${escapeHtmlForRulesReport(path)}</h2>
          ${incompatible.length ? `<p><strong>Cannot be combined with:</strong> ${escapeHtmlForRulesReport(incompatible.join(', '))}</p>` : ''}
          ${ruleHtml}
        </section>`
    }).join('')

    const html = `<!doctype html>
      <html>
        <head>
          <title>Case Controller AI Document Rules</title>
          <style>
            body { font-family: Arial, sans-serif; margin: 28px; color: #1f2933; }
            h1 { text-align: center; margin-bottom: 4px; }
            .subtitle { text-align: center; color: #555; margin-bottom: 24px; }
            .tag-section { border-top: 1px solid #d0d7de; padding: 14px 0; break-inside: avoid; }
            h2 { font-size: 18px; margin: 0 0 8px; }
            .rule { border: 1px solid #e2e8f0; border-radius: 6px; padding: 10px; margin: 8px 0; background: #fbfdff; }
            .rule-title { font-weight: bold; margin-bottom: 6px; }
            .rule-title span { font-weight: normal; color: #475569; }
            .rule-text { white-space: normal; line-height: 1.35; }
            .meta, .muted { color: #64748b; font-size: 12px; }
            ul { margin-top: 6px; }
            @media print { button { display: none; } body { margin: 18px; } }
          </style>
        </head>
        <body>
          <button onclick="window.print()" style="float:right">Print / Save as PDF</button>
          <h1>Case Controller AI Document Rules</h1>
          <div class="subtitle">Generated ${escapeHtmlForRulesReport(new Date().toLocaleString())}</div>
          ${rows || '<p>No tags found.</p>'}
        </body>
      </html>`

    const win = window.open('', '_blank')
    if (!win) {
      alert('Please allow popups to open the AI rules PDF report.')
      return
    }
    win.document.open()
    win.document.write(html)
    win.document.close()
    setTimeout(() => win.print(), 250)
  }

  function renderAiDocumentSettings() {
    const fieldsByTagId = new Map()
    documentFieldTagRules.forEach((rule) => {
      const field = documentFieldDefinitions.find((item) => item.id === rule.field_definition_id)
      if (!field) return
      const list = fieldsByTagId.get(rule.tag_id) || []
      list.push({ rule, field })
      fieldsByTagId.set(rule.tag_id, list)
    })

    const rulesByTagId = new Map()
    aiTagRules.forEach((rule) => {
      const list = rulesByTagId.get(rule.tag_id) || []
      list.push(rule)
      rulesByTagId.set(rule.tag_id, list)
    })

    const allUsedFieldIds = new Set(documentFieldDefinitions.map((field) => field.id))
    const fieldTypeLabel = (type) => ({
      date: 'Date box',
      time: 'Time box',
      text: 'Text box',
      long_text: 'Long text box',
      number: 'Number box',
      money: 'Money box'
    }[type] || type || 'Text box')


    function AiInstructionTextarea({ value, onValueChange, rows = 4, placeholder = '' }) {
      const textareaRef = useRef(null)
      const insertAtCursor = (token) => {
        if (!token) return
        const textarea = textareaRef.current
        const currentValue = value || ''
        if (!textarea) {
          onValueChange(`${currentValue}${currentValue ? ' ' : ''}${token}`)
          return
        }
        const start = textarea.selectionStart ?? currentValue.length
        const end = textarea.selectionEnd ?? currentValue.length
        const spacerBefore = start > 0 && currentValue[start - 1] && !/\s/.test(currentValue[start - 1]) ? ' ' : ''
        const spacerAfter = currentValue[end] && !/\s/.test(currentValue[end]) ? ' ' : ''
        const nextValue = `${currentValue.slice(0, start)}${spacerBefore}${token}${spacerAfter}${currentValue.slice(end)}`
        onValueChange(nextValue)
        setTimeout(() => {
          const cursor = start + spacerBefore.length + token.length + spacerAfter.length
          textarea.focus()
          textarea.setSelectionRange(cursor, cursor)
        }, 0)
      }

      const pageRefs = builtInPageFieldReferences
      const userRefs = userFieldReferenceList()

      return (
        <div style={{ display: 'grid', gap: 6 }}>
          <textarea
            ref={textareaRef}
            value={value || ''}
            onChange={(e) => onValueChange(e.target.value)}
            rows={rows}
            placeholder={placeholder}
            style={{ width: '100%' }}
          />
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
            <select defaultValue="" onChange={(e) => { insertAtCursor(e.target.value); e.target.value = '' }}>
              <option value="">Insert page field...</option>
              {pageRefs.map((field) => <option key={field.token} value={field.token}>{field.label}</option>)}
            </select>
            <select defaultValue="" onChange={(e) => { insertAtCursor(e.target.value); e.target.value = '' }}>
              <option value="">Insert user field...</option>
              {userRefs.map((field) => <option key={field.token} value={field.token}>{field.label}</option>)}
            </select>
            <small style={{ color: '#64748b' }}>Place your cursor in the text box, then insert a field reference.</small>
          </div>
        </div>
      )
    }

    function renderFieldEditor(tag) {
      const isEditing = Boolean(editingDocumentFieldRuleId)
      return (
        <form onSubmit={saveTaggedDocumentField} style={{ marginTop: 10, border: '1px solid #d5e1ea', borderRadius: 8, padding: 12, background: '#f8fbff', display: 'grid', gap: 10 }}>
          <h4 style={{ margin: 0 }}>{isEditing ? 'Edit field' : 'Add field'} for {tagFullName(tag.id)}</h4>

          {!isEditing && (
            <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
              <label>
                <input
                  type="radio"
                  checked={taggedFieldMode === 'new'}
                  onChange={() => {
                    setTaggedFieldMode('new')
                    setTaggedFieldExistingFieldId('')
                  }}
                />{' '}
                Create new field
              </label>
              <label>
                <input
                  type="radio"
                  checked={taggedFieldMode === 'existing'}
                  onChange={() => {
                    setTaggedFieldMode('existing')
                    setDocumentFieldForm(emptyDocumentFieldForm)
                    const firstReusableField = reusableFieldOptions()[0]
                    const initialFieldId = taggedFieldExistingFieldId || firstReusableField?.option_id || ''
                    setTaggedFieldExistingFieldId(initialFieldId)
                    setDocumentFieldRuleForm((current) => ({
                      ...current,
                      field_definition_id: initialFieldId,
                      extraction_instructions: defaultExtractionInstructionsForField(initialFieldId, tag.id)
                    }))
                  }}
                />{' '}
                Reuse existing field
              </label>
            </div>
          )}

          {!isEditing && taggedFieldMode === 'existing' && (
            <LabeledField label="Existing field">
              <select
                value={taggedFieldExistingFieldId}
                onChange={(e) => {
                  const fieldId = e.target.value
                  setTaggedFieldExistingFieldId(fieldId)
                  setDocumentFieldRuleForm((current) => ({
                    ...current,
                    field_definition_id: fieldId,
                    extraction_instructions: defaultExtractionInstructionsForField(fieldId, tag.id)
                  }))
                }}
              >
                <option value="">Select existing field</option>
                <optgroup label="User fields">
                  {documentFieldDefinitions.map((field) => (
                    <option key={field.id} value={field.id}>{field.label} ({fieldTypeLabel(field.field_type)})</option>
                  ))}
                </optgroup>
                {calculatedUserFields.filter((field) => field.is_active !== false).length > 0 && (
                  <optgroup label="Calculated fields">
                    {calculatedUserFields.filter((field) => field.is_active !== false).map((field) => (
                      <option key={`calc:${field.id}`} value={`calc:${field.id}`}>{calculatedFieldDisplayLabel(field)}</option>
                    ))}
                  </optgroup>
                )}
              </select>
            </LabeledField>
          )}

          {(isEditing || taggedFieldMode === 'new') && (
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'end' }}>
              <LabeledField label="Field name">
                <input
                  value={documentFieldForm.label}
                  onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, label: e.target.value })}
                  placeholder="Example: Setting Date"
                />
              </LabeledField>

              <LabeledField label="Field type">
                <select
                  value={documentFieldForm.field_type}
                  onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, field_type: e.target.value })}
                >
                  <option value="date">Date box</option>
                  <option value="time">Time box</option>
                  <option value="text">Text box</option>
                  <option value="long_text">Long text box</option>
                  <option value="number">Number box</option>
                  <option value="money">Money box</option>
                </select>
              </LabeledField>

              <label style={{ display: 'inline-flex', alignItems: 'center', gap: 5, marginBottom: 4 }}>
                <input
                  type="checkbox"
                  checked={documentFieldForm.is_active}
                  onChange={(e) => setDocumentFieldForm({ ...documentFieldForm, is_active: e.target.checked })}
                />
                Active
              </label>
            </div>
          )}

          <LabeledField label="AI instructions for this field">
            <FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()}
              value={documentFieldRuleForm.extraction_instructions}
              onValueChange={(value) => setDocumentFieldRuleForm({ ...documentFieldRuleForm, extraction_instructions: value })}
              rows={4}
              placeholder="Example: Find the hearing or setting date. Do not use the filing stamp date. Do not use the certificate of service date."
            />
          </LabeledField>

          <div style={{ fontSize: 12, color: '#64748b' }}>
            Fields are always saved as multiple-value capable, searchable, and will not automatically create timeline/calendar items yet.
          </div>

          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            <button type="submit">{isEditing ? 'Save Field Changes' : 'Add Field to Tag'}</button>
            <button type="button" onClick={cancelTaggedFieldForm}>Cancel</button>
          </div>
        </form>
      )
    }

    function renderEventRuleEditor(tag) {
      const savedRule = documentEventRules.find((rule) => rule.tag_id === tag.id)
      return (
        <div style={{ marginTop: 10, border: '1px solid #cfe3d1', borderRadius: 8, padding: 12, background: '#f6fff7' }}>
          <h4 style={{ marginTop: 0 }}>Create event from document: {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>Tell AI when this tagged document should create an event and how to fill the event fields. Later, the source document will be linked to the event so it can be opened from the event.</p>
          {savedRule && <div style={{ marginBottom: 10, padding: 8, border: '1px solid #d8ead9', borderRadius: 6, background: 'white' }}><strong>Saved event rule:</strong><div style={{ whiteSpace: 'pre-wrap' }}>{savedRule.should_create_event_instructions}</div><small>{savedRule.is_active === false ? 'Inactive' : 'Active'}</small></div>}
          <form onSubmit={saveDocumentEventRuleForCurrentTag} style={{ display: 'grid', gap: 10 }}>
            <LabeledField label="When should this tagged document become an event?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={3} value={documentEventRuleForm.should_create_event_instructions} onValueChange={(value) => setDocumentEventRuleForm({ ...documentEventRuleForm, should_create_event_instructions: value })} placeholder="Example: Create an event when this Notice sets a hearing, trial, conference, court proceeding, or deadline." /></LabeledField>
            <LabeledField label="How should AI identify the event title?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={2} value={documentEventRuleForm.event_title_instructions} onValueChange={(value) => setDocumentEventRuleForm({ ...documentEventRuleForm, event_title_instructions: value })} placeholder="Example: Use the title of the hearing or the motion being heard." /></LabeledField>
            <LabeledField label="How should AI identify the event date?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={2} value={documentEventRuleForm.event_date_instructions} onValueChange={(value) => setDocumentEventRuleForm({ ...documentEventRuleForm, event_date_instructions: value })} placeholder="Example: Use the hearing/setting date, not the filing stamp or certificate of service date." /></LabeledField>
            <LabeledField label="How should AI identify the event time?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={2} value={documentEventRuleForm.event_time_instructions} onValueChange={(value) => setDocumentEventRuleForm({ ...documentEventRuleForm, event_time_instructions: value })} placeholder="Example: Use the time stated near the setting date." /></LabeledField>
            <LabeledField label="How should AI identify the event description/details?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={2} value={documentEventRuleForm.event_description_instructions} onValueChange={(value) => setDocumentEventRuleForm({ ...documentEventRuleForm, event_description_instructions: value })} placeholder="Example: Summarize what is being heard and include court/location details if listed." /></LabeledField>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}><input type="checkbox" checked={documentEventRuleForm.is_active} onChange={(e) => setDocumentEventRuleForm({ ...documentEventRuleForm, is_active: e.target.checked })} /> Active</label>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}><button type="submit">Save Event Instructions</button>{savedRule && <button type="button" onClick={() => deleteDocumentEventRule(tag.id)}>Delete Event Instructions</button>}<button type="button" onClick={() => setAiDocumentTagAction({ tag_id: '', mode: '' })}>Cancel</button></div>
          </form>
        </div>
      )
    }

    function renderMetadataRuleEditor(tag) {
      const savedRule = tagMetadataRules[tag.id] || {}
      return (
        <div style={{ marginTop: 10, border: '1px solid #dccdf0', borderRadius: 8, padding: 12, background: '#fbf8ff' }}>
          <h4 style={{ marginTop: 0 }}>Specify document name and description for {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>Tell AI exactly how to fill the existing document Name and Description fields when this tag is selected. You may insert page fields or user fields into the instructions.</p>
          {(savedRule.name_instructions || savedRule.description_instructions) && <div style={{ marginBottom: 10, padding: 8, border: '1px solid #e6d8f5', borderRadius: 6, background: 'white' }}>{savedRule.name_instructions && <div><strong>Name:</strong> {savedRule.name_instructions}</div>}{savedRule.description_instructions && <div><strong>Description:</strong> {savedRule.description_instructions}</div>}</div>}
          <form onSubmit={saveTagMetadataRuleForCurrentTag} style={{ display: 'grid', gap: 10 }}>
            <LabeledField label="How should AI fill the document Name?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={3} value={tagMetadataRuleForm.name_instructions} onValueChange={(value) => setTagMetadataRuleForm({ ...tagMetadataRuleForm, name_instructions: value })} placeholder="Example: Use a short title like Notice of Hearing, Order on Motion to Compel, etc." /></LabeledField>
            <LabeledField label="How should AI fill the document Description?"><FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()} rows={3} value={tagMetadataRuleForm.description_instructions} onValueChange={(value) => setTagMetadataRuleForm({ ...tagMetadataRuleForm, description_instructions: value })} placeholder="Example: Briefly summarize what the document does and any relevant hearing/deadline information." /></LabeledField>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}><button type="submit">Save Name/Description Rules</button>{(savedRule.name_instructions || savedRule.description_instructions) && <button type="button" onClick={() => deleteTagMetadataRule(tag.id)}>Delete Rules</button>}<button type="button" onClick={() => setAiDocumentTagAction({ tag_id: '', mode: '' })}>Cancel</button></div>
          </form>
        </div>
      )
    }

    function renderExclusivityEditor(tag) {
      const existing = exclusivityRuleForTag(tag.id)
      const selectedIds = Array.isArray(tagExclusivityForm.incompatible_tag_ids) ? tagExclusivityForm.incompatible_tag_ids : []
      const allOtherTags = tags.filter((item) => item.id !== tag.id)
      return (
        <div style={{ marginTop: 10, border: '1px solid #f2c8c8', borderRadius: 8, padding: 12, background: '#fff5f5' }}>
          <h4 style={{ marginTop: 0 }}>Exclusivity rule for {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>
            Use this when this tag should not appear with certain other tags on the same document. Example: Filings &gt; Ours should be exclusive with Filings &gt; Opposing Party.
          </p>
          {existing && (existing.incompatible_tag_ids || []).length > 0 && (
            <div style={{ marginBottom: 10, padding: 8, border: '1px solid #ffd1d1', borderRadius: 6, background: 'white' }}>
              <strong>Currently cannot be combined with:</strong>{' '}
              {(existing.incompatible_tag_ids || []).map((id) => tagFullName(id)).join(', ')}
            </div>
          )}
          <form onSubmit={saveTagExclusivityRuleForCurrentTag} style={{ display: 'grid', gap: 10 }}>
            <div>
              <strong>Tags that cannot be applied with this tag:</strong>
              <div style={{ maxHeight: 220, overflow: 'auto', border: '1px solid #e2e8f0', borderRadius: 6, padding: 8, background: 'white', marginTop: 6 }}>
                {allOtherTags.map((item) => (
                  <label key={item.id} style={{ display: 'block', marginBottom: 4, paddingLeft: `${Math.max(0, tagDepth(item.id) * 14)}px` }}>
                    <input
                      type="checkbox"
                      checked={selectedIds.includes(item.id)}
                      onChange={() => toggleTagExclusivitySelection(item.id)}
                    />{' '}
                    {tagFullName(item.id)}
                  </label>
                ))}
              </div>
            </div>
            <LabeledField label="Optional instructions for AI">
              <FieldReferenceTextarea
                pageRefs={pageFieldReferenceList()}
                userRefs={userFieldReferenceList()}
                rows={3}
                value={tagExclusivityForm.instructions || ''}
                onValueChange={(value) => setTagExclusivityForm({ ...tagExclusivityForm, instructions: value })}
                placeholder="Example: If both seem possible, decide by the signature block. If still unsure, do not apply either source tag and add a warning."
              />
            </LabeledField>
            <label style={{ display: 'inline-flex', alignItems: 'center', gap: 5 }}>
              <input type="checkbox" checked={tagExclusivityForm.is_active !== false} onChange={(e) => setTagExclusivityForm({ ...tagExclusivityForm, is_active: e.target.checked })} /> Active
            </label>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
              <button type="submit">Save Exclusivity Rule</button>
              {existing && <button type="button" onClick={() => deleteTagExclusivityRule(tag.id)}>Delete Rule</button>}
              <button type="button" onClick={() => setAiDocumentTagAction({ tag_id: '', mode: '' })}>Cancel</button>
            </div>
          </form>
        </div>
      )
    }

    function tagTrainingExamplesForTag(tagId) {
      return tagTrainingExamples.filter((example) => example.tag_id === tagId && example.is_active !== false)
    }

    function tagFeedbackStats(tagId) {
      const tagPath = tagFullName(tagId)
      const relevant = aiFeedbackRecords.filter((record) => (record.ai_tag_paths || []).includes(tagPath) || (record.final_tag_paths || []).includes(tagPath))
      const correct = relevant.filter((record) => record.outcome === 'correct').length
      const incorrect = relevant.filter((record) => record.outcome === 'incorrect').length
      const partial = relevant.filter((record) => record.outcome === 'partial').length
      const total = correct + incorrect + partial
      return { correct, incorrect, partial, total, accuracy: total ? Math.round(((correct + partial * 0.5) / total) * 100) : null }
    }

    function activeTrainingExamplesForAi() {
      const examplesFromRules = tagTrainingExamples
        .filter((example) => example.is_active !== false)
        .map((example) => ({
          tag_id: example.tag_id,
          tag_path: tagFullName(example.tag_id),
          example_type: example.example_type,
          file_name: example.file_name || '',
          notes: example.notes || '',
          source: example.source || 'tag_example'
        }))
      aiTagRules.forEach((rule) => {
        const detail = aiTagRuleDetails[rule.id] || {}
        ;(detail.examples || []).forEach((example) => {
          examplesFromRules.push({
            tag_id: rule.tag_id,
            tag_path: tagFullName(rule.tag_id),
            rule_id: rule.id,
            rule_name: detail.rule_name || '',
            rule_type: detail.rule_type || 'positive',
            example_type: example.example_type,
            file_name: example.file_name || '',
            notes: example.notes || ''
          })
        })
      })
      return examplesFromRules
    }

    function recentAiFeedbackForAi() {
      return aiFeedbackRecords
        .slice(-30)
        .map((record) => ({
          outcome: record.outcome,
          document_name: record.document_name || '',
          ai_tag_paths: record.ai_tag_paths || [],
          final_tag_paths: record.final_tag_paths || [],
          feedback: record.feedback || ''
        }))
    }

    function openTrainingExamplesForTag(tagId) {
      setTagTrainingExampleForm({ tag_id: tagId, example_type: 'positive', file_name: '', notes: '', is_active: true })
      setAiDocumentTagAction({ tag_id: tagId, mode: 'training' })
      if (!expandedAiDocumentTagIds.includes(tagId)) setExpandedAiDocumentTagIds((current) => [...current, tagId])
    }

    function saveTrainingExampleForCurrentTag(e) {
      e.preventDefault()
      if (!tagTrainingExampleForm.tag_id) return
      if (!tagTrainingExampleForm.file_name && !tagTrainingExampleForm.notes.trim()) {
        alert('Add a file name or notes for the training example.')
        return
      }
      const record = {
        id: `training-${Date.now()}-${Math.random().toString(36).slice(2)}`,
        tag_id: tagTrainingExampleForm.tag_id,
        example_type: tagTrainingExampleForm.example_type || 'positive',
        file_name: tagTrainingExampleForm.file_name || '',
        notes: tagTrainingExampleForm.notes || '',
        is_active: tagTrainingExampleForm.is_active !== false,
        created_at: new Date().toISOString()
      }
      setTagTrainingExamples((current) => [record, ...current])
      setTagTrainingExampleForm({ tag_id: record.tag_id, example_type: 'positive', file_name: '', notes: '', is_active: true })
    }

    function deleteTrainingExample(exampleId) {
      if (!confirm('Delete this training example?')) return
      setTagTrainingExamples((current) => current.filter((example) => example.id !== exampleId))
    }


    function tagTriggerComponentsForTag(tagId) {
      return tagTriggerComponents.filter((component) => component.tag_id === tagId && component.is_active !== false)
    }

    function activeTagTriggerComponentsForAi() {
      return aiTagRules
        .filter((rule) => rule.is_active !== false)
        .map((rule) => {
          const detail = aiTagRuleDetails[rule.id] || {}
          return {
            id: rule.id,
            tag_id: rule.tag_id,
            tag_path: tagFullName(rule.tag_id),
            name: detail.rule_name || 'Recognition rule',
            trigger_type: detail.rule_type || 'positive',
            instructions: rule.rule_text || '',
            examples: detail.examples || []
          }
        })
    }

    function openTriggerComponentsForTag(tagId) {
      setTagTriggerComponentForm({ id: '', tag_id: tagId, name: '', trigger_type: 'positive', instructions: '', is_active: true })
      setAiDocumentTagAction({ tag_id: tagId, mode: 'triggers' })
      if (!expandedAiDocumentTagIds.includes(tagId)) setExpandedAiDocumentTagIds((current) => [...current, tagId])
    }

    function editTagTriggerComponent(component) {
      setTagTriggerComponentForm({
        id: component.id,
        tag_id: component.tag_id,
        name: component.name || '',
        trigger_type: component.trigger_type || 'positive',
        instructions: component.instructions || '',
        is_active: component.is_active !== false
      })
      setAiDocumentTagAction({ tag_id: component.tag_id, mode: 'triggers' })
      if (!expandedAiDocumentTagIds.includes(component.tag_id)) setExpandedAiDocumentTagIds((current) => [...current, component.tag_id])
    }

    function saveTagTriggerComponent(e) {
      e.preventDefault()
      if (!tagTriggerComponentForm.tag_id) return
      if (!tagTriggerComponentForm.name.trim() || !tagTriggerComponentForm.instructions.trim()) {
        alert('Add a trigger name and instructions.')
        return
      }
      const record = {
        ...tagTriggerComponentForm,
        id: tagTriggerComponentForm.id || `trigger-${Date.now()}-${Math.random().toString(36).slice(2)}`,
        name: tagTriggerComponentForm.name.trim(),
        instructions: tagTriggerComponentForm.instructions.trim(),
        trigger_type: tagTriggerComponentForm.trigger_type || 'positive',
        is_active: tagTriggerComponentForm.is_active !== false,
        updated_at: new Date().toISOString()
      }
      setTagTriggerComponents((current) => {
        const exists = current.some((item) => item.id === record.id)
        return exists ? current.map((item) => item.id === record.id ? record : item) : [record, ...current]
      })
      setTagTriggerComponentForm({ id: '', tag_id: record.tag_id, name: '', trigger_type: 'positive', instructions: '', is_active: true })
    }

    function deleteTagTriggerComponent(componentId) {
      if (!confirm('Delete this trigger component?')) return
      setTagTriggerComponents((current) => current.filter((item) => item.id !== componentId))
    }

    function triggerTypeLabel(type) {
      const labels = {
        positive: 'Positive trigger',
        required: 'Required trigger',
        exclusion: 'Exclusion trigger',
        context: 'Context trigger'
      }
      return labels[type] || 'Positive trigger'
    }

    function renderTriggerComponentsEditor(tag) {
      const components = tagTriggerComponentsForTag(tag.id)
      return (
        <div style={{ marginTop: 10, border: '1px solid #d5e1ea', borderRadius: 8, padding: 12, background: '#f6f0ff' }}>
          <h4 style={{ marginTop: 0 }}>Structured trigger components for {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>
            Break one long rule into smaller parts so the AI can report exactly what triggered, what did not trigger, and what exclusions it considered.
          </p>
          <form onSubmit={saveTagTriggerComponent} style={{ display: 'grid', gap: 8 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 220px', gap: 8 }}>
              <LabeledField label="Trigger name">
                <input value={tagTriggerComponentForm.name} onChange={(event) => setTagTriggerComponentForm({ ...tagTriggerComponentForm, name: event.target.value })} placeholder="Example: Title says Order or Decree" />
              </LabeledField>
              <LabeledField label="Trigger type">
                <select value={tagTriggerComponentForm.trigger_type} onChange={(event) => setTagTriggerComponentForm({ ...tagTriggerComponentForm, trigger_type: event.target.value })}>
                  <option value="positive">Positive trigger</option>
                  <option value="required">Required trigger</option>
                  <option value="exclusion">Exclusion trigger</option>
                  <option value="context">Context trigger</option>
                </select>
              </LabeledField>
            </div>
            <LabeledField label="Instructions for this trigger component">
              <FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()}
                value={tagTriggerComponentForm.instructions}
                onValueChange={(value) => setTagTriggerComponentForm({ ...tagTriggerComponentForm, instructions: value })}
                rows={4}
                placeholder="Example: Trigger if the title below the case caption contains Order, Orders, Decree, Order to Appear, or Order Setting Hearing."
              />
            </LabeledField>
            <label style={{ display: 'inline-flex', gap: 6, alignItems: 'center' }}><input type="checkbox" checked={tagTriggerComponentForm.is_active !== false} onChange={(event) => setTagTriggerComponentForm({ ...tagTriggerComponentForm, is_active: event.target.checked })} /> Active</label>
            <div style={{ display: 'flex', gap: 8 }}>
              <button type="submit">{tagTriggerComponentForm.id ? 'Save Trigger Component' : 'Add Trigger Component'}</button>
              <button type="button" onClick={() => setTagTriggerComponentForm({ id: '', tag_id: tag.id, name: '', trigger_type: 'positive', instructions: '', is_active: true })}>Clear</button>
              <button type="button" onClick={() => setAiDocumentTagAction({ tag_id: '', mode: '' })}>Close</button>
            </div>
          </form>
          <h5>Saved trigger components</h5>
          {components.length === 0 && <p style={{ color: '#666' }}>No structured trigger components for this tag yet.</p>}
          {components.map((component) => (
            <div key={component.id} style={{ borderTop: '1px solid #d7c8f7', padding: '8px 0' }}>
              <strong>{component.name}</strong> — {triggerTypeLabel(component.trigger_type)} {component.is_active === false ? '(inactive)' : ''}
              <div style={{ whiteSpace: 'pre-wrap', marginTop: 4 }}>{component.instructions}</div>
              <div style={{ marginTop: 6, display: 'flex', gap: 6 }}>
                <button type="button" onClick={() => editTagTriggerComponent(component)}>Edit</button>
                <button type="button" onClick={() => deleteTagTriggerComponent(component.id)}>Delete</button>
              </div>
            </div>
          ))}
        </div>
      )
    }

    function renderTrainingExamplesEditor(tag) {
      const examples = tagTrainingExamplesForTag(tag.id)
      const stats = tagFeedbackStats(tag.id)
      return (
        <div style={{ marginTop: 10, border: '1px solid #d5e1ea', borderRadius: 8, padding: 12, background: '#f7fff8' }}>
          <h4 style={{ marginTop: 0 }}>Examples and accuracy for {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>Add examples that should or should not trigger this tag. These examples are sent to AI with the rules.</p>
          <div style={{ display: 'flex', gap: 0, marginBottom: 10 }}>
            <button type="button" onClick={() => setTagExamplesView('positive')} style={{ padding: '6px 10px', background: tagExamplesView === 'positive' ? '#2f6584' : 'white', color: tagExamplesView === 'positive' ? 'white' : '#1f2d3d', border: '1px solid #c8d0d8' }}>Inclusion examples</button>
            <button type="button" onClick={() => setTagExamplesView('negative')} style={{ padding: '6px 10px', background: tagExamplesView === 'negative' ? '#2f6584' : 'white', color: tagExamplesView === 'negative' ? 'white' : '#1f2d3d', border: '1px solid #c8d0d8', borderLeft: 0 }}>Exclusion examples</button>
          </div>
          <div style={{ marginBottom: 10 }}>
            <strong>Feedback stats:</strong>{' '}
            {stats.total ? `${stats.accuracy}% adjusted accuracy (${stats.correct} correct, ${stats.partial} partial, ${stats.incorrect} wrong)` : 'No reviewed examples yet.'}
          </div>
          <form onSubmit={saveTrainingExampleForCurrentTag} style={{ display: 'grid', gap: 8 }}>
            <div style={{ display: 'flex', gap: 10, alignItems: 'center', flexWrap: 'wrap' }}>
              <label><input type="radio" checked={tagTrainingExampleForm.example_type === 'positive'} onChange={() => setTagTrainingExampleForm({ ...tagTrainingExampleForm, example_type: 'positive' })} /> Should trigger this tag</label>
              <label><input type="radio" checked={tagTrainingExampleForm.example_type === 'negative'} onChange={() => setTagTrainingExampleForm({ ...tagTrainingExampleForm, example_type: 'negative' })} /> Should NOT trigger this tag</label>
              <input
                type="file"
                onChange={(event) => setTagTrainingExampleForm({ ...tagTrainingExampleForm, file_name: event.target.files?.[0]?.name || '' })}
              />
              {tagTrainingExampleForm.file_name && <small>Selected: {tagTrainingExampleForm.file_name}</small>}
            </div>
            <textarea
              rows={3}
              value={tagTrainingExampleForm.notes}
              onChange={(event) => setTagTrainingExampleForm({ ...tagTrainingExampleForm, notes: event.target.value })}
              placeholder="Explain why this example should or should not trigger the tag. Example: This is an Order to Appear drafted by our firm, so it should be Filings > Ours > Orders."
            />
            <label style={{ display: 'inline-flex', gap: 6, alignItems: 'center' }}><input type="checkbox" checked={tagTrainingExampleForm.is_active !== false} onChange={(event) => setTagTrainingExampleForm({ ...tagTrainingExampleForm, is_active: event.target.checked })} /> Active</label>
            <div style={{ display: 'flex', gap: 8 }}>
              <button type="submit">Add Example</button>
              <button type="button" onClick={() => setAiDocumentTagAction({ tag_id: '', mode: '' })}>Close</button>
            </div>
          </form>
          <h5>Saved examples</h5>
          {examples.filter((example) => (example.example_type || 'positive') === tagExamplesView).length === 0 && <p style={{ color: '#666' }}>No {tagExamplesView === 'negative' ? 'exclusion' : 'inclusion'} examples for this tag yet.</p>}
          {examples.filter((example) => (example.example_type || 'positive') === tagExamplesView).map((example) => (
            <div key={example.id} style={{ borderTop: '1px solid #cde8d2', padding: '8px 0' }}>
              <strong>{example.example_type === 'negative' ? 'Should NOT trigger' : 'Should trigger'}</strong>
              {example.file_name && <> — {example.file_name}</>}
              {example.notes && <div style={{ whiteSpace: 'pre-wrap', marginTop: 4 }}>{example.notes}</div>}
              {example.document_excerpt && <details style={{ marginTop: 4 }}><summary>Document text used by AI</summary><div style={{ whiteSpace: 'pre-wrap', maxHeight: 180, overflow: 'auto', background: '#f8fafc', border: '1px solid #e2e8f0', padding: 6 }}>{example.document_excerpt}</div></details>}
              <small>{example.is_active === false ? 'Inactive' : 'Active'} | {example.created_at ? new Date(example.created_at).toLocaleString() : ''}</small>
              <div><button type="button" onClick={() => deleteTrainingExample(example.id)}>Delete</button></div>
            </div>
          ))}
        </div>
      )
    }

    function renderTagRulesEditor(tag) {
      const rulesForTag = rulesByTagId.get(tag.id) || []
      return (
        <div style={{ marginTop: 10, border: '1px solid #d5e1ea', borderRadius: 8, padding: 12, background: '#fffaf0' }}>
          <h4 style={{ marginTop: 0 }}>Tag recognition rules for {tagFullName(tag.id)}</h4>
          <p style={{ marginTop: 0, color: '#555' }}>
            These rules tell the AI when this tag should be applied. Use rule types to separate inclusion, required, exclusion, and context rules. You can attach example documents to each individual rule after saving it.
          </p>

          <form onSubmit={saveTagRecognitionRuleForCurrentTag} style={{ display: 'grid', gap: 10 }}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 220px', gap: 8 }}>
              <LabeledField label="Rule name">
                <input value={aiTagRuleForm.rule_name || ''} onChange={(event) => setAiTagRuleForm({ ...aiTagRuleForm, rule_name: event.target.value })} placeholder="Example: Title says Order or Decree" />
              </LabeledField>
              <LabeledField label="Rule type">
                <select value={aiTagRuleForm.rule_type || 'positive'} onChange={(event) => setAiTagRuleForm({ ...aiTagRuleForm, rule_type: event.target.value })}>
                  <option value="positive">Positive / inclusion rule</option>
                  <option value="required">Required rule</option>
                  <option value="exclusion">Exclusion rule</option>
                  <option value="context">Context rule</option>
                </select>
              </LabeledField>
            </div>
            <LabeledField label="Rule instructions">
              <FieldReferenceTextarea pageRefs={pageFieldReferenceList()} userRefs={userFieldReferenceList()}
                value={aiTagRuleForm.rule_text}
                onValueChange={(value) => setAiTagRuleForm({ ...aiTagRuleForm, rule_text: value })}
                rows={4}
                placeholder="Example: Apply Notices if the title says Notice of Hearing or Notice of Court Proceeding, or if the document gives notice that something is set for a date/time."
              />
            </LabeledField>
            <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'end' }}>
              <LabeledField label="Confidence threshold">
                <input
                  type="number"
                  min="0"
                  max="1"
                  step="0.05"
                  value={aiTagRuleForm.confidence_threshold}
                  onChange={(e) => setAiTagRuleForm({ ...aiTagRuleForm, confidence_threshold: e.target.value })}
                />
              </LabeledField>
              <label style={{ display: 'inline-flex', alignItems: 'center', gap: 5, marginBottom: 4 }}>
                <input
                  type="checkbox"
                  checked={aiTagRuleForm.is_active}
                  onChange={(e) => setAiTagRuleForm({ ...aiTagRuleForm, is_active: e.target.checked })}
                />
                Active
              </label>
            </div>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
              <button type="submit">{editingAiTagRuleId ? 'Save Rule Changes' : 'Add Tag Recognition Rule'}</button>
              <button
                type="button"
                onClick={() => {
                  setAiTagRuleForm({ ...emptyAiTagRuleForm, tag_id: tag.id })
                  setEditingAiTagRuleId(null)
                }}
              >
                Clear
              </button>
            </div>
          </form>

          {editingAiTagRuleId && (
            <form onSubmit={addExampleToEditingRule} style={{ marginTop: 12, padding: 10, border: '1px solid #eadfca', borderRadius: 8, background: '#fff' }}>
              <h5 style={{ marginTop: 0 }}>Example documents for this rule</h5>
              <p style={{ marginTop: 0, color: '#555' }}>Attach examples to this specific rule, not the whole tag, so the AI knows what each rule is supposed to catch or exclude.</p>
              <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap', alignItems: 'center' }}>
                <label><input type="radio" checked={aiTagRuleForm.example_type === 'positive'} onChange={() => setAiTagRuleForm({ ...aiTagRuleForm, example_type: 'positive' })} /> Demonstrates this rule</label>
                <label><input type="radio" checked={aiTagRuleForm.example_type === 'negative'} onChange={() => setAiTagRuleForm({ ...aiTagRuleForm, example_type: 'negative' })} /> Does NOT demonstrate this rule</label>
                <input type="file" onChange={(event) => setAiTagRuleForm({ ...aiTagRuleForm, example_file_name: event.target.files?.[0]?.name || '' })} />
                {aiTagRuleForm.example_file_name && <small>Selected: {aiTagRuleForm.example_file_name}</small>}
              </div>
              <textarea rows={3} value={aiTagRuleForm.example_notes || ''} onChange={(event) => setAiTagRuleForm({ ...aiTagRuleForm, example_notes: event.target.value })} placeholder="Explain why this document does or does not demonstrate this exact rule." style={{ width: '100%', marginTop: 8 }} />
              <button type="submit" style={{ marginTop: 6 }}>Add Example to Rule</button>
              {(aiTagRuleDetails[editingAiTagRuleId]?.examples || []).length > 0 && (
                <div style={{ marginTop: 10 }}>
                  {(aiTagRuleDetails[editingAiTagRuleId]?.examples || []).map((example) => (
                    <div key={example.id} style={{ borderTop: '1px solid #eee', padding: '6px 0' }}>
                      <strong>{example.example_type === 'negative' ? 'Does NOT demonstrate' : 'Demonstrates'}</strong>{example.file_name ? ` — ${example.file_name}` : ''}
                      {example.notes && <div style={{ whiteSpace: 'pre-wrap' }}>{example.notes}</div>}
                      <button type="button" onClick={() => deleteRuleExample(editingAiTagRuleId, example.id)}>Delete example</button>
                    </div>
                  ))}
                </div>
              )}
            </form>
          )}

          <h5>Saved recognition rules</h5>
          {rulesForTag.length === 0 && <p style={{ color: '#666' }}>No recognition rules for this tag yet.</p>}
          {rulesForTag.map((rule) => {
            const detail = aiTagRuleDetails[rule.id] || {}
            const examples = detail.examples || []
            return (
              <div key={rule.id} style={{ borderTop: '1px solid #eadfca', padding: '8px 0' }}>
                <div><strong>{detail.rule_name || 'Recognition rule'}</strong> — {triggerTypeLabel(detail.rule_type || 'positive')}</div>
                <div style={{ whiteSpace: 'pre-wrap', marginTop: 4 }}>{rule.rule_text}</div>
                <small>
                  Threshold: {rule.confidence_threshold ?? 0.75} | {rule.is_active === false ? 'Inactive' : 'Active'} | Examples: {examples.length}
                </small>

                <div style={{ marginTop: 8, padding: 8, border: '1px solid #eee', borderRadius: 6, background: '#fff' }}>
                  <strong>Add example document for this rule</strong>
                  <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap', marginTop: 6 }}>
                    <select
                      value={(ruleExampleForms[rule.id]?.example_type) || 'positive'}
                      onChange={(event) => updateRuleExampleForm(rule.id, { example_type: event.target.value })}
                    >
                      <option value="positive">Demonstrates this rule</option>
                      <option value="negative">Does NOT demonstrate this rule</option>
                    </select>
                    <input
                      type="file"
                      onChange={(event) => updateRuleExampleForm(rule.id, { file_name: event.target.files?.[0]?.name || '' })}
                    />
                    {(ruleExampleForms[rule.id]?.file_name) && <small>Selected: {ruleExampleForms[rule.id].file_name}</small>}
                  </div>
                  <textarea
                    rows={2}
                    value={(ruleExampleForms[rule.id]?.notes) || ''}
                    onChange={(event) => updateRuleExampleForm(rule.id, { notes: event.target.value })}
                    placeholder="Explain why this document does or does not demonstrate this exact rule."
                    style={{ width: '100%', marginTop: 6 }}
                  />
                  <button type="button" onClick={() => addExampleToRule(rule.id)}>Add Example</button>
                </div>

                {examples.length > 0 && (
                  <details open style={{ marginTop: 5 }}>
                    <summary>Examples attached to this rule</summary>
                    {examples.map((example) => (
                      <div key={example.id} style={{ padding: '4px 0', borderTop: '1px solid #f1f1f1' }}>
                        <strong>{example.example_type === 'negative' ? 'Does NOT demonstrate' : 'Demonstrates'}</strong>{example.file_name ? ` — ${example.file_name}` : ''}
                        {example.notes && <div style={{ whiteSpace: 'pre-wrap' }}>{example.notes}</div>}
                        <button type="button" onClick={() => deleteRuleExample(rule.id, example.id)}>Delete example</button>
                      </div>
                    ))}
                  </details>
                )}
                <div style={{ display: 'flex', gap: 6, marginTop: 5 }}>
                  <button type="button" onClick={() => startEditAiTagRule(rule)}>Edit Rule</button>
                  <button type="button" onClick={() => deleteAiDocumentSetting('document_ai_tag_rules', rule.id)}>Delete Rule</button>
                </div>
              </div>
            )
          })}
        </div>
      )
    }

    function renderTagNode(tag, level = 0) {
      const children = childTags(tag.id)
      const fieldItems = (fieldsByTagId.get(tag.id) || []).sort((a, b) => String(a.field.label || '').localeCompare(String(b.field.label || '')))
      const recognitionRules = rulesByTagId.get(tag.id) || []
      const eventRule = documentEventRules.find((rule) => rule.tag_id === tag.id)
      const metadataRule = tagMetadataRules[tag.id] || {}
      const exclusivityRule = exclusivityRuleForTag(tag.id)
      const expanded = expandedAiDocumentTagIds.includes(tag.id)
      const isActiveFieldForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'field'
      const isActiveRulesForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'rules'
      const isActiveEventForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'event'
      const isActiveMetadataForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'metadata'
      const isActiveExclusivityForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'exclusivity'
      const isActiveTrainingForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'training'
      const isActiveTriggerForm = aiDocumentTagAction.tag_id === tag.id && aiDocumentTagAction.mode === 'triggers'
      const triggerComponents = tagTriggerComponentsForTag(tag.id)
      const trainingExamples = tagTrainingExamplesForTag(tag.id)
      const feedbackStats = tagFeedbackStats(tag.id)

      return (
        <Fragment key={tag.id}>
          <div style={{ marginLeft: level * 24, border: '1px solid #d5dce3', borderRadius: 8, background: 'white', marginBottom: 8 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: 10 }}>
              <button type="button" onClick={() => toggleAiDocumentTagExpanded(tag.id)} title={expanded ? 'Collapse' : 'Expand'}>
                {expanded ? '▾' : '▸'}
              </button>
              {tag.icon_data ? <img src={tag.icon_data} alt="" style={{ width: 22, height: 22, objectFit: 'cover' }} /> : <span style={{ width: 22 }}>🏷️</span>}
              <strong>{tag.name}</strong>
              <span style={{ fontSize: 12, color: '#64748b' }}>
                {fieldItems.length} field{fieldItems.length === 1 ? '' : 's'} | {recognitionRules.length} recognition rule{recognitionRules.length === 1 ? '' : 's'}{eventRule ? ' | event rule' : ''}{metadataRule.name_instructions || metadataRule.description_instructions ? ' | name/description rules' : ''}{exclusivityRule ? ' | exclusivity rule' : ''}{feedbackStats.total ? ` | ${feedbackStats.accuracy}% accuracy` : ''}
              </span>
              <span style={{ flex: 1 }} />
              <button type="button" onClick={() => openAddFieldForTag(tag.id)}>Add Field</button>
              <button type="button" onClick={() => openTagRulesForTag(tag.id)}>Tag Recognition Rules</button>
              <button type="button" onClick={() => openExclusivityForTag(tag.id)}>Apply Exclusivity Rule</button>
              <button type="button" onClick={() => openTrainingExamplesForTag(tag.id)}>Examples</button>
              <button type="button" onClick={() => openMetadataRulesForTag(tag.id)}>Specify Name</button>
              <button type="button" onClick={() => openMetadataRulesForTag(tag.id)}>Specify Description</button>
              <button type="button" onClick={() => openCreateEventForTag(tag.id)}>Create Event From Document</button>
            </div>

            {expanded && (
              <div style={{ borderTop: '1px solid #edf2f7', padding: 10 }}>
                {fieldItems.length === 0 && <p style={{ color: '#666', marginTop: 0 }}>No document fields attached to this tag yet.</p>}
                {fieldItems.length > 0 && (
                  <div style={{ display: 'grid', gap: 8 }}>
                    {fieldItems.map(({ rule, field }) => (
                      <details key={rule.id} style={{ border: '1px solid #e2e8f0', borderRadius: 8, padding: 8, background: '#f8fafc' }}>
                        <summary style={{ cursor: 'pointer' }}>
                          <strong>{field.label}</strong> — {fieldTypeLabel(field.field_type)} {field.is_active === false || rule.is_active === false ? '(inactive)' : ''}
                        </summary>
                        <div style={{ marginTop: 8 }}>
                          <div style={{ whiteSpace: 'pre-wrap' }}><strong>AI looks for:</strong> {rule.extraction_instructions || 'No instructions yet.'}</div>
                          <div style={{ marginTop: 8, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                            <button type="button" onClick={() => startEditTaggedField(rule, field)}>Edit</button>
                            <button type="button" onClick={() => deleteAiDocumentSetting('document_field_tag_rules', rule.id)}>Remove from this tag</button>
                            <button type="button" onClick={() => deleteDocumentFieldEverywhere(field.id)}>Delete field everywhere</button>
                          </div>
                        </div>
                      </details>
                    ))}
                  </div>
                )}

                {(metadataRule.name_instructions || metadataRule.description_instructions) && !isActiveMetadataForm && (
                  <details style={{ marginTop: 8, border: '1px solid #e2e8f0', borderRadius: 8, padding: 8, background: '#f8fafc' }}>
                    <summary style={{ cursor: 'pointer' }}><strong>Name / Description rules</strong></summary>
                    {metadataRule.name_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Name:</strong> {metadataRule.name_instructions}</div>}
                    {metadataRule.description_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Description:</strong> {metadataRule.description_instructions}</div>}
                    <button type="button" onClick={() => openMetadataRulesForTag(tag.id)} style={{ marginTop: 6 }}>Edit name/description rules</button>
                  </details>
                )}

                {eventRule && !isActiveEventForm && (
                  <details style={{ marginTop: 8, border: '1px solid #e2e8f0', borderRadius: 8, padding: 8, background: '#f8fafc' }}>
                    <summary style={{ cursor: 'pointer' }}><strong>Event creation rule</strong></summary>
                    <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Create when:</strong> {eventRule.should_create_event_instructions || 'No instructions yet.'}</div>
                    {eventRule.event_title_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Event title:</strong> {eventRule.event_title_instructions}</div>}
                    {eventRule.event_date_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Event date:</strong> {eventRule.event_date_instructions}</div>}
                    {eventRule.event_time_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Event time:</strong> {eventRule.event_time_instructions}</div>}
                    {eventRule.event_description_instructions && <div style={{ marginTop: 6, whiteSpace: 'pre-wrap' }}><strong>Event description:</strong> {eventRule.event_description_instructions}</div>}
                    <button type="button" onClick={() => openCreateEventForTag(tag.id)} style={{ marginTop: 6 }}>Edit event rule</button>
                  </details>
                )}

                {isActiveFieldForm && renderFieldEditor(tag)}
                {isActiveRulesForm && renderTagRulesEditor(tag)}
                {isActiveMetadataForm && renderMetadataRuleEditor(tag)}
                {isActiveExclusivityForm && renderExclusivityEditor(tag)}
                {isActiveTrainingForm && renderTrainingExamplesEditor(tag)}
                {isActiveEventForm && renderEventRuleEditor(tag)}
              </div>
            )}
          </div>
          {children.map((child) => renderTagNode(child, level + 1))}
        </Fragment>
      )
    }

    const rootTags = childTags('')

    return (
      <>
        <h2>AI Documents</h2>
        <p>
          Attach document fields and recognition rules directly to tags. When AI later recognizes a tag on an uploaded document, the fields under that tag will appear on the document and AI will try to fill them in. You can edit the fields before saving.
        </p>
        <p style={{ color: '#555' }}>
          Use <strong>Apply Exclusivity Rule</strong> when one tag should not be combined with another tag on the same document, such as Filings &gt; Ours and Filings &gt; Opposing Party.
        </p>
        <div style={{ marginBottom: 12, display: 'flex', gap: 8, justifyContent: 'center', flexWrap: 'wrap' }}>
          <button type="button" onClick={() => setShowAiGuessReview(!showAiGuessReview)}>
            {showAiGuessReview ? 'Hide AI guess review' : 'Review AI guesses / accuracy'}
          </button>
          <button type="button" onClick={openAiRulesPdfReport}>Download / print AI rules PDF</button>
        </div>
        {showAiGuessReview && renderAiGuessReviewDashboard()}
        <section style={{ border: '1px solid #d5dce3', borderRadius: 8, padding: 14, background: '#f8fbff' }}>
          <h3>Tagged Document Fields and Recognition Rules</h3>
          {rootTags.length === 0 && <p>No tags exist yet. Create tags on the Tags page first.</p>}
          {rootTags.map((tag) => renderTagNode(tag, 0))}
        </section>
      </>
    )
  }



  function parseTimelineDate(value) {
    if (!value || isUndatedEventDate(value)) return null
    const date = new Date(`${value}T00:00:00`)
    if (Number.isNaN(date.getTime())) return null
    return date
  }

  function addTimelineDays(date, amount) {
    if (!date) return null
    const next = new Date(date)
    next.setDate(next.getDate() + Number(amount || 0))
    return next
  }

  function nthWeekdayOfMonth(year, monthIndex, weekday, n) {
    const date = new Date(year, monthIndex, 1)
    const offset = (weekday - date.getDay() + 7) % 7
    date.setDate(1 + offset + ((n - 1) * 7))
    return date
  }

  function lastWeekdayOfMonth(year, monthIndex, weekday) {
    const date = new Date(year, monthIndex + 1, 0)
    const offset = (date.getDay() - weekday + 7) % 7
    date.setDate(date.getDate() - offset)
    return date
  }

  function observedFixedHoliday(year, monthIndex, day) {
    const date = new Date(year, monthIndex, day)
    const observed = new Date(date)
    if (date.getDay() === 0) observed.setDate(date.getDate() + 1)
    if (date.getDay() === 6) observed.setDate(date.getDate() - 1)
    return observed
  }

  function courtHolidaySetForYear(year) {
    const dates = [
      observedFixedHoliday(year, 0, 1),
      nthWeekdayOfMonth(year, 0, 1, 3),
      nthWeekdayOfMonth(year, 1, 1, 3),
      lastWeekdayOfMonth(year, 4, 1),
      observedFixedHoliday(year, 5, 19),
      observedFixedHoliday(year, 6, 4),
      nthWeekdayOfMonth(year, 8, 1, 1),
      nthWeekdayOfMonth(year, 9, 1, 2),
      observedFixedHoliday(year, 10, 11),
      nthWeekdayOfMonth(year, 10, 4, 4),
      observedFixedHoliday(year, 11, 25)
    ]
    return new Set(dates.map(dateToInputValue))
  }

  function isWeekendOrHoliday(date) {
    if (!date) return false
    const day = date.getDay()
    if (day === 0 || day === 6) return true
    return courtHolidaySetForYear(date.getFullYear()).has(dateToInputValue(date))
  }

  function nextNonWeekendHolidayDate(date) {
    if (!date) return null
    const next = new Date(date)
    while (isWeekendOrHoliday(next)) next.setDate(next.getDate() + 1)
    return next
  }

  function shortTimelineDate(date) {
    if (!date) return ''
    return `${date.getMonth() + 1}/${date.getDate()}/${String(date.getFullYear()).slice(-2)}`
  }

  function daysBetweenTimelineDates(start, end) {
    return Math.max(1, Math.round((end - start) / 86400000))
  }

  function eventLooksLike(event, type) {
    const text = `${event.event_category || ''} ${event.event_subcategory || ''} ${event.title || ''} ${event.description || ''}`.toLowerCase()
    const tokens = type === 'trial'
      ? ['trial', 'final trial', 'bench trial', 'jury trial']
      : [type]
    return tokens.some((token) => text.includes(token))
  }

  function matterDisplayName(matter) {
    return matter.name || `${matter.clients?.last_name || ''}${matter.clients?.first_name ? ` (${matter.clients.first_name})` : ''}` || 'Unnamed matter'
  }

  function matterTimelineClientMatterLabel(matter) {
    const client = matterClientName(matter) || matter.matter_client_name || clientName(matter.client_id)
    const matterName = matterDisplayName(matter)
    if (client && matterName && client !== matterName) return `${client} - ${matterName}`
    return client || matterName || 'Unnamed matter'
  }

  const matterTimelineStickyClientMatterCellStyle = {
    position: 'sticky',
    left: 0,
    zIndex: 25,
    background: '#fff',
    boxShadow: '2px 0 4px rgba(15, 23, 42, 0.08)'
  }

  const matterTimelineStickyClientMatterHeaderStyle = {
    position: 'sticky',
    left: 0,
    zIndex: 40,
    background: '#f3f4f6',
    boxShadow: '2px 0 4px rgba(15, 23, 42, 0.08)'
  }

  function courtRuleForMatter(matter) {
    const key = matter.court_id || matter.courts?.id || ''
    return courtTimelineRules[key] || {}
  }

  function updateCourtTimelineRule(courtId, field, value) {
    setCourtTimelineRules((current) => ({
      ...current,
      [courtId]: {
        ...(current[courtId] || {}),
        [field]: value
      }
    }))
  }

  function normalizeDiscoveryTagPath(value = '') {
    return String(value || '')
      .toLowerCase()
      .replace(/&/g, ' and ')
      .replace(/[\'’]s\b/g, 's')
      .replace(/[^a-z0-9]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
  }

  function documentHasTimelineDiscoveryTag(doc, kind) {
    const normalizedPaths = (doc.tag_ids || []).map((tagId) => normalizeDiscoveryTagPath(tagFullName(tagId)))
    return normalizedPaths.some((path) => {
      if (kind === 'request') {
        return path === 'discovery our requests' ||
          path === 'discovery ours requests' ||
          path === 'discovery opposing party request' ||
          path === 'discovery opposing partys request' ||
          path === 'discovery opposing party requests' ||
          path === 'discovery opposing partys requests'
      }
      if (kind === 'response') {
        return path === 'discovery our responses' ||
          path === 'discovery ours responses' ||
          path === 'discovery opposing party responses' ||
          path === 'discovery opposing partys responses'
      }
      return false
    })
  }

  function timelineDocumentServiceDate(doc) {
    const values = doc.document_field_values || {}
    const fields = documentFieldsForTags(doc.tag_ids || [])
    const serviceField = serviceDateFieldForFields(fields)
    const candidates = []

    if (serviceField?.field_key) candidates.push(values[serviceField.field_key])
    Object.entries(values).forEach(([key, value]) => {
      const normalizedKey = String(key || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ')
      if (normalizedKey.includes('service') && normalizedKey.includes('date')) candidates.push(value)
    })

    for (const candidate of candidates) {
      const raw = Array.isArray(candidate) ? candidate.find(Boolean) : candidate
      const date = parseTimelineDate(raw) || parseDateInputValue(raw)
      if (date) return date
    }

    return null
  }

  function timelineAdjustmentKey(sourceType, sourceId, pointType) {
    return `${sourceType || 'timeline'}|||${sourceId || ''}|||${pointType || ''}`
  }

  function timelineAdjustedDate(sourceType, sourceId, pointType, fallbackDate) {
    const key = timelineAdjustmentKey(sourceType, sourceId, pointType)
    const adjusted = parseTimelineDate(matterTimelineDateAdjustments[key]) || parseDateInputValue(matterTimelineDateAdjustments[key])
    return adjusted || fallbackDate
  }

  function applyMatterTimelineAdjustmentToPoint(point) {
    if (!point?.sourceType || !point?.sourceId || !point?.type) return point
    const date = timelineAdjustedDate(point.sourceType, point.sourceId, point.type, point.date)
    return { ...point, date }
  }

  function applyMatterTimelineAdjustmentToSegment(segment) {
    const start = segment?.startSourceType && segment?.startSourceId && segment?.startPointType
      ? timelineAdjustedDate(segment.startSourceType, segment.startSourceId, segment.startPointType, segment.start)
      : segment.start
    const end = segment?.endSourceType && segment?.endSourceId && segment?.endPointType
      ? timelineAdjustedDate(segment.endSourceType, segment.endSourceId, segment.endPointType, segment.end)
      : segment.end
    return { ...segment, start, end }
  }

  function setMatterTimelineDateAdjustment(key, value) {
    setMatterTimelineDateAdjustments((current) => ({ ...current, [key]: value }))
  }

  function clearMatterTimelineDateAdjustment(key) {
    setMatterTimelineDateAdjustments((current) => {
      const next = { ...current }
      delete next[key]
      return next
    })
  }

  function assignMatterTimelinePointOffsets(points, segments, layoutMode = matterTimelineLayoutMode) {
    const grouped = new Map()
    points.forEach((point, index) => {
      const key = dateToInputValue(point.date)
      if (!key) return
      if (!grouped.has(key)) grouped.set(key, [])
      grouped.get(key).push({ point, index })
    })

    const offsets = [0, -11, 11, -19, 19, -27, 27]
    const nextPoints = points.map((point) => ({ ...point, yOffset: 0 }))
    if (layoutMode !== 'overlap') {
      grouped.forEach((items) => {
        if (items.length <= 1) return
        items.forEach((item, stackIndex) => {
          nextPoints[item.index] = { ...nextPoints[item.index], yOffset: offsets[stackIndex % offsets.length] }
        })
      })
    }

    const offsetForPoint = (sourceType, sourceId, pointType) => {
      const match = nextPoints.find((point) => point.sourceType === sourceType && point.sourceId === sourceId && point.type === pointType)
      return match?.yOffset || 0
    }

    const nextSegments = segments.map((segment) => ({
      ...segment,
      yOffset: segment.type === 'discovery_request_window'
        ? offsetForPoint(segment.startSourceType, segment.startSourceId, segment.startPointType)
        : 0
    }))

    return { points: nextPoints, segments: nextSegments }
  }


  function matterTimelineCourtDeadlineRows() {
    // Court-table deadline markers should stay highly visible.  After a browser/localStorage
    // reset, older saved option maps could fall back to black outline circles; use solid red
    // as the recovery/default color so deadlines do not look like inactive outline markers.
    return [
      { type: 'court_deadline', key: 'court:trial_exhibits', label: 'Trial exhibits', defaultColor: '#dc2626' },
      { type: 'court_deadline', key: 'court:hearing_exhibits', label: 'Hearing exhibits', defaultColor: '#dc2626' },
      { type: 'court_deadline', key: 'court:discovery_period', label: 'Discovery period', defaultColor: '#dc2626' },
      { type: 'court_deadline', key: 'court:pleading_date', label: 'Pleading date', defaultColor: '#dc2626' }
    ]
  }

  function matterTimelineDiscoveryRows() {
    return [
      { type: 'discovery', key: 'discovery:trial', field: 'trial', label: 'Trial', defaultColor: '#7c3aed' },
      { type: 'discovery', key: 'discovery:thirtyBeforeTrial', field: 'thirtyBeforeTrial', label: '30 days before trial', defaultColor: '#7c3aed' },
      { type: 'discovery', key: 'discovery:request_served', field: 'request_served', label: 'Request served', defaultColor: '#7c3aed' },
      { type: 'discovery', key: 'discovery:sent_to_c', field: 'sent_to_c', label: 'Sent to C', defaultColor: '#7c3aed' },
      { type: 'discovery', key: 'discovery:response_due', field: 'response_due', label: 'Response due', defaultColor: '#7c3aed' },
      { type: 'discovery', key: 'discovery:mediation_document_exchange', field: 'mediation_document_exchange', label: 'Mediation document exchange', defaultColor: '#7c3aed' }
    ]
  }

  function matterTimelineTagFieldRows() {
    return tags.flatMap((tag) => {
      const fields = matterTimelineFieldsForTag(tag.id)
      return fields.map((field) => ({
        type: 'tag',
        key: `tag:${tag.id}:field:${field.id}`,
        tagId: tag.id,
        fieldId: field.id,
        label: `${tagFullName(tag.id) || tag.name} > ${field.label || field.field_key || 'Field'}`,
        tagLabel: tagFullName(tag.id) || tag.name,
        fieldLabel: field.label || field.field_key || 'Field',
        defaultColor: tagColor(tag.id)
      }))
    })
  }

  function matterTimelineAllOptionRows() {
    const eventRows = options('event_category').map((category) => ({
      type: 'event',
      key: `event:${category.name}`,
      label: category.name,
      defaultColor: eventCategoryColor(category.name)
    }))
    return [...eventRows, ...matterTimelineTagFieldRows(), ...matterTimelineCourtDeadlineRows(), ...matterTimelineDiscoveryRows()]
  }

  function matterTimelineOptionSettingsMap(type) {
    if (type === 'event') return matterTimelineOptions.eventCategorySettings || {}
    if (type === 'court_deadline') return matterTimelineOptions.courtDeadlineSettings || {}
    if (type === 'discovery') return matterTimelineOptions.discoverySettings || {}
    return matterTimelineOptions.tagSettings || {}
  }

  function hasConfiguredMatterTimelineVisibility() {
    const maps = [
      matterTimelineOptions.eventCategorySettings,
      matterTimelineOptions.courtDeadlineSettings,
      matterTimelineOptions.discoverySettings,
      matterTimelineOptions.tagSettings
    ]
    return maps.some((map) => Object.values(map || {}).some((setting) => setting && Object.prototype.hasOwnProperty.call(setting, 'visible')))
  }

  function matterTimelineDefaultVisible(type) {
    // Recovery fallback: if Chrome/localStorage loses the saved Matter Timeline Options,
    // do not leave the page blank.  Show event categories, court deadlines, and
    // discovery-date rows until the user changes Matter Timeline Options again.
    if (hasConfiguredMatterTimelineVisibility()) return false
    return type === 'event' || type === 'court_deadline' || type === 'discovery'
  }

  function restoreDefaultMatterTimelineOptions() {
    const next = {
      ...matterTimelineOptions,
      eventCategorySettings: { ...(matterTimelineOptions.eventCategorySettings || {}) },
      courtDeadlineSettings: { ...(matterTimelineOptions.courtDeadlineSettings || {}) },
      discoverySettings: { ...(matterTimelineOptions.discoverySettings || {}) },
      tagSettings: { ...(matterTimelineOptions.tagSettings || {}) }
    }

    matterTimelineAllOptionRows().forEach((row) => {
      if (row.type === 'tag') return
      const mapName = row.type === 'event' ? 'eventCategorySettings' : row.type === 'court_deadline' ? 'courtDeadlineSettings' : 'discoverySettings'
      const current = next[mapName][row.key] || {}
      next[mapName][row.key] = {
        ...current,
        visible: true,
        shape: current.shape || matterTimelineDefaultShape(row.type),
        color: current.color || row.defaultColor,
        lineType: current.lineType || 'solid',
        lineColor: current.lineColor || current.color || row.defaultColor
      }
    })

    setMatterTimelineHiddenOptionKeys([])
    setMatterTimelineOptions(next)
  }

  function matterTimelineDefaultShape(type) {
    if (type === 'event') return 'solid_circle'
    if (type === 'court_deadline') return 'solid_circle'
    if (type === 'discovery') return 'solid_circle'
    return 'solid_square'
  }

  function matterTimelineOptionSetting(type, key, defaultColor = '#4b5563') {
    const stored = matterTimelineOptionSettingsMap(type)[key] || {}
    const hasStoredVisible = Object.prototype.hasOwnProperty.call(stored, 'visible')
    const recoveredCourtDeadline = type === 'court_deadline' && (!stored.color || stored.color === '#111827' || stored.shape === 'circle_outline')
    const safeColor = recoveredCourtDeadline ? (defaultColor === '#111827' ? '#dc2626' : defaultColor) : (stored.color || defaultColor)
    const safeShape = recoveredCourtDeadline ? 'solid_circle' : (stored.shape || matterTimelineDefaultShape(type))
    return {
      visible: hasStoredVisible ? Boolean(stored.visible) : matterTimelineDefaultVisible(type),
      shape: safeShape,
      color: safeColor,
      connectTo: stored.connectTo || '',
      connectedFieldId: stored.connectedFieldId || '',
      visibleFieldIds: Array.isArray(stored.visibleFieldIds) ? stored.visibleFieldIds : [],
      lineType: stored.lineType || 'solid',
      lineColor: stored.lineColor || safeColor
    }
  }

  function updateMatterTimelineOption(type, key, patch) {
    const mapName = type === 'event' ? 'eventCategorySettings' : type === 'court_deadline' ? 'courtDeadlineSettings' : type === 'discovery' ? 'discoverySettings' : 'tagSettings'
    const current = matterTimelineOptions[mapName] || {}
    setMatterTimelineOptions({
      ...matterTimelineOptions,
      [mapName]: {
        ...current,
        [key]: {
          ...(current[key] || {}),
          ...patch
        }
      }
    })
  }

  function setMatterTimelineOptionGroupVisible(type, visible) {
    const rows = type === 'event'
      ? options('event_category').map((category) => ({ key: `event:${category.name}`, color: eventCategoryColor(category.name) }))
      : type === 'court_deadline'
        ? matterTimelineCourtDeadlineRows().map((row) => ({ key: row.key, color: row.defaultColor }))
        : type === 'discovery'
          ? matterTimelineDiscoveryRows().map((row) => ({ key: row.key, color: row.defaultColor }))
          : matterTimelineTagFieldRows().map((row) => ({ key: row.key, color: row.defaultColor }))
    const mapName = type === 'event' ? 'eventCategorySettings' : type === 'court_deadline' ? 'courtDeadlineSettings' : type === 'discovery' ? 'discoverySettings' : 'tagSettings'
    const current = matterTimelineOptions[mapName] || {}
    const next = { ...current }
    rows.forEach((row) => {
      next[row.key] = {
        ...(next[row.key] || {}),
        visible,
        shape: next[row.key]?.shape || matterTimelineDefaultShape(type),
        color: next[row.key]?.color || row.color,
        lineType: next[row.key]?.lineType || 'solid',
        lineColor: next[row.key]?.lineColor || next[row.key]?.color || row.color
      }
    })
    setMatterTimelineOptions({ ...matterTimelineOptions, [mapName]: next })
  }

  function matterTimelineSelectedEventCategories() {
    return options('event_category')
      .filter((category) => matterTimelineOptionSetting('event', `event:${category.name}`, eventCategoryColor(category.name)).visible)
      .map((category) => category.name)
  }

  function matterTimelineSelectedTagFieldRows() {
    return matterTimelineTagFieldRows()
      .filter((row) => matterTimelineOptionSetting('tag', row.key, row.defaultColor).visible)
  }

  function matterTimelineSelectedCourtDeadlineKeys() {
    return matterTimelineCourtDeadlineRows()
      .filter((row) => matterTimelineOptionSetting('court_deadline', row.key, row.defaultColor).visible)
      .map((row) => row.key)
  }

  function matterTimelineSelectedDiscoveryRows() {
    return matterTimelineDiscoveryRows()
      .filter((row) => matterTimelineOptionSetting('discovery', row.key, row.defaultColor).visible)
  }

  function matterTimelineSortCategories() {
    return Array.isArray(matterTimelineOptions.sortCategories) ? matterTimelineOptions.sortCategories : []
  }

  function setMatterTimelineSortCategories(categories) {
    setMatterTimelineOptions({ ...matterTimelineOptions, sortCategories: categories })
  }

  function addMatterTimelineSortCategory() {
    const name = matterTimelineSortCategoryDraftName.trim()
    if (!name) return
    const category = { id: `sort-${Date.now()}-${Math.random().toString(36).slice(2)}`, name, optionKeys: [] }
    setMatterTimelineSortCategories([...matterTimelineSortCategories(), category])
    setMatterTimelineSortCategoryDraftName('')
  }

  function updateMatterTimelineSortCategory(categoryId, patch) {
    setMatterTimelineSortCategories(matterTimelineSortCategories().map((category) => category.id === categoryId ? { ...category, ...patch } : category))
  }

  function deleteMatterTimelineSortCategory(categoryId) {
    setMatterTimelineSortCategories(matterTimelineSortCategories().filter((category) => category.id !== categoryId))
    if (matterTimelineSortMode === `custom:${categoryId}`) {
      setMatterTimelineSortMode('all')
      saveMioStateKey('caseMioMatterTimelineSortMode', 'all')
    }
  }

  function toggleMatterTimelineSortCategoryOption(categoryId, optionKey) {
    const categories = matterTimelineSortCategories().map((category) => {
      if (category.id !== categoryId) return category
      const keys = Array.isArray(category.optionKeys) ? category.optionKeys : []
      const nextKeys = keys.includes(optionKey) ? keys.filter((key) => key !== optionKey) : [...keys, optionKey]
      return { ...category, optionKeys: nextKeys }
    })
    setMatterTimelineSortCategories(categories)
  }

  function matterTimelineSortCategoryForMode(mode) {
    if (!String(mode || '').startsWith('custom:')) return null
    const id = String(mode).slice('custom:'.length)
    return matterTimelineSortCategories().find((category) => category.id === id) || null
  }

  function matterTimelineFieldsForTag(tagId) {
    return documentFieldsForTags([tagId])
  }

  function formatMatterTimelineFieldValue(value) {
    if (Array.isArray(value)) return value.filter(Boolean).join(', ')
    if (value === null || value === undefined) return ''
    return String(value)
  }

  function matterTimelineFieldPointDate(field, value) {
    const raw = Array.isArray(value) ? value.find(Boolean) : value
    return parseTimelineDate(raw) || parseDateInputValue(raw) || null
  }

  function toggleMatterTimelineTagField(tagKey, fieldId) {
    const setting = matterTimelineOptionSetting('tag', tagKey)
    const current = Array.isArray(setting.visibleFieldIds) ? setting.visibleFieldIds : []
    const next = current.includes(fieldId) ? current.filter((id) => id !== fieldId) : [...current, fieldId]
    updateMatterTimelineOption('tag', tagKey, { visibleFieldIds: next })
  }

  function matterTimelinePointVisual(point) {
    if (!point?.optionType || !point?.optionKey) return null
    return matterTimelineOptionSetting(point.optionType, point.optionKey, point.defaultColor || point.color || '#4b5563')
  }

  function matterTimelinePointIsVisible(point) {
    if (!point?.optionType || !point?.optionKey) return true
    if (matterTimelineHiddenOptionKeys.includes(point.optionKey)) return false
    return matterTimelinePointVisual(point).visible
  }

  function toggleMatterTimelinePageOptionVisibility(optionKey) {
    setMatterTimelineHiddenOptionKeys((current) => current.includes(optionKey) ? current.filter((key) => key !== optionKey) : [...current, optionKey])
  }

  function matterTimelineConnectionSegments(points) {
    const visibleOptionPoints = points.filter((point) => matterTimelinePointIsVisible(point) && point.optionKey)
    const segments = []
    visibleOptionPoints.forEach((point, index) => {
      const visual = matterTimelinePointVisual(point)
      if (!visual?.connectTo) return
      const target = visibleOptionPoints.find((candidate) => candidate.optionKey === visual.connectTo)
      if (!target || target === point) return
      segments.push({ from: point, to: target, lineType: visual.lineType || 'solid', color: visual.lineColor || visual.color || '#4b5563', key: `${point.optionKey}-${visual.connectTo}-${index}` })
    })
    return segments
  }

  function matterTimelineLineDash(lineType) {
    if (lineType === 'dashed') return '7 5'
    if (lineType === 'dotted') return '1 6'
    return undefined
  }

  function openMatterTimelineOptionsSettings() {
    setSettingsTab('matter_timeline_options')
    try { saveMioStateKey('caseMioPreferredSettingsTab', 'matter_timeline_options') } catch {}
    if (typeof window !== 'undefined') {
      const url = `${window.location.origin}${window.location.pathname}#settings:matter_timeline_options`
      window.open(url, '_blank', 'noopener,noreferrer')
    }
  }

  function matterTimelineFilterValue(value) {
    return value ? String(value) : '__blank__'
  }

  function matterTimelineFilterLabel(value) {
    return value === '__blank__' ? 'Blank / not set' : value
  }

  function matterTimelineStatusOptions(field, category) {
    const values = [
      ...options(category).map((option) => option.name).filter(Boolean),
      ...matters.map((matter) => matter[field]).filter(Boolean)
    ]
    const unique = Array.from(new Set(values.map((value) => String(value))))
      .sort((a, b) => a.localeCompare(b))
      .map((value) => ({ value, label: value }))
    const hasBlank = matters.some((matter) => !matter[field])
    return hasBlank ? [...unique, { value: '__blank__', label: 'Blank / not set' }] : unique
  }

  function selectedMatterTimelineFilters(currentFilters, optionRows) {
    const optionValues = optionRows.map((option) => option.value)
    if (!Array.isArray(currentFilters)) return optionValues
    return currentFilters.filter((value) => optionValues.includes(value))
  }

  function setMatterTimelineStatusFilter(kind, nextValues) {
    if (kind === 'case') setMatterTimelineCaseStatusFilters(nextValues)
    if (kind === 'matter') setMatterTimelineMatterStatusFilters(nextValues)
  }

  function toggleMatterTimelineStatusFilter(kind, value, optionRows) {
    const current = selectedMatterTimelineFilters(kind === 'case' ? matterTimelineCaseStatusFilters : matterTimelineMatterStatusFilters, optionRows)
    const next = current.includes(value) ? current.filter((item) => item !== value) : [...current, value]
    setMatterTimelineStatusFilter(kind, next)
  }

  function matterMatchesTimelineStatusFilters(matter, caseOptions, matterStatusOptions) {
    const selectedCaseStatuses = selectedMatterTimelineFilters(matterTimelineCaseStatusFilters, caseOptions)
    const selectedMatterStatuses = selectedMatterTimelineFilters(matterTimelineMatterStatusFilters, matterStatusOptions)
    return selectedCaseStatuses.includes(matterTimelineFilterValue(matter.case_status)) && selectedMatterStatuses.includes(matterTimelineFilterValue(matter.matter_status))
  }

  function syncMatterTimelineScroll(source) {
    if (matterTimelineScrollSyncRef.current) return
    const top = matterTimelineTopScrollRef.current
    const floating = matterTimelineFloatingScrollRef.current
    const main = matterTimelineMainScrollRef.current
    if (!top || !main) return
    const sourceNode = source === 'floating' ? floating : source === 'top' ? top : main
    if (!sourceNode) return
    matterTimelineScrollSyncRef.current = true
    const nextScrollLeft = sourceNode.scrollLeft
    if (source !== 'top') top.scrollLeft = nextScrollLeft
    if (source !== 'main') main.scrollLeft = nextScrollLeft
    if (floating && source !== 'floating') floating.scrollLeft = nextScrollLeft
    window.requestAnimationFrame(() => { matterTimelineScrollSyncRef.current = false })
  }

  function matterTimelineItems(matter) {
    const matterEvents = events.filter((event) => event.matter_id === matter.id && event.is_active !== false && !isUndatedEventDate(event.start_date))
    const today = startOfTodayTimeline()
    const futureOrTodayEventDate = (event) => {
      const date = parseTimelineDate(event.start_date)
      return date && date >= today ? date : null
    }
    const trialEvents = matterEvents
      .filter((event) => eventLooksLike(event, 'trial') && futureOrTodayEventDate(event))
      .sort((a, b) => futureOrTodayEventDate(a) - futureOrTodayEventDate(b))
    const hearingEvents = matterEvents
      .filter((event) => eventLooksLike(event, 'hearing') && futureOrTodayEventDate(event))
      .sort((a, b) => futureOrTodayEventDate(a) - futureOrTodayEventDate(b))

    const nextTrial = trialEvents[0] || null
    const furthestTrial = trialEvents.length ? trialEvents[trialEvents.length - 1] : null
    const trialDate = parseTimelineDate(nextTrial?.start_date)
    const furthestTrialDate = parseTimelineDate(furthestTrial?.start_date)
    const allTrialDate = earliestUpcomingTimelineDate(trialEvents.map((event) => parseTimelineDate(event.start_date)))
    const allSettingDate = earliestUpcomingTimelineDate([
      ...trialEvents.map((event) => parseTimelineDate(event.start_date)),
      ...hearingEvents.map((event) => parseTimelineDate(event.start_date))
    ])
    const rule = courtRuleForMatter(matter)
    const trialExhibitDays = Number(rule.trial_exhibit_days_before_trial || '')
    const hearingExhibitDays = Number(rule.hearing_exhibit_days_before_hearing || '')
    const trialExhibitDate = trialDate && Number.isFinite(trialExhibitDays) && trialExhibitDays > 0 && rule.trial_exhibit_days_before_trial !== '' ? nextNonWeekendHolidayDate(addTimelineDays(trialDate, -trialExhibitDays)) : null
    const discoveryEndDate = trialDate ? nextNonWeekendHolidayDate(addTimelineDays(trialDate, -30)) : null
    const discoveryPeriodDate = furthestTrialDate ? nextNonWeekendHolidayDate(addTimelineDays(furthestTrialDate, -30)) : null
    const pleadingDate = furthestTrialDate ? nextNonWeekendHolidayDate(addTimelineDays(furthestTrialDate, -7)) : null

    const rawPoints = []
    const rawSegments = []

    // The Matter Timelines page now shows only items selected in Settings > Matter Timeline Options.
    // Built-in trial, hearing, discovery, and deadline markers stay off the timeline unless
    // their event category or tag/field is selected below.

    const selectedEventCategories = matterTimelineSelectedEventCategories()
    matterEvents
      .filter((event) => selectedEventCategories.includes(event.event_category) && !isUndatedEventDate(event.start_date) && parseTimelineDate(event.start_date))
      .forEach((event) => {
        const optionKey = `event:${event.event_category}`
        const defaultColor = eventBlockColor(event)
        rawPoints.push({
          type: 'matter_timeline_option',
          sourceType: 'event',
          sourceId: event.id,
          date: parseTimelineDate(event.start_date),
          label: formatEventListBlockTitle(event),
          optionType: 'event',
          optionKey,
          defaultColor,
          color: defaultColor
        })
      })

    const selectedTagFieldRows = matterTimelineSelectedTagFieldRows()
    if (selectedTagFieldRows.length) {
      const selectedTagIds = Array.from(new Set(selectedTagFieldRows.map((row) => row.tagId)))
      documents
        .filter((doc) => doc.matter_id === matter.id && selectedTagIds.some((tagId) => (doc.tag_ids || []).includes(tagId)))
        .forEach((doc) => {
          const matchedRows = selectedTagFieldRows.filter((row) => (doc.tag_ids || []).includes(row.tagId))
          matchedRows.forEach((row) => {
            const fields = matterTimelineFieldsForTag(row.tagId)
            const field = fields.find((candidate) => candidate.id === row.fieldId)
            if (!field) return
            const values = applyCalculatedDocumentFieldValues(fields, doc.document_field_values || {})
            const fieldKey = field.field_key || field.id
            const valueText = formatMatterTimelineFieldValue(values[fieldKey])
            const fieldDate = matterTimelineFieldPointDate(field, values[fieldKey])
            if (!fieldDate) return
            const defaultColor = row.defaultColor || tagColor(row.tagId)
            const fieldPointId = `${doc.id}:tag:${row.tagId}:field:${field.id}`
            rawPoints.push({
              type: `tag_field:${field.id}`,
              sourceType: 'document_field',
              sourceId: fieldPointId,
              date: fieldDate,
              label: `${row.tagLabel || tagFullName(row.tagId) || 'Tag'} - ${field.label || field.field_key || 'Field'}${valueText ? `: ${valueText}` : ''}`,
              optionType: 'tag',
              optionKey: row.key,
              defaultColor,
              color: defaultColor
            })
          })
        })
      // Tags do not add their own element/document date points here. Only selected tag fields appear.
    }

    const selectedCourtDeadlineKeys = matterTimelineSelectedCourtDeadlineKeys()
    if (selectedCourtDeadlineKeys.includes('court:trial_exhibits') && trialExhibitDate) {
      const row = matterTimelineCourtDeadlineRows().find((item) => item.key === 'court:trial_exhibits')
      rawPoints.push({
        type: 'trial_exhibit',
        sourceType: 'court_deadline',
        sourceId: `${matter.id}:trial_exhibits`,
        date: trialExhibitDate,
        label: 'Trial exhibits due',
        optionType: 'court_deadline',
        optionKey: 'court:trial_exhibits',
        defaultColor: row?.defaultColor || '#111827',
        color: row?.defaultColor || '#111827'
      })
    }

    if (selectedCourtDeadlineKeys.includes('court:hearing_exhibits') && Number.isFinite(hearingExhibitDays) && hearingExhibitDays > 0 && rule.hearing_exhibit_days_before_hearing !== '') {
      const row = matterTimelineCourtDeadlineRows().find((item) => item.key === 'court:hearing_exhibits')
      hearingEvents.forEach((hearing) => {
        const hearingDate = parseTimelineDate(hearing.start_date)
        if (!hearingDate) return
        const hearingExhibitDate = nextNonWeekendHolidayDate(addTimelineDays(hearingDate, -hearingExhibitDays))
        rawPoints.push({
          type: 'hearing_exhibit',
          sourceType: 'court_deadline',
          sourceId: `${hearing.id}:hearing_exhibits`,
          date: hearingExhibitDate,
          label: `Hearing exhibits due - ${formatEventListBlockTitle(hearing)}`,
          optionType: 'court_deadline',
          optionKey: 'court:hearing_exhibits',
          defaultColor: row?.defaultColor || '#111827',
          color: row?.defaultColor || '#111827'
        })
      })
    }


    if (selectedCourtDeadlineKeys.includes('court:discovery_period') && discoveryPeriodDate) {
      const row = matterTimelineCourtDeadlineRows().find((item) => item.key === 'court:discovery_period')
      rawPoints.push({
        type: 'discovery_period',
        sourceType: 'court_deadline',
        sourceId: `${matter.id}:discovery_period`,
        date: discoveryPeriodDate,
        label: 'Discovery period',
        optionType: 'court_deadline',
        optionKey: 'court:discovery_period',
        defaultColor: row?.defaultColor || '#111827',
        color: row?.defaultColor || '#111827'
      })
    }

    if (selectedCourtDeadlineKeys.includes('court:pleading_date') && pleadingDate) {
      const row = matterTimelineCourtDeadlineRows().find((item) => item.key === 'court:pleading_date')
      rawPoints.push({
        type: 'pleading_date',
        sourceType: 'court_deadline',
        sourceId: `${matter.id}:pleading_date`,
        date: pleadingDate,
        label: 'Pleading date',
        optionType: 'court_deadline',
        optionKey: 'court:pleading_date',
        defaultColor: row?.defaultColor || '#111827',
        color: row?.defaultColor || '#111827'
      })
    }

    const selectedDiscoveryRows = matterTimelineSelectedDiscoveryRows()
    if (selectedDiscoveryRows.length) {
      ['our', 'their'].flatMap((side) => discoveryRows(side))
        .filter((row) => row.matter?.id === matter.id)
        .forEach((discoveryRow) => {
          selectedDiscoveryRows.forEach((optionRow) => {
            const dateValue = discoveryRow[optionRow.field]
            const date = parseTimelineDate(dateValue) || parseDateInputValue(dateValue)
            if (!date) return
            rawPoints.push({
              type: `discovery:${optionRow.field}`,
              sourceType: 'discovery',
              sourceId: `${discoveryRow.id}:${optionRow.field}`,
              documentId: discoveryRow.document?.id || '',
              date,
              label: `${optionRow.label} - ${discoveryRow.documentTitle || 'Discovery request'}`,
              optionType: 'discovery',
              optionKey: optionRow.key,
              defaultColor: optionRow.defaultColor,
              color: optionRow.defaultColor
            })
          })
        })
    }

    const adjustedPoints = rawPoints.map(applyMatterTimelineAdjustmentToPoint)
    const adjustedSegments = rawSegments.map(applyMatterTimelineAdjustmentToSegment)
    const positioned = assignMatterTimelinePointOffsets(adjustedPoints, adjustedSegments, matterTimelineLayoutMode)

    return { matter, points: positioned.points, segments: positioned.segments, trialDate, allTrialDate, allSettingDate, discoveryEndDate, trialExhibitDate, discoveryPeriodDate, pleadingDate, hearingEvents }
  }

  function allMatterTimelineData() {
    return matters.filter((matter) => matter.is_active !== false).map(matterTimelineItems)
  }

  function startOfTodayTimeline() {
    const today = new Date()
    today.setHours(0, 0, 0, 0)
    return today
  }

  function earliestUpcomingTimelineDate(dates) {
    const today = startOfTodayTimeline()
    const valid = dates
      .filter(Boolean)
      .map((date) => new Date(date))
      .filter((date) => !Number.isNaN(date.getTime()) && date >= today)
      .sort((a, b) => a - b)
    return valid[0] || null
  }

  function matterTimelineSelectedSortDate(row) {
    if (!row) return null
    const visiblePoints = (row.points || []).filter(matterTimelinePointIsVisible)
    const visibleOptionKeys = new Set(visiblePoints.map((point) => point.optionKey).filter(Boolean))
    const visibleSegmentDates = (row.segments || [])
      .filter((segment) => {
        if (!segment.optionKey && !segment.fromOptionKey && !segment.toOptionKey) return true
        return (!segment.optionKey || visibleOptionKeys.has(segment.optionKey))
          && (!segment.fromOptionKey || visibleOptionKeys.has(segment.fromOptionKey))
          && (!segment.toOptionKey || visibleOptionKeys.has(segment.toOptionKey))
      })
      .flatMap((segment) => [segment.start, segment.end])
    return earliestUpcomingTimelineDate([
      ...visiblePoints.map((point) => point.date),
      ...visibleSegmentDates
    ])
  }

  function matterTimelineDeadlineSortDate(row) {
    if (!row) return null
    return earliestUpcomingTimelineDate((row.points || [])
      .filter(matterTimelinePointIsVisible)
      .filter((point) => point.type === 'their_response_due' || point.type === 'discovery_end' || point.type === 'pleading_deadline' || point.type === 'trial_exhibit' || point.type === 'hearing_exhibit' || point.type === 'discovery_period' || point.type === 'pleading_date')
      .map((point) => point.date))
  }

  function matterTimelineSortDate(row, mode) {
    if (!row) return null
    const customCategory = matterTimelineSortCategoryForMode(mode)
    if (customCategory) {
      const keys = new Set(Array.isArray(customCategory.optionKeys) ? customCategory.optionKeys : [])
      return earliestUpcomingTimelineDate((row.points || [])
        .filter((point) => point.optionKey && keys.has(point.optionKey))
        .map((point) => point.date))
    }
    if (mode === 'trial') return row.allTrialDate || null
    if (mode === 'setting') return row.allSettingDate || null
    if (mode === 'deadline') return matterTimelineDeadlineSortDate(row)
    if (mode === 'all') {
      return earliestUpcomingTimelineDate([
        matterTimelineDeadlineSortDate(row),
        row.allSettingDate || null,
        row.allTrialDate || null,
        matterTimelineSelectedSortDate(row)
      ])
    }
    return matterTimelineSelectedSortDate(row)
  }

  function matterTimelineHasSelectedVisibleItem(row) {
    return Boolean(matterTimelineSelectedSortDate(row))
  }

  function sortedMatterTimelineData(rows, mode) {
    return [...rows].sort((a, b) => {
      if (mode === 'all') {
        const aHasSelected = matterTimelineHasSelectedVisibleItem(a)
        const bHasSelected = matterTimelineHasSelectedVisibleItem(b)
        if (aHasSelected && !bHasSelected) return -1
        if (!aHasSelected && bHasSelected) return 1
      }
      const aDate = matterTimelineSortDate(a, mode)
      const bDate = matterTimelineSortDate(b, mode)
      if (aDate && bDate) return aDate - bDate
      if (aDate) return -1
      if (bDate) return 1
      return matterDisplayName(a.matter).localeCompare(matterDisplayName(b.matter))
    })
  }

  function timelineSortLabel(mode) {
    const customCategory = matterTimelineSortCategoryForMode(mode)
    if (customCategory) return `next ${customCategory.name} item`
    if (mode === 'deadline') return 'next deadline'
    if (mode === 'trial') return 'next trial'
    if (mode === 'setting') return 'next trial/hearing setting'
    return 'next timeline item'
  }

  function matterTimelineVisibleWidth() {
    return Math.max(700, Number(matterTimelineViewportWidth || 0) - matterTimelineFixedColumnsWidth - 28)
  }

  function matterTimelineSvgWidthForRange(range) {
    const today = startOfTodayTimeline()
    const end = range?.end || addTimelineDays(today, 365)
    const start = range?.start || addTimelineDays(today, -120)
    const totalDays = Math.max(1, daysBetweenTimelineDates(start, end))
    const visibleDays = Math.max(1, Number(matterTimelineWindowDays) || 30)
    const width = Math.ceil((totalDays / visibleDays) * matterTimelineVisibleWidth()) + 24
    return Math.max(matterTimelineBaseSvgWidth, Math.min(200000, width))
  }

  function matterTimelineTableWidthForRange(range) {
    return matterTimelineFixedColumnsWidth + matterTimelineSvgWidthForRange(range)
  }

  function timelineRangeForRows(rows) {
    const eventDates = []
    rows.forEach((row) => {
      row.points.filter(matterTimelinePointIsVisible).forEach((point) => { if (point.date) eventDates.push(point.date) })
      row.segments.forEach((segment) => { if (segment.start) eventDates.push(segment.start); if (segment.end) eventDates.push(segment.end) })
    })

    const today = startOfTodayTimeline()
    const safePast = addTimelineDays(today, -3650)
    const safeFuture = addTimelineDays(today, 3650)
    const validEventDates = eventDates
      .filter((date) => date instanceof Date && !Number.isNaN(date.getTime()))
      .filter((date) => date >= safePast && date <= safeFuture)
    const dates = [...validEventDates, today]

    if (!validEventDates.length) {
      return { start: addTimelineDays(today, -120), end: addTimelineDays(today, 365) }
    }

    const min = new Date(Math.min(...dates.map((date) => date.getTime())))
    const max = new Date(Math.max(...dates.map((date) => date.getTime())))
    const start = min < today ? addTimelineDays(min, -7) : addTimelineDays(today, -120)
    const end = max > today ? addTimelineDays(max, 7) : addTimelineDays(today, 365)
    return { start, end }
  }

  function timelineGridDates(start, end) {
    const first = new Date(start)
    first.setDate(first.getDate() - first.getDay())
    const dates = []
    const current = new Date(first)
    let guard = 0
    while (current <= end && guard < 600) {
      dates.push(new Date(current))
      current.setDate(current.getDate() + 7)
      guard += 1
    }
    return dates
  }

  function renderMatterTimelineRow(row, range, timelineSvgWidth) {
    const width = timelineSvgWidth || matterTimelineSvgWidthForRange(range)
    const scrollableWidth = width
    const height = 72
    const start = range.start
    const end = range.end
    const totalDays = daysBetweenTimelineDates(start, end)
    const xFor = (date) => Math.max(8, Math.min(width - 8, 8 + ((date - start) / 86400000 / totalDays) * (width - 16)))
    const grid = timelineGridDates(start, end)
    const today = startOfTodayTimeline()
    const todayX = today >= start && today <= end ? xFor(today) : null

    const openMatterTimelinePoint = (point) => {
      if (point.sourceType === 'event') {
        const event = events.find((item) => item.id === point.sourceId)
        if (event) editEvent(event)
        return
      }
      if (point.sourceType === 'discovery') {
        const doc = documents.find((item) => item.id === point.documentId)
        if (doc) openDocumentEditWindow(doc)
      }
    }

    const pointClickProps = (point) => ((point.sourceType === 'event') || (point.sourceType === 'discovery' && point.documentId)) ? {
      onClick: (event) => { event.stopPropagation(); openMatterTimelinePoint(point) },
      style: { cursor: 'pointer' },
      tabIndex: 0,
      role: 'button',
      onKeyDown: (event) => { if (event.key === 'Enter' || event.key === ' ') { event.preventDefault(); openMatterTimelinePoint(point) } }
    } : {}

    const optionMarker = (point, key, title, x, y, visual) => {
      const color = visual.color || point.defaultColor || '#4b5563'
      const shape = visual.shape || matterTimelineDefaultShape(point.optionType)
      const clickProps = pointClickProps(point)
      if (shape === 'square_outline') return <rect key={key} x={x - 5} y={y - 5} width={10} height={10} fill="white" stroke={color} strokeWidth="3" {...clickProps}><title>{title}</title></rect>
      if (shape === 'solid_square') return <rect key={key} x={x - 5} y={y - 5} width={10} height={10} fill={color} stroke={color} strokeWidth="2" {...clickProps}><title>{title}</title></rect>
      if (shape === 'circle_outline') return <circle key={key} cx={x} cy={y} r="5" fill="white" stroke={color} strokeWidth="3" {...clickProps}><title>{title}</title></circle>
      return <circle key={key} cx={x} cy={y} r="5" fill={color} stroke={color} strokeWidth="2" {...clickProps}><title>{title}</title></circle>
    }

    const marker = (point, index) => {
      if (!matterTimelinePointIsVisible(point)) return null
      const x = xFor(point.date)
      const y = 34 + Number(point.yOffset || 0)
      const key = `${point.type}-${dateToInputValue(point.date)}-${index}`
      const title = `${point.label}: ${shortTimelineDate(point.date)}`
      const visual = matterTimelinePointVisual(point)
      if (visual) return optionMarker(point, key, title, x, y, visual)
      const clickProps = pointClickProps(point)
      if (point.type === 'trial') return <rect key={key} x={x - 5} y={y - 5} width={10} height={10} fill="none" stroke="#1d4ed8" strokeWidth="3" {...clickProps}><title>{title}</title></rect>
      if (point.type === 'discovery_request') return <circle key={key} cx={x} cy={y} r="4" fill="#f97316" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'discovery_response_due' || point.type === 'discovery_response') return <circle key={key} cx={x} cy={y} r="4" fill="#dc2626" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'discovery_end') return <circle key={key} cx={x} cy={y} r="4" fill="#dc2626" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'trial_exhibit' || point.type === 'hearing_exhibit') return <circle key={key} cx={x} cy={y} r="4" fill="#111827" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'hearing') return <circle key={key} cx={x} cy={y} r="4" fill="#111827" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'discovery_period' || point.type === 'pleading_date') return <circle key={key} cx={x} cy={y} r="4" fill="#111827" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'pleading_deadline') return <circle key={key} cx={x} cy={y} r="4" fill="#dc2626" {...clickProps}><title>{title}</title></circle>
      if (point.type === 'their_request_served' || point.type === 'their_response_due') return <circle key={key} cx={x} cy={y} r="4" fill="#dc2626" {...clickProps}><title>{title}</title></circle>
      return <circle key={key} cx={x} cy={y} r="4" fill="#4b5563" {...clickProps}><title>{title}</title></circle>
    }

    const visiblePoints = row.points.filter(matterTimelinePointIsVisible)
    const optionConnections = matterTimelineConnectionSegments(visiblePoints)

    return (
      <div style={{ width: scrollableWidth, minWidth: scrollableWidth, position: 'relative' }}>
      <svg width={width} height={height} viewBox={`0 0 ${width} ${height}`} style={{ overflow: 'visible', display: 'block' }}>
        <line x1="8" x2={width - 8} y1="34" y2="34" stroke="#6b7280" strokeWidth="1" />
        {todayX !== null && (
          <g>
            <line x1={todayX} x2={todayX} y1="4" y2="68" stroke="#16a34a" strokeWidth="2" strokeDasharray="6 4" />
            <text x={todayX + 5} y="68" fontSize="11" fill="#166534">Today</text>
            <title>Today: {shortTimelineDate(today)}</title>
          </g>
        )}
        {grid.map((date, index) => {
          const x = xFor(date)
          return (
            <g key={dateToInputValue(date)}>
              <line x1={x} x2={x} y1="8" y2="62" stroke="#d1d5db" strokeWidth="1" />
              {index % 2 === 0 && <text x={x} y="12" textAnchor="middle" fontSize="11" fill="#374151">{shortTimelineDate(date)}</text>}
            </g>
          )
        })}
        {optionConnections.map((segment) => {
          const x1 = xFor(segment.from.date)
          const x2 = xFor(segment.to.date)
          const sameDay = dateToInputValue(segment.from.date) === dateToInputValue(segment.to.date)
          const y1 = 34 + Number(segment.from.yOffset || 0)
          const y2 = matterTimelineLayoutMode === 'overlap' || sameDay ? y1 : 34 + Number(segment.to.yOffset || 0)
          return <line key={segment.key} x1={x1} x2={x2} y1={y1} y2={y2} stroke={segment.color} strokeWidth="2.5" strokeLinecap="round" strokeDasharray={matterTimelineLineDash(segment.lineType)}><title>{segment.from.label} connected to {segment.to.label}</title></line>
        })}
        {row.segments.map((segment, index) => {
          const x1 = xFor(segment.start)
          const x2 = xFor(segment.end)
          const color = segment.color || (segment.type === 'their_discovery' || segment.type === 'trial_prep' || segment.type === 'discovery_request_window' ? '#dc2626' : '#111827')
          const y = 34 + Number(segment.yOffset || 0)
          return <line key={`${segment.type}-${index}`} x1={x1} x2={x2} y1={y} y2={y} stroke={color} strokeWidth={segment.type === 'tag_field_connection' ? '2.5' : '5'} strokeLinecap="round" strokeDasharray={matterTimelineLineDash(segment.lineType)}><title>{segment.label}: {shortTimelineDate(segment.start)} to {shortTimelineDate(segment.end)}</title></line>
        })}
        {visiblePoints.map(marker)}
      </svg>
      </div>
    )
  }


  function renderMatterTimelineOptionsSettings() {
    const eventRows = options('event_category').map((category) => ({
      type: 'event',
      key: `event:${category.name}`,
      label: category.name,
      defaultColor: eventCategoryColor(category.name)
    }))
    const tagRows = matterTimelineTagFieldRows()
    const courtDeadlineRows = matterTimelineCourtDeadlineRows()
    const discoveryRowsForOptions = matterTimelineDiscoveryRows()
    const connectionOptions = matterTimelineAllOptionRows()
      .filter((option) => matterTimelineOptionSetting(option.type, option.key, option.defaultColor).visible)
    const selectedSortOptions = [...connectionOptions].sort((a, b) => a.label.localeCompare(b.label))
    const sortCategories = matterTimelineSortCategories()

    const selectedCount = (rows) => rows.filter((row) => matterTimelineOptionSetting(row.type, row.key, row.defaultColor).visible).length

    const renderRows = (rows) => (
      <div style={{ overflowX: 'auto', border: '1px solid #d5dce3', borderRadius: 6, background: 'white', marginBottom: 20 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 1380 }}>
          <thead>
            <tr style={{ background: '#f3f4f6' }}>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 70 }}>Show</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Name</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 220 }}>Timeline field</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 160 }}>Shape</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 130 }}>Color</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 240 }}>Connect to</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 140 }}>Line type</th>
              <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left', width: 130 }}>Line color</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((row) => {
              const setting = matterTimelineOptionSetting(row.type, row.key, row.defaultColor)
              const fieldLabel = row.type === 'tag' ? row.fieldLabel : row.type === 'court_deadline' ? 'Court deadline' : row.type === 'discovery' ? 'Discovery page date' : 'Event category'
              return (
                <tr key={row.key}>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <input type="checkbox" checked={setting.visible} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { visible: event.target.checked })} />
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <span style={{ display: 'inline-block', width: 12, height: 12, background: row.defaultColor, border: '1px solid #999', verticalAlign: 'middle', marginRight: 6 }} />
                    {row.label}
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>{fieldLabel}</td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <select value={setting.shape} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { shape: event.target.value })} style={{ width: '100%' }}>
                      {matterTimelineShapeOptions.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
                    </select>
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <input type="color" value={setting.color} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { color: event.target.value, lineColor: setting.lineColor || event.target.value })} />
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <select value={setting.connectTo} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { connectTo: event.target.value })} style={{ width: '100%' }}>
                      <option value="">No connection</option>
                      {connectionOptions.filter((option) => option.key !== row.key).map((option) => <option key={option.key} value={option.key}>{option.type === 'event' ? 'Event' : option.type === 'court_deadline' ? 'Court deadline' : option.type === 'discovery' ? 'Discovery' : 'Tag field'}: {option.label}</option>)}
                    </select>
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <select value={setting.lineType} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { lineType: event.target.value })} style={{ width: '100%' }} disabled={!setting.connectTo}>
                      {matterTimelineLineOptions.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
                    </select>
                  </td>
                  <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                    <input type="color" value={setting.lineColor} onChange={(event) => updateMatterTimelineOption(row.type, row.key, { lineColor: event.target.value })} disabled={!setting.connectTo} />
                  </td>
                </tr>
              )
            })}
            {!rows.length && <tr><td colSpan="8" style={{ padding: 16, textAlign: 'center', color: '#666' }}>No options found.</td></tr>}
          </tbody>
        </table>
      </div>
    )


    return (
      <div>
        <h2>Matter Timeline Options</h2>
        <p>Select exactly which event categories, tag fields, and court deadlines appear on the Matter Timelines page. Nothing appears on the timeline unless it is selected here. The Connect to dropdown only lists items checked as Show.</p>

        <div style={{ marginBottom: 20, padding: 12, border: '1px solid #c8d0d8', borderRadius: 6, background: '#f8fafc' }}>
          <h3 style={{ marginTop: 0 }}>Matter timeline sort dropdown options</h3>
          <p style={{ marginTop: 0, color: '#555', fontSize: 13 }}>Create custom order categories for the Matter Timelines page. These only decide how matters are sorted; the Timeline items dropdown still controls which dots are shown on the page.</p>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap', marginBottom: 12 }}>
            <input
              value={matterTimelineSortCategoryDraftName}
              onChange={(event) => setMatterTimelineSortCategoryDraftName(event.target.value)}
              placeholder="New category name, e.g. Settings"
              style={{ padding: 6, minWidth: 260 }}
            />
            <button type="button" onClick={addMatterTimelineSortCategory}>Add category</button>
          </div>
          {sortCategories.map((category) => {
            const keys = Array.isArray(category.optionKeys) ? category.optionKeys : []
            return (
              <details key={category.id} open style={{ border: '1px solid #d5dce3', borderRadius: 6, background: 'white', padding: 10, marginBottom: 10 }}>
                <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>{category.name || 'Unnamed category'} <span style={{ fontWeight: 'normal', color: '#666', fontSize: 12 }}>({keys.length} selected)</span></summary>
                <div style={{ display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap', margin: '10px 0' }}>
                  <label>Name <input value={category.name || ''} onChange={(event) => updateMatterTimelineSortCategory(category.id, { name: event.target.value })} style={{ marginLeft: 6, padding: 4 }} /></label>
                  <button type="button" onClick={() => updateMatterTimelineSortCategory(category.id, { optionKeys: selectedSortOptions.map((option) => option.key) })}>Select all shown options</button>
                  <button type="button" onClick={() => updateMatterTimelineSortCategory(category.id, { optionKeys: [] })}>Clear</button>
                  <button type="button" onClick={() => deleteMatterTimelineSortCategory(category.id)}>Delete category</button>
                </div>
                <div style={{ maxHeight: 180, overflowY: 'auto', display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))', gap: 6 }}>
                  {selectedSortOptions.map((option) => (
                    <label key={`${category.id}-${option.key}`} style={{ border: '1px solid #e5e7eb', borderRadius: 4, padding: '5px 8px', background: keys.includes(option.key) ? '#eef6ff' : 'white' }}>
                      <input type="checkbox" checked={keys.includes(option.key)} onChange={() => toggleMatterTimelineSortCategoryOption(category.id, option.key)} />
                      {' '}{option.type === 'event' ? 'Events' : option.type === 'court_deadline' ? 'Court deadlines' : option.type === 'discovery' ? 'Discovery' : 'Tags'} &gt; {option.label}
                    </label>
                  ))}
                  {!selectedSortOptions.length && <div style={{ color: '#666' }}>Select timeline items below first, then they will appear here.</div>}
                </div>
              </details>
            )
          })}
          {!sortCategories.length && <div style={{ color: '#666' }}>No custom sort categories yet.</div>}
        </div>

        <div style={{ marginBottom: 10, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <strong>Events:</strong>
          <span>{selectedCount(eventRows)} of {eventRows.length} selected</span>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('event', true)}>All</button>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('event', false)}>None</button>
        </div>
        {renderRows(eventRows)}

        <div style={{ marginBottom: 10, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <strong>Tags:</strong>
          <span>{selectedCount(tagRows)} of {tagRows.length} selected</span>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('tag', true)}>All</button>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('tag', false)}>None</button>
        </div>
        {renderRows(tagRows)}

        <div style={{ marginBottom: 10, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <strong>Court Deadlines:</strong>
          <span>{selectedCount(courtDeadlineRows)} of {courtDeadlineRows.length} selected</span>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('court_deadline', true)}>All</button>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('court_deadline', false)}>None</button>
        </div>
        {renderRows(courtDeadlineRows)}

        <div style={{ marginBottom: 10, display: 'flex', gap: 8, alignItems: 'center', flexWrap: 'wrap' }}>
          <strong>Discovery:</strong>
          <span>{selectedCount(discoveryRowsForOptions)} of {discoveryRowsForOptions.length} selected</span>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('discovery', true)}>All</button>
          <button type="button" onClick={() => setMatterTimelineOptionGroupVisible('discovery', false)}>None</button>
        </div>
        {renderRows(discoveryRowsForOptions)}
      </div>
    )
  }

  function renderMatterTimelineSettingsTable() {
    const rows = allMatterTimelineData()
      .flatMap((row) => row.points.map((point) => ({ row, point })))
      .filter(({ point }) => point.sourceType && point.sourceId && point.type && point.date)
      .sort((a, b) => {
        const matterCompare = matterDisplayName(a.row.matter).localeCompare(matterDisplayName(b.row.matter))
        if (matterCompare) return matterCompare
        return a.point.date - b.point.date
      })

    const typeLabel = (type) => {
      const labels = {
        trial: 'Trial',
        discovery_end: 'Discovery end',
        trial_exhibit: 'Trial exhibits due',
        hearing: 'Hearing',
        hearing_exhibit: 'Hearing exhibits due',
        pleading_deadline: 'Pleading deadline',
        discovery_request: 'Discovery request served',
        discovery_response_due: 'Discovery response due',
        discovery_response: 'Discovery response served',
        their_request_served: 'Discovery request served',
        their_response_due: 'Discovery response due',
        'discovery:trial': 'Discovery trial',
        'discovery:thirtyBeforeTrial': 'Discovery 30 days before trial',
        'discovery:request_served': 'Discovery request served',
        'discovery:sent_to_c': 'Discovery sent to C',
        'discovery:response_due': 'Discovery response due',
        'discovery:mediation_document_exchange': 'Discovery mediation document exchange'
      }
      return labels[type] || type
    }

    return (
      <div>
        <h2>Matter Timelines</h2>
        <p>Adjust dates shown on the Matter Timelines page only. These changes do not change calendar events or document field dates.</p>
        <div style={{ overflowX: 'auto', border: '1px solid #d5dce3', borderRadius: 6, background: 'white' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: 900 }}>
            <thead>
              <tr style={{ background: '#f3f4f6' }}>
                <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Matter</th>
                <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Timeline date</th>
                <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Type</th>
                <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Description</th>
                <th style={{ border: '1px solid #d5dce3', padding: 6, textAlign: 'left' }}>Action</th>
              </tr>
            </thead>
            <tbody>
              {rows.map(({ row, point }, index) => {
                const key = timelineAdjustmentKey(point.sourceType, point.sourceId, point.type)
                const value = dateToInputValue(point.date)
                const hasAdjustment = Boolean(matterTimelineDateAdjustments[key])
                return (
                  <tr key={`${key}-${index}`}>
                    <td style={{ border: '1px solid #d5dce3', padding: 6 }}>{matterDisplayName(row.matter)}</td>
                    <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                      <input type="date" value={value} onChange={(event) => setMatterTimelineDateAdjustment(key, event.target.value)} />
                      {hasAdjustment && <span style={{ marginLeft: 6, color: '#b45309', fontSize: 12 }}>adjusted</span>}
                    </td>
                    <td style={{ border: '1px solid #d5dce3', padding: 6 }}>{typeLabel(point.type)}</td>
                    <td style={{ border: '1px solid #d5dce3', padding: 6 }}>{point.label}</td>
                    <td style={{ border: '1px solid #d5dce3', padding: 6 }}>
                      <button type="button" onClick={() => clearMatterTimelineDateAdjustment(key)} disabled={!hasAdjustment}>Reset</button>
                    </td>
                  </tr>
                )
              })}
              {!rows.length && <tr><td colSpan="5" style={{ padding: 16, textAlign: 'center', color: '#666' }}>No matter timeline dates found yet.</td></tr>}
            </tbody>
          </table>
        </div>
      </div>
    )
  }

  function renderMatterTimelinesPage() {
    const caseStatusOptions = matterTimelineStatusOptions('case_status', 'case_status')
    const matterStatusOptions = matterTimelineStatusOptions('matter_status', 'matter_status')
    const selectedCaseStatuses = selectedMatterTimelineFilters(matterTimelineCaseStatusFilters, caseStatusOptions)
    const selectedMatterStatuses = selectedMatterTimelineFilters(matterTimelineMatterStatusFilters, matterStatusOptions)
    const rows = sortedMatterTimelineData(
      allMatterTimelineData().filter((row) => matterMatchesTimelineStatusFilters(row.matter, caseStatusOptions, matterStatusOptions)),
      matterTimelineSortMode
    )
    const range = timelineRangeForRows(rows)
    const timelineSvgWidth = matterTimelineSvgWidthForRange(range)
    const timelineTableMinWidth = matterTimelineTableWidthForRange(range)
    const selectedTimelineOptionRows = matterTimelineAllOptionRows()
      .filter((option) => matterTimelineOptionSetting(option.type, option.key, option.defaultColor).visible)
      .sort((a, b) => a.label.localeCompare(b.label))
    const selectedVisibleTimelineOptionCount = selectedTimelineOptionRows.filter((option) => !matterTimelineHiddenOptionKeys.includes(option.key)).length
    return (
      <>
        <h1>Matter Timelines</h1>
        <p>Each row shows a matter timeline with trial dates, hearings, discovery request response windows, discovery-end dates, and exhibit deadlines.</p>
        {!hasConfiguredMatterTimelineVisibility() && (
          <div style={{ margin: '8px 0 12px', padding: 10, border: '1px solid #f3c56b', background: '#fff8e5', borderRadius: 6, color: '#5f4600' }}>
            Matter Timeline Options looked empty, so Mio is showing the default timeline items instead of leaving the page blank.
            <button type="button" onClick={restoreDefaultMatterTimelineOptions} style={{ marginLeft: 8 }}>Save defaults</button>
          </div>
        )}

        <div style={{ marginBottom: 12 }}>
          <button type="button" onClick={openMatterTimelineOptionsSettings} style={{ padding: '7px 12px', border: '1px solid #c8d0d8', background: '#fff', fontWeight: 'bold' }}>
            Matter Timeline Options
          </button>
        </div>

        <p style={{ color: '#555' }}>Court exhibit deadline rules are now edited in <strong>Settings &gt; Court Table</strong>.</p>

        <div style={{ marginBottom: 12, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8, flexWrap: 'wrap' }}>
          <label htmlFor="matterTimelineSortMode"><strong>Order matters by:</strong></label>
          <select
            id="matterTimelineSortMode"
            value={matterTimelineSortMode}
            onChange={(event) => {
              setMatterTimelineSortMode(event.target.value)
              saveMioStateKey('caseMioMatterTimelineSortMode', event.target.value)
            }}
          >
            <option value="deadline">Deadline</option>
            <option value="trial">Trial</option>
            <option value="setting">Setting</option>
            <option value="all">All</option>
            {matterTimelineSortCategories().map((category) => <option key={category.id} value={`custom:${category.id}`}>{category.name || 'Unnamed category'}</option>)}
          </select>
          <span style={{ color: '#666', fontSize: 12 }}>Showing matters with selected visible timeline items first, then the soonest {timelineSortLabel(matterTimelineSortMode)}.</span>
        </div>

        <div style={{ margin: '8px auto 12px', display: 'flex', gap: 12, justifyContent: 'center', alignItems: 'flex-start', flexWrap: 'wrap' }}>
          <details style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 220 }}>
            <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>Case Status <span style={{ fontWeight: 'normal', color: '#666', fontSize: 12 }}>({selectedCaseStatuses.length} of {caseStatusOptions.length})</span></summary>
            <div style={{ display: 'flex', gap: 6, margin: '8px 0 6px' }}>
              <button type="button" onClick={() => setMatterTimelineStatusFilter('case', caseStatusOptions.map((option) => option.value))}>All</button>
              <button type="button" onClick={() => setMatterTimelineStatusFilter('case', [])}>None</button>
            </div>
            <div style={{ maxHeight: 150, overflowY: 'auto' }}>
              {caseStatusOptions.map((option) => (
                <label key={option.value} style={{ display: 'block', fontSize: 12, marginBottom: 3 }}>
                  <input type="checkbox" checked={selectedCaseStatuses.includes(option.value)} onChange={() => toggleMatterTimelineStatusFilter('case', option.value, caseStatusOptions)} />
                  {' '}{matterTimelineFilterLabel(option.label)}
                </label>
              ))}
            </div>
          </details>

          <details style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 220 }}>
            <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>Matter Status <span style={{ fontWeight: 'normal', color: '#666', fontSize: 12 }}>({selectedMatterStatuses.length} of {matterStatusOptions.length})</span></summary>
            <div style={{ display: 'flex', gap: 6, margin: '8px 0 6px' }}>
              <button type="button" onClick={() => setMatterTimelineStatusFilter('matter', matterStatusOptions.map((option) => option.value))}>All</button>
              <button type="button" onClick={() => setMatterTimelineStatusFilter('matter', [])}>None</button>
            </div>
            <div style={{ maxHeight: 150, overflowY: 'auto' }}>
              {matterStatusOptions.map((option) => (
                <label key={option.value} style={{ display: 'block', fontSize: 12, marginBottom: 3 }}>
                  <input type="checkbox" checked={selectedMatterStatuses.includes(option.value)} onChange={() => toggleMatterTimelineStatusFilter('matter', option.value, matterStatusOptions)} />
                  {' '}{matterTimelineFilterLabel(option.label)}
                </label>
              ))}
            </div>
          </details>

          <details style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 280 }}>
            <summary style={{ cursor: 'pointer', fontWeight: 'bold' }}>Timeline items <span style={{ fontWeight: 'normal', color: '#666', fontSize: 12 }}>({selectedVisibleTimelineOptionCount} of {selectedTimelineOptionRows.length})</span></summary>
            <div style={{ display: 'flex', gap: 6, margin: '8px 0 6px' }}>
              <button type="button" onClick={() => setMatterTimelineHiddenOptionKeys([])}>All</button>
              <button type="button" onClick={() => setMatterTimelineHiddenOptionKeys(selectedTimelineOptionRows.map((option) => option.key))}>None</button>
            </div>
            <div style={{ maxHeight: 180, overflowY: 'auto' }}>
              {selectedTimelineOptionRows.map((option) => (
                <label key={option.key} style={{ display: 'block', fontSize: 12, marginBottom: 3 }}>
                  <input type="checkbox" checked={!matterTimelineHiddenOptionKeys.includes(option.key)} onChange={() => toggleMatterTimelinePageOptionVisibility(option.key)} />
                  {' '}{option.label}
                </label>
              ))}
              {!selectedTimelineOptionRows.length && (
                <div style={{ fontSize: 12, color: '#666' }}>
                  No selected timeline items yet.
                  <button type="button" onClick={restoreDefaultMatterTimelineOptions} style={{ marginLeft: 8 }}>Restore default items</button>
                </div>
              )}
            </div>
          </details>

          <label style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 180 }}>
            <strong>Timeline layout</strong>{' '}
            <select value={matterTimelineLayoutMode} onChange={(event) => setMatterTimelineLayoutMode(event.target.value)} style={{ marginLeft: 6 }}>
              <option value="overlap">Overlap</option>
              <option value="separate">Separate</option>
            </select>
          </label>

          <label style={{ border: '1px solid #d5dce3', borderRadius: 6, padding: 8, background: '#fff', minWidth: 230 }}>
            <strong>Days visible at once</strong>{' '}
            <select value={matterTimelineWindowDays} onChange={(event) => setMatterTimelineWindowDays(Number(event.target.value))} style={{ marginLeft: 6 }}>
              <option value={14}>2 weeks</option>
              <option value={30}>30 days</option>
              <option value={60}>60 days</option>
              <option value={90}>90 days</option>
              <option value={120}>120 days</option>
            </select>
          </label>
        </div>

        <p style={{ color: '#555', fontSize: 13 }}>Only checked timeline items selected in Matter Timeline Options are shown. Use Days visible at once to control timeline spacing; scroll horizontally to see dates outside the visible window.</p>

        <div style={{ marginBottom: 6, textAlign: 'right' }}>
          <button
            type="button"
            onClick={() => {
              const rangeForToday = timelineRangeForRows(rows)
              const totalDays = Math.max(1, daysBetweenTimelineDates(rangeForToday.start, rangeForToday.end))
              const today = startOfTodayTimeline()
              const todayX = Math.max(8, Math.min(timelineSvgWidth - 8, 8 + ((today - rangeForToday.start) / 86400000 / totalDays) * (timelineSvgWidth - 16)))
              const targetScrollLeft = Math.max(0, todayX - 8)
              const top = matterTimelineTopScrollRef.current
              const floating = matterTimelineFloatingScrollRef.current
              const main = matterTimelineMainScrollRef.current
              if (top) top.scrollLeft = Math.min(targetScrollLeft, Math.max(0, top.scrollWidth - top.clientWidth))
              if (main) main.scrollLeft = Math.min(targetScrollLeft, Math.max(0, main.scrollWidth - main.clientWidth))
              if (floating) floating.scrollLeft = Math.min(targetScrollLeft, Math.max(0, floating.scrollWidth - floating.clientWidth))
            }}
          >
            Show today at left
          </button>
        </div>

        <div
          ref={matterTimelineTopScrollRef}
          onScroll={() => syncMatterTimelineScroll('top')}
          style={{
            overflowX: 'auto',
            overflowY: 'hidden',
            width: '100%',
            position: 'sticky',
            top: 0,
            zIndex: 30,
            background: '#fff',
            maxWidth: 'calc(100vw - 270px)',
            height: 18,
            marginBottom: 4,
            scrollbarGutter: 'stable'
          }}
        >
          <div style={{ width: timelineTableMinWidth, minWidth: timelineTableMinWidth, height: 1 }} />
        </div>

        <div
          ref={matterTimelineFloatingScrollRef}
          onScroll={() => syncMatterTimelineScroll('floating')}
          style={{
            position: 'fixed',
            left: matterTimelineFixedColumnsWidth + 20,
            right: 20,
            bottom: 8,
            height: 18,
            overflowX: 'auto',
            overflowY: 'hidden',
            background: 'rgba(255,255,255,0.96)',
            border: '1px solid #d5dce3',
            borderRadius: 8,
            boxShadow: '0 2px 10px rgba(0,0,0,0.16)',
            zIndex: 100
          }}
          aria-label="Floating matter timeline horizontal scroll"
        >
          <div style={{ width: timelineTableMinWidth, minWidth: timelineTableMinWidth, height: 1 }} />
        </div>

        <div
          ref={matterTimelineMainScrollRef}
          onScroll={() => syncMatterTimelineScroll('main')}
          style={{
            border: '1px solid #d5dce3',
            borderRadius: 8,
            overflowX: 'auto',
            overflowY: 'visible',
            width: '100%',
            maxWidth: 'calc(100vw - 270px)',
            background: 'white',
            paddingBottom: 16,
            scrollbarGutter: 'stable'
          }}
        >
          <table style={{ width: 'max-content', minWidth: timelineTableMinWidth, borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ background: '#f3f4f6' }}>
                <th style={{ ...matterTimelineStickyClientMatterHeaderStyle, textAlign: 'left', padding: 8, width: matterTimelineClientMatterColumnWidth, minWidth: matterTimelineClientMatterColumnWidth }}>Client / Matter</th>
                <th style={{ textAlign: 'left', padding: 8, width: matterTimelineSortDateColumnWidth, minWidth: matterTimelineSortDateColumnWidth }}>Sort date</th>
                <th style={{ textAlign: 'left', padding: 8 }}>Timeline</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((row) => (
                <tr key={row.matter.id} style={{ borderTop: '1px solid #e5e7eb' }}>
                  <td style={{ ...matterTimelineStickyClientMatterCellStyle, padding: 8, verticalAlign: 'middle', fontWeight: 600, width: matterTimelineClientMatterColumnWidth, minWidth: matterTimelineClientMatterColumnWidth }}>
                    <a
                      href={`#matter_dashboard:${encodeURIComponent(row.matter.id)}`}
                      onClick={(event) => {
                        if (event.ctrlKey || event.metaKey || event.shiftKey || event.altKey || event.button !== 0) return
                        event.preventDefault()
                        openMatterTaskTemplates(row.matter)
                      }}
                      style={{ color: '#1d4ed8', textDecoration: 'underline', fontWeight: 600 }}
                    >
                      {matterTimelineClientMatterLabel(row.matter)}
                    </a>
                  </td>
                  <td style={{ padding: 8, verticalAlign: 'middle', width: matterTimelineSortDateColumnWidth, minWidth: matterTimelineSortDateColumnWidth, color: matterTimelineSortDate(row, matterTimelineSortMode) ? '#111827' : '#9ca3af' }}>
                    {matterTimelineSortDate(row, matterTimelineSortMode) ? shortTimelineDate(matterTimelineSortDate(row, matterTimelineSortMode)) : 'No upcoming item'}
                  </td>
                  <td style={{ padding: 8 }}>{renderMatterTimelineRow(row, range, timelineSvgWidth)}</td>
                </tr>
              ))}
              {!rows.length && <tr><td colSpan="3" style={{ padding: 20, textAlign: 'center' }}>No active matters found.</td></tr>}
            </tbody>
          </table>
        </div>
      </>
    )
  }



  const serviceGraphScopes = ['User.Read', 'Mail.ReadWrite', 'Mail.ReadWrite.Shared', 'Mail.Send', 'Mail.Send.Shared']

  function updateServiceGraphConfig(field, value) {
    setServiceGraphConfig((config) => ({ ...config, [field]: value }))
  }

  function serviceGraphAuthority() {
    const tenant = (serviceGraphConfig.tenantId || 'common').trim()
    return `https://login.microsoftonline.com/${tenant || 'common'}`
  }

  function serviceGraphRedirectUri() {
    // Full-page MSAL redirect must return to the currently hosted React app, not to the static
    // /auth-redirect.html placeholder. The placeholder is fine for some popup
    // flows, but in Chrome it was leaving the popup stuck on "Signing in..."
    // until MSAL timed out. Returning to the app lets handleRedirectPromise()
    // complete the sign-in and restore the page.
    const configured = String(serviceGraphConfig.redirectUri || '').trim()
    if (configured && !/auth-redirect\.html/i.test(configured)) return configured.split('#')[0]
    return `${window.location.origin}${window.location.pathname || '/'}`
  }

  function microsoftPopupRedirectUri() {
    return serviceGraphRedirectUri()
  }

  function clearMicrosoftInteractionState() {
    try {
      const clearFrom = (storage) => {
        Object.keys(storage || {}).forEach((key) => {
          const lower = String(key).toLowerCase()
          if (lower.includes('interaction') || lower.includes('request_state') || lower.includes('nonce') || lower.includes('authority')) {
            storage.removeItem(key)
          }
        })
      }
      clearFrom(sessionStorage)
      clearFrom(localStorage)
    } catch {}
  }

  function microsoftAuthRequest(extra = {}) {
    return {
      scopes: serviceGraphScopes,
      prompt: 'select_account',
      redirectUri: microsoftPopupRedirectUri(),
      ...extra
    }
  }

async function loadMicrosoftMsalScript() {
  try {
    const msalLib = await import('@azure/msal-browser')
    return msalLib
  } catch (error) {
    console.error('Microsoft sign-in library failed to load:', error)
    throw new Error('Microsoft sign-in library failed to load from the installed package.')
  }
}
      

  async function getServiceMsalApp() {
  const msalLib = await loadMicrosoftMsalScript()
  const clientId = (serviceGraphConfig.clientId || '').trim()
  if (!clientId) throw new Error('Enter the Microsoft Application (client) ID in Service Email Settings first.')

  const app = new msalLib.PublicClientApplication({
    auth: {
      clientId,
      authority: serviceGraphAuthority(),
      redirectUri: serviceGraphRedirectUri(),
      navigateToLoginRequestUrl: false
    },
    system: { allowNativeBroker: false },
    cache: {
      cacheLocation: 'localStorage',
      storeAuthStateInCookie: false
    }
  })

  await app.initialize()
  return app
}
useEffect(() => {
  async function finishMicrosoftRedirectSignIn() {
    try {
      const clientId = (serviceGraphConfig.clientId || '').trim()
      if (!clientId) return

      const app = await getServiceMsalApp()
      const result = await app.handleRedirectPromise()
      const account = result?.account || app.getAllAccounts()[0]

      if (!account) return

      app.setActiveAccount(account)

      setServiceGraphAuth({
        connected: true,
        account: {
          username: account.username || '',
          name: account.name || ''
        },
        connected_at: new Date().toISOString()
      })

      setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))

      setServiceEmailScanNote(
        `Connected to Microsoft as ${account.username || account.name || 'signed-in user'}.`
      )

      const returnHash = sessionStorage.getItem('caseMioMicrosoftReturnHash') || window.location.hash || '#service_inbox'
      sessionStorage.removeItem('caseMioMicrosoftReturnPage')
      sessionStorage.removeItem('caseMioMicrosoftReturnHash')
      if (returnHash) {
        window.history.replaceState(null, '', returnHash)
        const targetPage = returnHash.replace(/^#/, '').split('?')[0] || 'service_inbox'
        if (targetPage) setPage(targetPage)
      }

      setServiceGraphBusy(false)
    } catch (error) {
      console.error('Microsoft redirect sign-in failed:', error)
      setServiceEmailScanNote(`Microsoft redirect sign-in failed: ${error.message || error}`)
      setServiceGraphBusy(false)
    }
  }

  finishMicrosoftRedirectSignIn()
}, [])

useEffect(() => {
  let cancelled = false
  async function restoreMicrosoftGraphConnection() {
    try {
      const clientId = (serviceGraphConfig.clientId || '').trim()
      if (!clientId) return
      const app = await getServiceMsalApp()
      const account = app.getActiveAccount() || app.getAllAccounts()[0]
      if (!account || cancelled) return
      app.setActiveAccount(account)
      await app.acquireTokenSilent({ scopes: serviceGraphScopes, account }).catch(() => null)
      if (cancelled) return
      setServiceGraphAuth({
        connected: true,
        account: { username: account.username || '', name: account.name || '' },
        connected_at: new Date().toISOString()
      })
      setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))
      setServiceEmailScanNote(`Microsoft email connection restored for ${account.username || account.name || 'signed-in user'}.`)
    } catch (error) {
      console.warn('Microsoft connection restore skipped:', error)
    }
  }
  restoreMicrosoftGraphConnection()
  return () => { cancelled = true }
}, [])
 async function connectMicrosoftGraph() {
  setServiceGraphBusy(true)
  try {
    clearMicrosoftInteractionState()
    const app = await getServiceMsalApp()
    const currentHash = window.location.hash || `#${page || 'service_inbox'}`
    const currentUrl = `${window.location.origin}${window.location.pathname || '/'}${currentHash}`
    sessionStorage.setItem('caseMioMicrosoftReturnHash', currentHash)
    sessionStorage.setItem('caseMioMicrosoftReturnPage', currentHash.replace(/^#/, '').split('?')[0] || page || 'service_inbox')
    setServiceEmailScanNote('Opening Microsoft sign-in. This should return to the same page you are on now.')

    let result = null
    try {
      result = await app.loginPopup(microsoftAuthRequest({
        redirectUri: serviceGraphRedirectUri(),
        prompt: 'select_account'
      }))
    } catch (popupError) {
      console.warn('Microsoft popup sign-in failed; falling back to redirect sign-in:', popupError)
      await app.loginRedirect(microsoftAuthRequest({
        redirectUri: serviceGraphRedirectUri(),
        redirectStartPage: currentUrl,
        prompt: 'select_account'
      }))
      return
    }

    const account = result?.account || app.getAllAccounts()[0]
    if (!account) throw new Error('Microsoft sign-in completed, but no account was returned.')
    app.setActiveAccount(account)
    setServiceGraphAuth({
      connected: true,
      account: { username: account.username || '', name: account.name || '' },
      connected_at: new Date().toISOString()
    })
    setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))
    setServiceEmailScanNote(`Connected to Microsoft as ${account.username || account.name || 'signed-in user'}.`)
    if (currentHash && window.location.hash !== currentHash) window.history.replaceState(null, '', currentHash)
    const targetPage = currentHash.replace(/^#/, '').split('?')[0]
    if (targetPage) setPage(targetPage)
  } catch (error) {
    console.error('Microsoft connection failed:', error)
    setServiceGraphAuth({ connected: false, account: null })
    setServiceEmailScanNote(`Microsoft connection failed: ${error.message || error}`)
    alert(`Microsoft connection failed: ${error.message || error}`)
  } finally {
    setServiceGraphBusy(false)
  }
}

  async function disconnectMicrosoftGraph() {
    setServiceGraphBusy(true)
    try {
      const app = await getServiceMsalApp()
      const account = app.getActiveAccount() || app.getAllAccounts()[0]
      if (account) await app.logoutPopup({ account })
    } catch {}
    setServiceGraphAuth({ connected: false, account: null })
    setServiceGraphConfig((config) => ({ ...config, mode: 'mock' }))
    setServiceEmailScanNote('Disconnected Microsoft Graph. Service Inbox is back in mock/test mode.')
    setServiceGraphBusy(false)
  }

  async function getMicrosoftGraphToken(options = {}) {
    const { allowInteractive = false } = options
    const app = await getServiceMsalApp()
    await app.handleRedirectPromise().catch(() => null)
    let account = app.getActiveAccount() || app.getAllAccounts()[0]

    if (!account && allowInteractive) {
      clearMicrosoftInteractionState()
      const currentHash = window.location.hash || `#${page || 'service_inbox'}`
      sessionStorage.setItem('caseMioMicrosoftReturnHash', currentHash)
      sessionStorage.setItem('caseMioMicrosoftReturnPage', currentHash.replace(/^#/, '').split('?')[0] || page || 'service_inbox')
      await app.loginRedirect(microsoftAuthRequest({ redirectUri: serviceGraphRedirectUri(), prompt: 'select_account' }))
      throw new Error('Microsoft sign-in started. Finish the Microsoft sign-in and run the scan again.')
    }

    if (!account) {
      setServiceGraphAuth({ connected: false, account: null })
      setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))
      throw new Error('Microsoft is not connected in this browser. Click Connect / Reconnect Microsoft, sign in, then run the scan again.')
    }

    app.setActiveAccount(account)

    try {
      const token = await app.acquireTokenSilent({ scopes: serviceGraphScopes, account })
      setServiceGraphAuth({
        connected: true,
        account: { username: account.username || '', name: account.name || '' },
        connected_at: new Date().toISOString()
      })
      setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))
      return token.accessToken
    } catch (silentError) {
      console.warn('Silent Microsoft token refresh failed:', silentError)
      if (!allowInteractive) {
        throw new Error('Microsoft sign-in expired or needs consent. Click Connect / Reconnect Microsoft, finish Microsoft sign-in, then run the scan again.')
      }
      clearMicrosoftInteractionState()
      const currentHash = window.location.hash || `#${page || 'service_inbox'}`
      sessionStorage.setItem('caseMioMicrosoftReturnHash', currentHash)
      sessionStorage.setItem('caseMioMicrosoftReturnPage', currentHash.replace(/^#/, '').split('?')[0] || page || 'service_inbox')
      await app.acquireTokenRedirect(microsoftAuthRequest({ account, redirectUri: serviceGraphRedirectUri() }))
      throw new Error('Microsoft consent/sign-in started. Finish the Microsoft sign-in and run the scan again.')
    }
  }

  function sleepServiceGraph(ms) {
    return new Promise((resolve) => setTimeout(resolve, ms))
  }

  async function graphFetch(path, options = {}) {
    const token = await getMicrosoftGraphToken({ allowInteractive: !!options.allowInteractive })
    const url = path.startsWith('https://') ? path : `https://graph.microsoft.com/v1.0${path}`
    const maxRetries = Number.isFinite(options.maxRetries) ? options.maxRetries : 3
    const fetchOptions = { ...options }
    delete fetchOptions.allowInteractive
    delete fetchOptions.maxRetries

    for (let attempt = 0; attempt <= maxRetries; attempt += 1) {
      const response = await fetch(url, {
        ...fetchOptions,
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
          Prefer: 'outlook.body-content-type="text"',
          ...(fetchOptions.headers || {})
        }
      })

      if (response.status === 429 && attempt < maxRetries) {
        const retryAfterHeader = response.headers.get('Retry-After')
        const retryAfterSeconds = Number(retryAfterHeader || 0)
        const waitMs = Number.isFinite(retryAfterSeconds) && retryAfterSeconds > 0
          ? retryAfterSeconds * 1000
          : Math.min(15000, 1500 * Math.pow(2, attempt))
        setServiceEmailScanNote(`Microsoft Graph is throttling this mailbox. Waiting ${Math.ceil(waitMs / 1000)} second(s), then retrying...`)
        await sleepServiceGraph(waitMs)
        continue
      }

      if (!response.ok) {
        let detail = ''
        try { detail = JSON.stringify(await response.json()) } catch { detail = await response.text() }
        throw new Error(`Graph ${response.status}: ${detail}`)
      }
      if (response.status === 204) return null
      const responseText = await response.text()
      if (!responseText) return null
      try {
        return JSON.parse(responseText)
      } catch (jsonError) {
        return { raw: responseText }
      }
    }

    throw new Error('Graph request failed after throttling retries.')
  }

  function isGraphItemNotFound(error) {
    return /Graph 404|ErrorItemNotFound|specified object was not found|not found in the store/i.test(String(error?.message || error || ''))
  }

  function graphMailboxBase(mailboxEmail) {
    const signedInEmail = (serviceGraphAuth?.account?.username || '').toLowerCase()
    const mailbox = String(mailboxEmail || '').trim()
    if (!mailbox || mailbox.toLowerCase() === signedInEmail) return '/me'
    return `/users/${encodeURIComponent(mailbox)}`
  }

  function sourceUsesFocusedOrOther(source) {
    const name = String(source?.outlook_folder_name || '').toLowerCase()
    if (name.includes('focused')) return 'focused'
    if (name.includes('other')) return 'other'
    return ''
  }

  function normalizeServiceEmail(value) {
    return String(value || '').trim().toLowerCase()
  }

  function serviceInboxMailboxMatches(sourceOrEmail, filterValue = serviceInboxMailboxFilter) {
    if (!filterValue || filterValue === 'all') return true
    const email = typeof sourceOrEmail === 'string' ? sourceOrEmail : sourceOrEmail?.mailbox_email
    return normalizeServiceEmail(email) === normalizeServiceEmail(filterValue)
  }

  function makeAdHocInboxSource(mailboxEmail) {
    const clean = String(mailboxEmail || '').trim()
    const label = clean.split('@')[0] || 'email'
    return {
      id: `adhoc-${normalizeServiceEmail(clean).replace(/[^a-z0-9]/g, '-')}-inbox`,
      account_label: label,
      mailbox_email: clean,
      outlook_folder_name: 'Inbox',
      monitor_section: 'Inbox',
      filing_category: `${label} inbox`,
      default_onedrive_folder: serviceGraphConfig?.defaultOneDriveFolder || '',
      read_folder_name: 'Read',
      default_billing_minutes: Number(serviceGraphConfig?.defaultBillingMinutes || 6),
      enabled: true
    }
  }

  function configuredServiceEmailSourcesForCurrentFilters() {
    const configured = serviceEmailSources
      .filter((source) => source.enabled)
      .filter((source) => serviceInboxMailboxMatches(source))
      .filter((source) => serviceInboxFolderFilter === 'all' || source.id === serviceInboxFolderFilter)

    if (configured.length) return configured

    // If the user picked a specific mailbox but does not yet have a checked row
    // for that mailbox/folder in Settings, still let them scan that mailbox's
    // Inbox. This avoids the confusing "no enabled folders" dead end.
    if (serviceInboxMailboxFilter && serviceInboxMailboxFilter !== 'all' && serviceInboxFolderFilter === 'all') {
      return [makeAdHocInboxSource(serviceInboxMailboxFilter)]
    }

    return configured
  }

  function sourceFolderPathParts(source, forRead = false) {
    const raw = String(forRead ? (source?.read_folder_name || 'Read') : (source?.outlook_folder_name || 'Inbox'))
    return raw.split('/').map((part) => part.trim()).filter((part) => part && !/^focused$/i.test(part) && !/^other$/i.test(part))
  }

  async function listChildMailFolders(basePath, folderId = null) {
    const start = folderId ? `${basePath}/mailFolders/${encodeURIComponent(folderId)}/childFolders?$top=100` : `${basePath}/mailFolders?$top=100`
    const folders = []
    let next = start
    while (next) {
      const data = await graphFetch(next)
      folders.push(...(data.value || []))
      next = data['@odata.nextLink'] || ''
    }
    return folders
  }

  async function resolveOutlookFolderId(source, forRead = false) {
    const explicitId = forRead ? source?.read_folder_id : source?.outlook_folder_id
    if (explicitId) return explicitId
    const base = graphMailboxBase(source.mailbox_email)
    const parts = sourceFolderPathParts(source, forRead)
    if (!parts.length) return 'inbox'
    let currentId = null
    for (let i = 0; i < parts.length; i += 1) {
      const wanted = parts[i].toLowerCase()
      if (wanted === 'inbox' && i === 0) {
        currentId = 'inbox'
        continue
      }
      const children = await listChildMailFolders(base, currentId)
      const found = children.find((folder) => String(folder.displayName || '').toLowerCase() === wanted)
      if (!found) {
        const all = await listAllMailFoldersFlat(base)
        const flatFound = all.find((folder) => String(folder.displayName || '').toLowerCase() === wanted)
          || all.find((folder) => String(folder.displayName || '').toLowerCase().replace(/[^a-z0-9]/g, '') === wanted.replace(/[^a-z0-9]/g, ''))
        if (flatFound) return flatFound.id
        const available = all.map((folder) => folder.displayName).filter(Boolean).slice(0, 30).join(', ')
        throw new Error(`Could not find Outlook folder "${parts[i]}" for ${source.mailbox_email}. Available folders include: ${available || 'none returned'}. Add its Graph folder ID in settings or rename the setting to match Outlook.`)
      }
      currentId = found.id
    }
    return currentId || 'inbox'
  }

  async function listAllMailFoldersFlat(basePath) {
    const result = []
    const queue = await listChildMailFolders(basePath)
    while (queue.length) {
      const folder = queue.shift()
      result.push(folder)
      try {
        const children = await listChildMailFolders(basePath, folder.id)
        queue.push(...children)
      } catch {}
    }
    return result
  }


  async function listMessagesInMailFolder(basePath, folderId, maxMessages = 100) {
    const messages = []
    let next = `${basePath}/mailFolders/${encodeURIComponent(folderId)}/messages?$select=id,subject,receivedDateTime,from,bodyPreview,body,hasAttachments,inferenceClassification,webLink,conversationId,parentFolderId,isRead&$orderby=receivedDateTime desc&$top=50`
    while (next && messages.length < maxMessages) {
      const data = await graphFetch(next)
      messages.push(...(data.value || []))
      next = data['@odata.nextLink'] || ''
    }
    return messages.slice(0, maxMessages)
  }

  async function listMessageAttachments(basePath, messageId) {
    if (!messageId) return []
    try {
      const data = await graphFetch(`${basePath}/messages/${encodeURIComponent(messageId)}/attachments?$select=id,name,contentType,size,isInline&$top=25`)
      return (data.value || []).map((attachment) => ({
        id: attachment.id || '',
        name: attachment.name || 'Attachment',
        content_type: attachment.contentType || '',
        size: attachment.size || 0,
        is_inline: Boolean(attachment.isInline),
        content_url: attachment.content_url || '',
        content_loaded: Boolean(attachment.content_url)
      }))
    } catch (error) {
      console.warn('Could not load message attachments:', messageId, error)
      return []
    }
  }

  function nonInlineServiceAttachments(rowOrAttachments) {
    const attachments = Array.isArray(rowOrAttachments) ? rowOrAttachments : (rowOrAttachments?.attachments || [])
    return attachments.filter((item) => !item.is_inline)
  }

  function servicePdfAttachments(rowOrAttachments) {
    return nonInlineServiceAttachments(rowOrAttachments).filter((item) => /\.pdf$/i.test(item.name || '') || /pdf/i.test(item.content_type || ''))
  }

  function primaryServicePdfAttachment(rowOrAttachments) {
    return servicePdfAttachments(rowOrAttachments)[0] || nonInlineServiceAttachments(rowOrAttachments)[0] || null
  }

  async function loadMessageAttachmentContent(basePath, messageId, attachment) {
    if (!messageId || !attachment?.id) return attachment
    if (attachment.content_url) return attachment
    const full = await graphFetch(`${basePath}/messages/${encodeURIComponent(messageId)}/attachments/${encodeURIComponent(attachment.id)}`)
    const contentBytes = full.contentBytes || full.content_bytes || ''
    const contentType = full.contentType || attachment.content_type || 'application/pdf'
    const contentUrl = contentBytes ? `data:${contentType};base64,${contentBytes}` : ''
    return {
      ...attachment,
      name: full.name || attachment.name || 'Attachment',
      content_type: contentType,
      size: full.size || attachment.size || 0,
      content_url: contentUrl,
      content_loaded: Boolean(contentUrl)
    }
  }

  function latestMessagePerConversation(messages = []) {
    const byConversation = new Map()
    messages.forEach((message) => {
      const key = message.conversationId || message.id
      const existing = byConversation.get(key)
      if (!existing || new Date(message.receivedDateTime || 0) > new Date(existing.receivedDateTime || 0)) {
        byConversation.set(key, message)
      }
    })
    return Array.from(byConversation.values()).sort((a, b) => new Date(b.receivedDateTime || 0) - new Date(a.receivedDateTime || 0))
  }

  function normalizeCauseNumber(value = '') {
    return String(value || '').toLowerCase().replace(/[^a-z0-9]/g, '')
  }

  function matterPartySearchTerms(matter) {
    const terms = []
    const add = (value) => {
      const clean = String(value || '').trim()
      if (clean && clean.length > 2) terms.push(clean.toLowerCase())
    }
    add(matter.name || matter.matter_name || matter.case_name || matter.style)
    add(matter.cause_number || matter.cause || matter.case_number)
    const client = clients.find((clientItem) => String(clientItem.id) === String(matter.client_id))
    add(client?.name)
    add(client?.first_name && client?.last_name ? `${client.first_name} ${client.last_name}` : '')
    ;['client_name', 'opposing_party', 'opposing_party_name', 'opposingParty', 'other_party', 'respondent', 'petitioner'].forEach((field) => add(matter[field]))
    return [...new Set(terms)]
  }

  function inferServiceEmailMatter(message) {
    const haystackRaw = `${message.subject || ''} ${message.bodyPreview || ''} ${message.body?.content || ''}`
    const haystack = haystackRaw.toLowerCase()
    const normalizedHaystack = normalizeCauseNumber(haystackRaw)
    let best = { id: '', score: 0 }
    matters.forEach((matter) => {
      let score = 0
      const cause = matter.cause_number || matter.cause || matter.case_number || ''
      const normalizedCause = normalizeCauseNumber(cause)
      if (normalizedCause && normalizedCause.length >= 5 && normalizedHaystack.includes(normalizedCause)) score += 100
      matterPartySearchTerms(matter).forEach((term) => {
        const normalizedTerm = normalizeCauseNumber(term)
        if (term && haystack.includes(term)) score += Math.min(40, 10 + term.length)
        else if (normalizedTerm && normalizedTerm.length >= 5 && normalizedHaystack.includes(normalizedTerm)) score += 25
      })
      if (score > best.score) best = { id: matter.id, score }
    })
    return best.score >= 20 ? best.id : ''
  }

  function cleanEmailPreview(text = '') {
    return String(text || '')
      .replace(/\r/g, '\n')
      .replace(/-{2,}\s*Original Message[\s\S]*$/i, '')
      .replace(/From:\s.*\nSent:\s.*\nTo:\s.*[\s\S]*$/i, '')
      .replace(/\n\s*Ben Beveridge[\s\S]*$/i, '')
      .replace(/\n\s*Beveridge Law Firm[\s\S]*$/i, '')
      .replace(/\n\s*CONFIDENTIALITY NOTICE[\s\S]*$/i, '')
      .replace(/\n\s*This message.*confidential[\s\S]*$/i, '')
      .replace(/\n\s*Sent from my .*[\s\S]*$/i, '')
      .replace(/\s+/g, ' ')
      .trim()
  }

  function shortEmailPreview(text = '', maxLength = 180) {
    const cleaned = cleanEmailPreview(text)
    return cleaned.length > maxLength ? `${cleaned.slice(0, maxLength)}...` : cleaned
  }

  function htmlToPlainText(text = '') {
    return String(text || '')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/gi, ' ')
      .replace(/&amp;/gi, '&')
      .replace(/&lt;/gi, '<')
      .replace(/&gt;/gi, '>')
      .replace(/&#39;/gi, "'")
      .replace(/&quot;/gi, '"')
  }

  function decodeServiceHtmlEntity(value = '') {
    return String(value || '')
      .replace(/&amp;/gi, '&')
      .replace(/&lt;/gi, '<')
      .replace(/&gt;/gi, '>')
      .replace(/&#39;/gi, "'")
      .replace(/&quot;/gi, '"')
      .replace(/&nbsp;/gi, ' ')
  }

  function fileNameFromServiceUrl(url = '') {
    try {
      const parsed = new URL(url)
      const tail = decodeURIComponent((parsed.pathname || '').split('/').filter(Boolean).pop() || '')
      return tail && tail.includes('.') ? tail.replace(/[\/:*?"<>|]/g, ' ').slice(0, 160) : ''
    } catch {
      return ''
    }
  }

  function serviceDocumentNameFromLink(link) {
    if (!link) return ''
    const candidates = [link.name, link.label, fileNameFromServiceUrl(link.url)].map((value) => String(value || '').trim())
    const usable = candidates.find((value) => value && /\.pdf$/i.test(value))
      || candidates.find((value) => value && /pdf|document|download|filing|file[- ]?stamped/i.test(value) && !/^https?:/i.test(value))
      || ''
    if (!usable) return ''
    return usable
      .replace(/download\/select the pdf to fill this from the pdf name/ig, '')
      .replace(/[\\/:*?"<>|]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 160)
  }

  function extractServiceFilingLinks(html = '') {
    const text = String(html || '')
    const links = []
    const addLink = (url, label = '') => {
      const cleanUrl = decodeServiceHtmlEntity(url || '').trim()
      if (!/^https?:\/\//i.test(cleanUrl)) return
      if (links.some((item) => item.url === cleanUrl)) return
      const cleanLabel = decodeServiceHtmlEntity(String(label || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
      const guessedName = fileNameFromServiceUrl(cleanUrl)
      const lower = `${cleanUrl} ${cleanLabel}`.toLowerCase()
      const likelyPdf = lower.includes('.pdf') || lower.includes('document') || lower.includes('download') || lower.includes('efile') || lower.includes('tyler')
      links.push({
        id: `link-${links.length + 1}`,
        url: cleanUrl,
        label: cleanLabel || guessedName || (likelyPdf ? 'Download eFile document/PDF' : 'Open link'),
        name: guessedName || cleanLabel || (likelyPdf ? 'eFile document/PDF' : 'Link'),
        likely_pdf: likelyPdf
      })
    }

    const anchorRegex = /<a[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi
    let match
    while ((match = anchorRegex.exec(text))) addLink(match[1], match[2])

    const urlRegex = /(https?:\/\/[^\s"'<>]+)/gi
    while ((match = urlRegex.exec(text))) addLink(match[1], '')

    return links.filter((link) => link.likely_pdf || /efile|tyler|document|download|pdf/i.test(`${link.url} ${link.label}`)).slice(0, 10)
  }

  function primaryServiceFilingLink(rowOrLinks) {
    const links = Array.isArray(rowOrLinks) ? rowOrLinks : (rowOrLinks?.filing_links || [])
    return links.find((link) => link.likely_pdf) || links[0] || null
  }

  function isBenFiledEmailText(text = '') {
    const normalized = String(text || '').toLowerCase()
    return /filed\s+by\s*:?\s*(benjamin\s+beveridge|ben\s+beveridge)|filer\s*:?\s*(benjamin\s+beveridge|ben\s+beveridge)|submitted\s+by\s*:?\s*(benjamin\s+beveridge|ben\s+beveridge)|attorney\s+for\s+.*benjamin\s+beveridge/.test(normalized) || normalized.includes('ben beveridge') || normalized.includes('benjamin beveridge')
  }

  function serviceEmailReceivedDatePrefix(messageOrRow) {
    const date = (messageOrRow.receivedDateTime || messageOrRow.received_at) ? new Date(messageOrRow.receivedDateTime || messageOrRow.received_at) : new Date()
    const yy = String(date.getFullYear()).slice(-2)
    const mm = String(date.getMonth() + 1).padStart(2, '0')
    const dd = String(date.getDate()).padStart(2, '0')
    return `${yy}.${mm}.${dd}`
  }

  function extractAcceptedPdfNameFromEmailHtml(html = '') {
    const raw = String(html || '')
    const clean = (value) => decodeServiceHtmlEntity(String(value || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim())
      .replace(/[\\/:*?"<>|]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()

    const leadDocumentMatch = raw.match(/Lead\s+Document[\s\S]{0,800}?<t[dh][^>]*>([^<]*?\.pdf)\s*<\/t[dh]>/i)
      || raw.match(/Document\s+Details[\s\S]{0,1200}?([A-Z0-9][^<>\r\n]{2,180}\.pdf)/i)
      || htmlToPlainText(raw).match(/Lead\s+Document\s+([^\r\n]{2,180}\.pdf)/i)
      || htmlToPlainText(raw).match(/Document\s+Details[\s\S]{0,600}?([^\r\n]{2,180}\.pdf)/i)
    return leadDocumentMatch ? clean(leadDocumentMatch[1]) : ''
  }

  function enhanceServiceFilingLinksWithPdfName(links = [], html = '') {
    const extractedName = extractAcceptedPdfNameFromEmailHtml(html)
    if (!extractedName) return links
    return links.map((link) => {
      const label = String(link.label || link.name || '').toLowerCase()
      const url = String(link.url || '').toLowerCase()
      if (label.includes('download document') || label.includes('file stamped copy') || url.includes('viewdocuments') || url.includes('document')) {
        return { ...link, name: extractedName, fileName: extractedName, likely_pdf: true }
      }
      return link
    })
  }

  function cleanServicePdfBaseName(value = '') {
    const cleaned = String(value || '')
      .replace(/^\d{2}\.\d{2}\.\d{2}\s+/i, '')
      .replace(/^lead\s+document\s+/i, '')
      .replace(/^download\s*document\s*/i, '')
      .replace(/[\\/:*?"<>|]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
    return cleaned || 'efile-document.pdf'
  }

  function bestServiceLocalPdfBaseName(row = {}, file = {}) {
    const rowName = cleanServicePdfBaseName(row.extracted_pdf_name || '')
    const fileName = cleanServicePdfBaseName(file.name || '')
    const rowLooksBad = !rowName || /viewdocuments\.aspx|efile[- ]?document|download|select the pdf/i.test(rowName)
    return rowLooksBad ? (fileName || rowName || 'efile-document.pdf') : rowName
  }

  function ensurePdfExtension(name = '') {
    const clean = String(name || '').trim().replace(/\.+$/g, '')
    if (!clean) return 'efile-document.pdf'
    if (/\.pdf$/i.test(clean)) return clean
    return `${clean}.pdf`
  }

  function makeServicePdfDocumentName(rowOrMessage, baseName = '') {
    const pdfName = ensurePdfExtension(cleanServicePdfBaseName(baseName || rowOrMessage?.extracted_pdf_name || rowOrMessage?.suggested_document_name || 'efile-document.pdf'))
    return `${serviceEmailReceivedDatePrefix(rowOrMessage)} ${pdfName}`.replace(/[\/:*?"<>|]/g, ' ').replace(/\s+/g, ' ').trim()
  }

  function makeAcceptedDocumentName(message, attachments = [], filingLinks = [], html = '') {
    const attachment = primaryServicePdfAttachment(attachments)
    const attachmentName = attachment?.name ? String(attachment.name) : ''
    const extractedHtmlName = extractAcceptedPdfNameFromEmailHtml(html)
    const linkName = safeServiceDocumentNameFromLink(primaryServiceFilingLink(filingLinks))
    const baseName = attachmentName || extractedHtmlName || linkName || 'efile-document.pdf'
    return makeServicePdfDocumentName(message, baseName).slice(0, 190)
  }

  function serviceEmailFilingTagIds() {
    const normalized = (value) => String(value || '').toLowerCase().replace(/\s+/g, ' ').trim()
    const exact = tags.find((tag) => normalized(tagFullName(tag.id)) === 'filings > ours')
    if (exact) return tagAndParentIds([exact.id])
    const oursUnderFilings = tags.find((tag) => normalized(tag.name) === 'ours' && normalized(tagFullName(tag.parent_id)).endsWith('filings'))
    if (oursUnderFilings) return tagAndParentIds([oursUnderFilings.id])
    const ours = tags.find((tag) => normalized(tag.name) === 'ours')
    return ours ? tagAndParentIds([ours.id]) : []
  }

  function serviceEmailDocumentTagIds(row = null) {
    if (Array.isArray(row?.document_tag_ids) && row.document_tag_ids.length) return row.document_tag_ids
    return serviceEmailFilingTagIds()
  }

  function serviceEmailDocumentTagLabel(row = null) {
    const ids = serviceEmailDocumentTagIds(row)
    return ids.length ? ids.map((id) => tagFullName(id)).filter(Boolean).join(', ') : 'No tag selected'
  }

  function updateServiceEmailDocumentTag(rowId, tagId) {
    const tagIds = tagId ? tagAndParentIds([tagId]) : []
    setServiceEmailRows((rows) => rows.map((row) => row.id === rowId ? { ...row, document_tag_ids: tagIds } : row))
  }

  function serviceEmailDocumentLeafTagId(row = null) {
    const ids = serviceEmailDocumentTagIds(row)
    if (!ids.length) return ''
    return ids[ids.length - 1]
  }

  async function blobToDataUrl(blob) {
    return await new Promise((resolve, reject) => {
      const reader = new FileReader()
      reader.onload = () => resolve(reader.result || '')
      reader.onerror = reject
      reader.readAsDataURL(blob)
    })
  }

  async function createServiceEmailDocumentRecord(row, fileName, blob) {
    if (!row?.suggested_matter_id || !fileName) return null
    const alreadyExists = documents.some((doc) => doc.source_service_email_id === row.id && (doc.file_name === fileName || doc.name === fileName.replace(/\.pdf$/i, '')))
    if (alreadyExists) return null
    const dataUrl = blob ? await blobToDataUrl(blob) : ''
    const documentRecord = {
      id: `doc-${Date.now()}-${Math.random().toString(36).slice(2)}`,
      matter_id: row.suggested_matter_id,
      name: fileName.replace(/\.pdf$/i, ''),
      date: row.received_at ? new Date(row.received_at).toISOString().slice(0, 10) : dateToInputValue(new Date()),
      description: `Saved from Service Inbox: ${row.subject || ''}`,
      status: 'Ours',
      tag_ids: Array.isArray(row.document_tag_ids) && row.document_tag_ids.length ? tagAndParentIds(row.document_tag_ids) : serviceEmailFilingTagIds(),
      document_field_values: {},
      upload_date: dateToInputValue(new Date()),
      file_name: fileName,
      file_type: 'application/pdf',
      file_size: blob?.size || 0,
      file_data: dataUrl,
      file_data_url: dataUrl,
      source_service_email_id: row.id,
      source_outlook_message_id: row.outlook_message_id || '',
      source_mailbox_email: row.mailbox_email || serviceEmailMailboxAddress(row.source_id) || '',
      ...emptyDocumentAiReview
    }
    setDocuments((current) => [documentRecord, ...current])
    return documentRecord
  }

  function classifyLiveServiceEmail(source, message) {
    const fromEmail = message.from?.emailAddress?.address || ''
    const fromName = message.from?.emailAddress?.name || fromEmail || 'Unknown sender'
    const subject = message.subject || '(no subject)'
    const bodyPreview = message.bodyPreview || ''
    const bodyContent = message.body?.content || bodyPreview || ''
    const plainBody = htmlToPlainText(bodyContent || bodyPreview)
    const attachments = Array.isArray(message.attachments) ? message.attachments : []
    const filingLinks = enhanceServiceFilingLinksWithPdfName(extractServiceFilingLinks(bodyContent || bodyPreview || ''), bodyContent || bodyPreview || '')
    const combinedRaw = `${fromEmail} ${fromName} ${subject} ${bodyPreview} ${plainBody}`
    const combined = combinedRaw.toLowerCase()
    const sourceCategory = String(source.filing_category || '').toLowerCase()
    const subjectLower = subject.toLowerCase()
    const isEfile = combined.includes('efiletexas') || combined.includes('tylertech') || combined.includes('efilingmail') || combined.includes('efile') || /@efilingmail\./i.test(fromEmail)
    const startsFilingSubmitted = subjectLower.startsWith('filing submitted for case:')
    const startsFilingAccepted = subjectLower.startsWith('filing accepted for case:')
    const containsFilingSubmitted = combined.includes('filing submitted')
    const containsNotificationOfService = combined.includes('notification of service') || combined.includes('you have been served') || combined.includes('served with')
    const containsFilingAccepted = combined.includes('filing accepted') || combined.includes('file-stamped') || combined.includes('file stamped')
    const filedByMe = isBenFiledEmailText(combinedRaw)

    let actionGroup = 'response_mark_read'
    let confidence = 62

    if (startsFilingSubmitted && containsFilingSubmitted && filedByMe) {
      actionGroup = 'no_response'
      confidence = 94
    } else if (startsFilingSubmitted && containsNotificationOfService && !filedByMe) {
      actionGroup = 'notification_service'
      confidence = 95
    } else if (startsFilingAccepted && containsFilingAccepted && filedByMe) {
      actionGroup = 'accepted'
      confidence = 96
    } else if (isEfile && containsNotificationOfService) {
      actionGroup = 'notification_service'
      confidence = 88
    } else if (isEfile && containsFilingAccepted) {
      actionGroup = 'accepted'
      confidence = 88
    } else {
      const isNoReply = /no-reply|noreply|donotreply|do-not-reply/.test(fromEmail.toLowerCase())
      const clientHit = clients.some((client) => {
        const name = String(client.name || `${client.first_name || ''} ${client.last_name || ''}`).trim().toLowerCase()
        const email = String(client.email || '').toLowerCase()
        return (email && fromEmail.toLowerCase().includes(email)) || (name && combined.includes(name))
      })
      if ((isNoReply && !clientHit) || sourceCategory.includes('main inbox') || sourceCategory.includes('office inbox')) {
        actionGroup = isNoReply && !clientHit ? 'no_response' : 'response_mark_read'
        confidence = actionGroup === 'no_response' ? 80 : 62
      }
      if (sourceCategory.includes('file-stamped') || sourceCategory.includes('accepted')) {
        actionGroup = 'accepted'
        confidence = Math.max(confidence, 82)
      }
      if (sourceCategory.includes('incoming service') || sourceCategory.includes('notification')) {
        actionGroup = 'notification_service'
        confidence = Math.max(confidence, 82)
      }
    }

    const suggestedMatterId = inferServiceEmailMatter(message)
    const categoryLabel = serviceEmailPhaseLabel(actionGroup)
    const docName = actionGroup === 'accepted'
      ? makeAcceptedDocumentName(message, attachments, filingLinks, bodyContent || bodyPreview || '')
      : actionGroup === 'notification_service'
        ? `${subject.replace(/[\\/:*?"<>|]/g, ' ').slice(0, 90)}.pdf`
        : ''
    const summary = actionGroup === 'no_response'
      ? 'Predicted no response needed. Review the guess, then mark/move to Read.'
      : actionGroup === 'response_mark_read'
        ? 'Predicted response needed. Review/edit the draft, send the response, then move/mark as Read.'
        : actionGroup === 'accepted'
          ? 'Predicted accepted e-filed filing filed by this office. Review the extracted PDF/save path before moving to Read.'
          : 'Predicted notification of service filed by another party and served on this office. Review the extracted PDF/save path before moving to Read.'

    return {
      id: `live-${source.id}-${message.id}`,
      source_id: source.id,
      mailbox_email: source.mailbox_email || '',
      account_label: source.account_label || '',
      outlook_folder_name: source.outlook_folder_name || 'Inbox',
      read_folder_name: source.read_folder_name || 'Read',
      outlook_folder_id: source.outlook_folder_id || '',
      read_folder_id: source.read_folder_id || '',
      outlook_message_id: message.id,
      outlook_conversation_id: message.conversationId || '',
      outlook_parent_folder_id: message.parentFolderId || '',
      outlook_web_link: message.webLink || '',
      has_attachments: Boolean(message.hasAttachments) || attachments.length > 0 || filingLinks.length > 0,
      attachments,
      filing_links: filingLinks,
      received_at: message.receivedDateTime || new Date().toISOString(),
      from_name: fromName,
      from_email: fromEmail,
      subject,
      body_preview: cleanEmailPreview(plainBody || bodyPreview),
      filing_category: source.filing_category || 'Needs Review',
      action_group: actionGroup,
      suggested_action: actionGroup === 'no_response'
        ? 'No response needed. Mark/move to Read.'
        : actionGroup === 'response_mark_read'
          ? 'Draft/send a response, then mark/move to Read.'
          : `Review ${categoryLabel}, extract/save PDF to matter efile folder, bill time, then move to Read.`,
      suggested_matter_id: suggestedMatterId,
      suggested_document_name: docName,
      suggested_save_path: suggestedMatterId && matterEfileFolders[suggestedMatterId] ? matterEfileFolders[suggestedMatterId] : '',
      extracted_pdf_name: docName ? docName.replace(/^\d{2}\.\d{2}\.\d{2}\s+/, '') : (extractAcceptedPdfNameFromEmailHtml(bodyContent || bodyPreview || '') || safeServiceDocumentNameFromLink(primaryServiceFilingLink(filingLinks)) || ''),
      confidence: suggestedMatterId ? Math.max(confidence, 88) : confidence,
      status: 'needs_review',
      moved_to_read: false,
      selected: actionGroup === 'no_response',
      category_checked: actionGroup,
      phase_selected: false,
      billing_minutes: actionGroup === 'no_response' ? 0 : (source.default_billing_minutes ?? 6),
      draft_response: actionGroup === 'response_mark_read' ? `Thank you for your email. I have received it and will review it.\n\nBen` : '',
      proposed_actions: [
        { id: `move-${message.id}`, type: 'move_email', label: `Move Outlook email to ${source.read_folder_name || 'Read'}`, approved: true, completed: false }
      ],
      ai_summary: summary
    }
  }

  async function scanServiceEmailLive() {
    if (serviceGraphConfig.mode !== 'live') {
      scanServiceEmailMock()
      return
    }

    setServiceGraphBusy(true)
    try {
      await getMicrosoftGraphToken({ allowInteractive: false })
      const enabledSources = configuredServiceEmailSourcesForCurrentFilters()

      if (!enabledSources.length) {
        throw new Error('No enabled Outlook folders match the current email/folder filters. Choose All connected emails / All folders, or add/check a matching row in Service Email Settings.')
      }

      const liveRows = []
      const scannedSourceIds = new Set(enabledSources.map((source) => source.id))
      const skippedSources = []

      for (const source of enabledSources) {
        try {
          const base = graphMailboxBase(source.mailbox_email)
          const folderId = await resolveOutlookFolderId(source, false)
          const messages = await listMessagesInMailFolder(base, folderId, 100)
          const focusedMode = sourceUsesFocusedOrOther(source)
          const filteredMessages = messages.filter((message) => !focusedMode || String(message.inferenceClassification || '').toLowerCase() === focusedMode)
          const latestMessages = latestMessagePerConversation(filteredMessages)
          for (const message of latestMessages) {
            try {
              // Do not fetch every message's attachments during scan. Microsoft Graph
              // throttles shared mailboxes when many attachment requests happen at once.
              // Attachment/PDF details are loaded only when you preview or process a row.
              liveRows.push(classifyLiveServiceEmail({ ...source, outlook_folder_id: folderId }, { ...message, attachments: [] }))
            } catch (classifyError) {
              console.warn('Skipping one Outlook message during classification:', message?.subject, classifyError)
            }
          }
        } catch (error) {
          console.warn('Skipping Outlook source during scan:', source, error)
          skippedSources.push(`${source.account_label || source.mailbox_email || 'mailbox'} / ${source.outlook_folder_name || 'Inbox'}: ${error.message || error}`)
        }
      }

      if (!liveRows.length && skippedSources.length) {
        throw new Error(`No emails were scanned because every enabled folder failed. First skipped folder: ${skippedSources[0]}`)
      }

      setServiceEmailRows((rows) => {
        const priorByOutlookId = new Map(rows.map((row) => [row.outlook_message_id || row.id, row]))
        const mergedLiveRows = liveRows.map((row) => {
          const existing = priorByOutlookId.get(row.outlook_message_id)
          return { ...existing, ...row, selected: existing?.selected ?? row.selected, phase_selected: existing?.phase_selected ?? row.phase_selected }
        })

        const keepRows = rows.filter((row) => {
          if (row.status === 'completed' || row.moved_to_read) return false
          const isLive = String(row.id || '').startsWith('live-')
          if (!isLive) return true
          return !scannedSourceIds.has(row.source_id)
        })

        return [...mergedLiveRows, ...keepRows]
      })

      if (liveRows[0]) setSelectedServiceEmailId(liveRows[0].id)
      // PDF/attachment details load on demand when a row is opened or processed.
      // This prevents Microsoft Graph mailbox concurrency throttling.

      // After a live scan, show the user everything that came back instead of hiding it
      // behind the previous Status or action-group filter.
      setServiceInboxFilter('all')
      setServiceInboxPhase('all')
      setServiceInboxViewMode('grouped')
      setCollapsedServiceInboxSections({})

      setServiceEmailScanNote(`Scan complete. Found ${liveRows.length} live Outlook email(s) in ${enabledSources.length - skippedSources.length} configured folder(s).${skippedSources.length ? ` Skipped ${skippedSources.length} folder(s); first skipped: ${skippedSources[0]}` : ''}`)
      setPage('service_inbox')
    } catch (error) {
      console.error('Service email live scan failed:', error)
      setServiceEmailScanNote(`Service email live scan failed: ${error.message || error}`)
      alert(`Service email live scan failed: ${error.message || error}`)
    } finally {
      setServiceGraphBusy(false)
    }
  }

  async function testMicrosoftGraphConnection() {
    setServiceGraphBusy(true)
    try {
      const me = await graphFetch('/me?$select=displayName,userPrincipalName,mail', { allowInteractive: true })
      setServiceGraphAuth({ connected: true, account: { username: me.userPrincipalName || me.mail || '', name: me.displayName || '' }, connected_at: new Date().toISOString() })
      setServiceGraphConfig((config) => ({ ...config, mode: 'live' }))
      setServiceEmailScanNote(`Microsoft Graph test succeeded for ${me.displayName || me.userPrincipalName || me.mail}.`)
    } catch (error) {
      setServiceEmailScanNote(`Microsoft Graph test failed: ${error.message || error}`)
    } finally {
      setServiceGraphBusy(false)
    }
  }

  function recordServiceEmailAction(actionType, row, details = {}) {
    const billingMinutes = Number(details.billing_minutes ?? row?.billing_minutes ?? 0) || 0
    const matterId = details.matter_id ?? row?.suggested_matter_id ?? ''
    const entry = {
      id: crypto?.randomUUID ? crypto.randomUUID() : `svc-log-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      created_at: new Date().toISOString(),
      action_type: actionType,
      result: details.result || 'completed',
      email_subject: row?.subject || '',
      email_sender: row?.from_email || row?.from_name || '',
      mailbox_email: row?.mailbox_email || serviceEmailMailboxAddress(row?.source_id) || '',
      folder: row?.outlook_folder_name || serviceEmailSourceLabel(row?.source_id) || '',
      matter_id: matterId,
      matter: matterId ? matterLabel(matterId) : '',
      category: serviceEmailPhaseLabel(serviceEmailRowCategory(row)),
      billing_minutes: billingMinutes,
      document_name: details.document_name ?? row?.suggested_document_name ?? '',
      save_path: details.save_path ?? (row ? serviceEmailSavePath(row) : ''),
      notes: details.notes || ''
    }
    setServiceEmailActionLog((current) => [entry, ...current].slice(0, 500))
    return entry
  }

  function serviceEmailBillingSourceKey(row) {
    return row?.outlook_message_id || row?.id || `svc-${Date.now()}-${Math.random().toString(16).slice(2)}`
  }

  function billingMatterClientName(matterId) {
    const matter = matters.find((item) => String(item.id) === String(matterId))
    if (!matter) return ''
    return matterClientName(matter) || matter.client_name || matter.clients?.name || ''
  }

  function billingMatterClientId(matterId) {
    const matter = matters.find((item) => String(item.id) === String(matterId))
    return matter?.client_id || matter?.client?.id || matter?.clients?.id || ''
  }

  function billingClientMatchesSearch(entry, searchText) {
    const needle = String(searchText || '').trim().toLowerCase()
    if (!needle) return true
    const matter = matters.find((item) => String(item.id) === String(entry.matter_id)) || {}
    const client = clients.find((item) => String(item.id) === String(entry.client_id || matter.client_id)) || {}
    const haystack = [
      entry.client_name,
      billingMatterClientName(entry.matter_id),
      matter.matter_client_name,
      matter.client_name,
      client.first_name,
      client.last_name,
      client.email,
      billingMatterName(entry.matter_id)
    ].filter(Boolean).join(' ').toLowerCase()
    return haystack.includes(needle)
  }

  function billingMatterCauseNumber(matterId) {
    const matter = matters.find((item) => String(item.id) === String(matterId))
    return matter?.cause_number || matter?.cause || matter?.case_number || ''
  }

  function maybeCreateServiceEmailBillingEntry(row, descriptionPrefix = 'Service email review') {
    const minutes = Number(row?.billing_minutes || 0)
    if (!row?.suggested_matter_id || !minutes || minutes <= 0) return null
    const userId = currentBillingUserId()
    const rate = rateForBilling(userId, row.suggested_matter_id)
    const hours = Number((minutes / 60).toFixed(2))
    const sourceKey = serviceEmailBillingSourceKey(row)
    const entry = {
      id: crypto?.randomUUID ? crypto.randomUUID() : `billing-${Date.now()}-${Math.random().toString(16).slice(2)}`,
      matter_id: row.suggested_matter_id,
      task_id: '',
      user_id: userId,
      date: new Date().toISOString().slice(0, 10),
      description: `${descriptionPrefix}: ${row.subject || 'email'}`,
      matter_status: billingMatterStatus(row.suggested_matter_id),
      matter_step: 'Service Inbox',
      rate,
      billing_time: hours,
      amount: Number((hours * rate).toFixed(2)),
      source_service_email_id: sourceKey,
      source_service_email_row_id: row.id || '',
      source_outlook_message_id: row.outlook_message_id || '',
      source_service_subject: row.subject || '',
      client_name: billingMatterClientName(row.suggested_matter_id),
      cause_number: billingMatterCauseNumber(row.suggested_matter_id),
      created_at: new Date().toISOString()
    }
    let shouldSaveRelational = false
    setBillingEntries((current) => {
      const alreadyLogged = current.some((item) => (item.source_service_email_id && item.source_service_email_id === sourceKey) || (row.outlook_message_id && item.source_outlook_message_id === row.outlook_message_id))
      shouldSaveRelational = !alreadyLogged
      return alreadyLogged ? current : [entry, ...current]
    })
    if (shouldSaveRelational) saveBillingEntryToRelational(entry)
    return entry
  }

  async function markLiveRowRead(row) {
    if (!row?.outlook_message_id || String(row.outlook_message_id).startsWith('mock-')) return false
    const source = serviceEmailSource(row.source_id) || {
      id: row.source_id,
      mailbox_email: row.mailbox_email,
      outlook_folder_name: row.outlook_folder_name || 'Inbox',
      outlook_folder_id: row.outlook_folder_id,
      read_folder_name: row.read_folder_name || 'Read',
      read_folder_id: row.read_folder_id
    }
    if (!source?.mailbox_email) return false
    const base = graphMailboxBase(source.mailbox_email)
    await graphFetch(`${base}/messages/${encodeURIComponent(row.outlook_message_id)}`, {
      method: 'PATCH',
      body: JSON.stringify({ isRead: true })
    })
    return true
  }

  async function moveLiveRowToRead(row) {
    if (!row?.outlook_message_id || String(row.outlook_message_id).startsWith('mock-')) return false
    const configuredSource = serviceEmailSource(row.source_id)
    const source = {
      ...(configuredSource || {}),
      id: row.source_id || configuredSource?.id,
      mailbox_email: row.mailbox_email || configuredSource?.mailbox_email,
      outlook_folder_name: row.outlook_folder_name || configuredSource?.outlook_folder_name || 'Inbox',
      outlook_folder_id: row.outlook_folder_id || row.outlook_parent_folder_id || configuredSource?.outlook_folder_id || '',
      read_folder_name: row.read_folder_name || configuredSource?.read_folder_name || 'Read',
      read_folder_id: row.read_folder_id || configuredSource?.read_folder_id || ''
    }
    if (!source?.mailbox_email) return false
    const base = graphMailboxBase(source.mailbox_email)

    async function findDestinationId() {
      const configuredName = String(source.read_folder_name || '').trim()
      const candidates = [
        configuredName,
        configuredName && !configuredName.toLowerCase().startsWith('inbox') ? `Inbox / ${configuredName}` : '',
        'Inbox / Read',
        'Read',
        'Accepted (Read)',
        'Notification of Service (Read)'
      ].filter(Boolean)

      if (source.read_folder_id) return source.read_folder_id
      for (const name of candidates) {
        try {
          return await resolveOutlookFolderId({ ...source, read_folder_name: name, read_folder_id: '' }, true)
        } catch (error) {
          console.warn(`Read destination not found for candidate "${name}"`, error)
        }
      }
      throw new Error(`Could not find a Read destination folder for ${source.mailbox_email}. Set the exact Read folder name or Graph folder ID in Service Email Settings.`)
    }

    async function messageIdsToMoveFromSourceFolder() {
      const ids = new Set([row.outlook_message_id])
      const conversationId = String(row.outlook_conversation_id || '').trim()
      const sourceFolderId = source.outlook_folder_id || row.outlook_parent_folder_id || ''
      if (!conversationId || !sourceFolderId) return [...ids]

      try {
        // Prefer the messages that are currently still in the source folder. This avoids
        // trying to move old conversation messages that Outlook/Graph has already moved
        // and now reports as 404.
        const data = await graphFetch(`${base}/mailFolders/${encodeURIComponent(sourceFolderId)}/messages?$select=id,parentFolderId,conversationId&$top=100`)
        ;(data.value || []).forEach((message) => {
          if (message?.id && String(message.conversationId || '') === conversationId) ids.add(message.id)
        })
      } catch (error) {
        console.warn('Could not expand conversation move set; moving selected message only.', error)
      }
      return [...ids]
    }

    const destinationId = await findDestinationId()
    const body = JSON.stringify({ destinationId })
    const sourceFolderId = source.outlook_folder_id || row.outlook_parent_folder_id || ''
    const messageIds = await messageIdsToMoveFromSourceFolder()
    let movedAny = false
    let sawNotFound = false
    let lastError = null

    for (const messageId of messageIds) {
      try {
        await graphFetch(`${base}/messages/${encodeURIComponent(messageId)}`, {
          method: 'PATCH',
          body: JSON.stringify({ isRead: true })
        })
      } catch (error) {
        if (isGraphItemNotFound(error)) sawNotFound = true
        else console.warn('Mark read before move failed:', messageId, error)
      }

      const movePaths = [
        sourceFolderId ? `${base}/mailFolders/${encodeURIComponent(sourceFolderId)}/messages/${encodeURIComponent(messageId)}/move` : '',
        `${base}/messages/${encodeURIComponent(messageId)}/move`
      ].filter(Boolean)

      let movedThisMessage = false
      for (const path of movePaths) {
        try {
          await graphFetch(path, { method: 'POST', body })
          movedThisMessage = true
          movedAny = true
          break
        } catch (error) {
          lastError = error
          if (isGraphItemNotFound(error)) {
            sawNotFound = true
          } else {
            console.warn('Move attempt failed:', path, error)
          }
        }
      }

      if (!movedThisMessage && !sawNotFound) {
        throw new Error(lastError?.message || lastError || 'Move failed for unknown reason')
      }
    }

    // If Graph says the item is already gone from the source folder, treat that as
    // good enough for this review queue and remove the row from the app list.
    return movedAny || sawNotFound
  }

  async function sendLiveServiceEmailResponse(row) {
    if (!row?.draft_response || !row.from_email || String(row.outlook_message_id || '').startsWith('mock-')) return false
    const source = serviceEmailSource(row.source_id)
    const base = graphMailboxBase(source?.mailbox_email)
    await graphFetch(`${base}/sendMail`, {
      method: 'POST',
      body: JSON.stringify({
        message: {
          subject: `Re: ${row.subject || ''}`,
          body: { contentType: 'Text', content: row.draft_response },
          toRecipients: [{ emailAddress: { address: row.from_email, name: row.from_name || row.from_email } }]
        },
        saveToSentItems: true
      })
    })
    return true
  }

  function serviceEmailSource(sourceId) {
    return serviceEmailSources.find((item) => item.id === sourceId) || null
  }

  function serviceEmailSourceLabel(sourceId) {
    const source = serviceEmailSource(sourceId)
    return source ? source.outlook_folder_name : ''
  }

  function serviceEmailMailboxLabel(sourceId) {
    const source = serviceEmailSource(sourceId)
    return source ? (source.account_label || source.mailbox_email || '') : ''
  }

  function serviceEmailMailboxAddress(sourceId) {
    const source = serviceEmailSource(sourceId)
    return source ? (source.mailbox_email || '') : ''
  }

  function serviceEmailReadFolder(sourceId) {
    const source = serviceEmailSource(sourceId)
    return source ? source.read_folder_name : 'Read'
  }

  function serviceEmailKnownMatterPath(row) {
    if (!row?.suggested_matter_id) return ''
    return matterEfileFolders[row.suggested_matter_id] || ''
  }

  function sanitizeServiceEfilePath(value = '', row = null) {
    const matterName = row?.suggested_matter_id ? matterLabel(row.suggested_matter_id) : '{Matter}'
    return String(value || '')
      .replace(/\$\{handle\.name\}/g, '')
      .replace(/\{handle\.name\}/g, '')
      .replace(/\{Matter\}/g, matterName)
      .replace(/\{matter\}/g, matterName)
      .replace(/\\\s+/g, '\\')
      .replace(/\s+\\/g, '\\')
      .replace(/\\{2,}/g, '\\')
      .trim()
  }

  function serviceEmailSavePath(row) {
    const source = serviceEmailSource(row.source_id)
    const matterPath = serviceEmailKnownMatterPath(row)
    // A matter-specific path always wins over a generic row/source template.
    const rawPath = matterPath || row.suggested_save_path || source?.default_onedrive_folder || ''
    return sanitizeServiceEfilePath(rawPath, row)
  }

  function serviceEmailPathIsKnown(row) {
    const path = serviceEmailSavePath(row)
    return Boolean(path && !/\{Matter\}|\{matter\}|\$\{handle\.name\}|\{handle\.name\}/.test(path))
  }

  async function dataUrlToBlob(dataUrl = '') {
    if (!dataUrl) return null
    const response = await fetch(dataUrl)
    return await response.blob()
  }

  async function callMioLocalHelper(path, payload) {
    const response = await fetch(`${MIO_LOCAL_HELPER_URL}${path}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload || {})
    })
    let data = null
    try { data = await response.json() } catch { data = null }
    if (!response.ok || !data?.ok) {
      const message = data?.error || data?.message || `Local helper returned ${response.status}`
      throw new Error(message)
    }
    return data
  }

  async function saveServicePdfViaLocalHelper(row) {
    const currentRow = serviceEmailRows.find((item) => item.id === row?.id) || row
    if (!currentRow) return false
    const link = primaryServiceFilingLink(currentRow)
    if (!link?.url) throw new Error('No eFile PDF link was found on this row.')
    const targetDir = serviceEmailSavePath(currentRow)
    if (!targetDir || /\{Matter\}|\{matter\}|\$\{handle\.name\}|\{handle\.name\}/.test(targetDir)) {
      throw new Error('Set the Matter efile folder on this row first. The local helper needs the exact Windows folder path shown in the Matter efile folder field.')
    }
    const rowDocName = String(currentRow.suggested_document_name || '').trim()
    const baseName = cleanServicePdfBaseName(currentRow.extracted_pdf_name || safeServiceDocumentNameFromLink(link) || link.fileName || link.name || 'efile-document.pdf')
    const targetFileName = ensurePdfExtension(rowDocName || makeServicePdfDocumentName(currentRow, baseName))
      .replace(/[\/:*?"<>|]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()

    let result
    try {
      result = await callMioLocalHelper('/save-efile-pdf', {
        sourceUrl: link.url,
        targetDir,
        fileName: targetFileName,
        expectedPdfName: baseName,
        subject: currentRow.subject || '',
        receivedAt: currentRow.received_at || '',
        matterLabel: currentRow.suggested_matter_id ? matterLabel(currentRow.suggested_matter_id) : '',
        rowId: currentRow.id
      })
    } catch (error) {
      throw new Error(`Optional local save helper failed: ${error.message || error}. The online version can continue without the helper by using browser folder access.`)
    }

    const savedFileName = result.fileName || targetFileName
    const dataUrl = result.dataUrl || ''
    const blob = dataUrl ? await dataUrlToBlob(dataUrl) : new Blob([], { type: 'application/pdf' })
    const attachment = {
      id: `helper-${Date.now()}`,
      name: savedFileName,
      content_type: 'application/pdf',
      size: result.size || blob.size || 0,
      is_inline: false,
      content_url: dataUrl,
      content_loaded: Boolean(dataUrl),
      blob
    }

    await createServiceEmailDocumentRecord({
      ...currentRow,
      suggested_document_name: savedFileName,
      extracted_pdf_name: cleanServicePdfBaseName(savedFileName),
      document_tag_ids: serviceEmailDocumentTagIds(currentRow)
    }, savedFileName, blob)

    setServiceEmailRows((rows) => rows.map((item) => item.id === currentRow.id ? {
      ...item,
      extracted_pdf_name: cleanServicePdfBaseName(savedFileName),
      suggested_document_name: savedFileName,
      saved_pdf_name: savedFileName,
      saved_pdf_at: new Date().toISOString(),
      saved_pdf_path: result.savedPath || `${targetDir}\\${savedFileName}`,
      has_attachments: true,
      attachments: [attachment, ...((item.attachments || []).filter((att) => (att.id || att.name) !== (attachment.id || attachment.name)))]
    } : item))
    if (dataUrl) {
      setSelectedPdfPreviewName(savedFileName)
      setSelectedPdfPreviewUrl(dataUrl)
    }
    setServiceEmailScanNote(`Saved ${savedFileName} to ${targetDir} and added it to Documents with tag: ${serviceEmailDocumentTagLabel(currentRow)}.`)
    return { ok: true, fileName: savedFileName, savedPath: result.savedPath || `${targetDir}\\${savedFileName}`, documentTagLabel: serviceEmailDocumentTagLabel(currentRow), size: result.size || blob.size || 0 }
  }

  async function promptForMatterEfileFolder(rowId) {
    const row = serviceEmailRows.find((item) => item.id === rowId)
    if (!row) return
    if (!row.suggested_matter_id) {
      alert('Pick the matter first, then choose its efile folder path.')
      return
    }
    const current = serviceEmailSavePath(row) || `C:\\Users\\bever\\OneDrive - Beveridge Law Firm, PLLC\\All Matters\\1. Open Cases\\${matterLabel(row.suggested_matter_id)}\\efile`
    let next = ''

    let selectedDirectoryHandle = null
    if (window.showDirectoryPicker) {
      try {
        selectedDirectoryHandle = await window.showDirectoryPicker({ mode: 'readwrite' })
        next = window.prompt(`Chrome confirmed you selected folder: ${selectedDirectoryHandle?.name || 'folder'}.\n\nFor security, Chrome does not reveal the full Windows path automatically. Paste or confirm the full OneDrive efile folder path for display/logging only. The app will save PDFs to the folder you just selected.\n\nMatter:\n${matterLabel(row.suggested_matter_id)}`, current) || current
      } catch (error) {
        if (error?.name === 'AbortError') return
      }
    }

    if (!next) {
      next = window.prompt(`Paste or type the OneDrive efile folder path for:\n${matterLabel(row.suggested_matter_id)}`, current) || ''
    }
    next = sanitizeServiceEfilePath(next, row)
    if (!next) return
    setMatterEfileFolders((folders) => ({ ...folders, [row.suggested_matter_id]: next }))
    if (selectedDirectoryHandle) {
      rememberServiceEfileFolderHandle(row.suggested_matter_id, rowId, selectedDirectoryHandle)
    }
    setServiceEmailRows((rows) => rows.map((item) => item.id === rowId ? { ...item, suggested_save_path: next } : item))
    setServiceEmailScanNote(`Saved efile folder for ${matterLabel(row.suggested_matter_id)}. PDFs will save to the selected folder you chose, not the Case Controller Mio app folder.`)
  }

  function openServiceEmailInOutlook(row) {
    if (row?.outlook_web_link) {
      window.open(row.outlook_web_link, '_blank', 'noopener,noreferrer')
      return
    }
    setSelectedServiceEmailId(row?.id || '')
    setServiceEmailScanNote('This email does not have an Outlook web link. Showing it in the preview panel instead.')
  }

  function openServiceAttachmentPreview(rowId, attachment) {
    setSelectedPdfPreviewName(attachment?.name || 'Attachment')
    setSelectedPdfPreviewUrl(attachment?.content_url || '')
    if (attachment?.content_url) window.open(attachment.content_url, '_blank', 'noopener,noreferrer')
    else setServiceEmailScanNote('Attachment name is available. Use an accepted/notification row so the app can download the PDF content from Microsoft Graph before previewing it.')
  }

  async function ensureAcceptedRowPdf(rowId) {
    const row = serviceEmailRows.find((item) => item.id === rowId)
    if (!row || !row.outlook_message_id || String(row.outlook_message_id).startsWith('mock-')) return
    try {
      const source = serviceEmailSource(row.source_id) || row
      const base = graphMailboxBase(row.mailbox_email || source.mailbox_email)
      let attachments = row.attachments || []
      if (!attachments.length && row.outlook_message_id) attachments = await listMessageAttachments(base, row.outlook_message_id)
      const primary = primaryServicePdfAttachment(attachments)
      let updatedAttachments = attachments
      let loadedPrimary = primary
      if (primary?.id && !primary.content_url) {
        loadedPrimary = await loadMessageAttachmentContent(base, row.outlook_message_id, primary)
        updatedAttachments = attachments.map((item) => item.id === primary.id ? loadedPrimary : item)
      }
      const link = primaryServiceFilingLink(row)
      const fallbackName = row.extracted_pdf_name || link?.fileName || link?.name || fileNameFromServiceUrl(link?.url || '') || ''
      const docName = loadedPrimary?.name
        ? `${serviceEmailReceivedDatePrefix(row)} ${String(loadedPrimary.name).replace(/[\/:*?"<>|]/g, ' ').slice(0, 160)}`
        : (fallbackName ? `${serviceEmailReceivedDatePrefix(row)} ${String(fallbackName).replace(/[\/:*?"<>|]/g, ' ').slice(0, 160)}` : '')
      setServiceEmailRows((rows) => rows.map((item) => item.id === rowId ? {
        ...item,
        has_attachments: updatedAttachments.length > 0 || item.has_attachments || Boolean(link),
        attachments: updatedAttachments,
        extracted_pdf_name: loadedPrimary?.name || item.extracted_pdf_name || fallbackName || '',
        suggested_document_name: docName || item.suggested_document_name || ''
      } : item))
      if (loadedPrimary?.name) {
        setSelectedPdfPreviewName(loadedPrimary.name)
        setSelectedPdfPreviewUrl(loadedPrimary.content_url || '')
      }
      return loadedPrimary || null
    } catch (error) {
      console.warn('Could not download accepted e-service PDF yet:', error)
      setServiceEmailScanNote(`Could not download PDF for the accepted row yet: ${error.message || error}`)
      return null
    }
  }

  async function downloadServiceFilingLink(row, options = {}) {
    const link = primaryServiceFilingLink(row)
    if (!link?.url) {
      setServiceEmailScanNote('No eFile download link was found in this email. Open the email in Outlook and confirm the blue Download Document link is visible in the message body.')
      return null
    }
    const guessedName = row.extracted_pdf_name || safeServiceDocumentNameFromLink(link) || link.fileName || link.name || 'efile-document.pdf'
    const safeName = cleanServicePdfBaseName(guessedName)
    try {
      const response = await fetch(link.url, { credentials: 'include' })
      if (!response.ok) throw new Error(`Download returned ${response.status}`)
      const blob = await response.blob()
      const type = blob.type || 'application/pdf'
      const objectUrl = URL.createObjectURL(blob)
      const attachment = {
        id: `downloaded-${Date.now()}`,
        name: safeName,
        content_type: type,
        size: blob.size,
        is_inline: false,
        content_url: objectUrl,
        content_loaded: true,
        blob
      }
      const docName = makeServicePdfDocumentName(row, safeName)
      setServiceEmailRows((rows) => rows.map((item) => item.id === row.id ? {
        ...item,
        has_attachments: true,
        attachments: [attachment, ...((item.attachments || []).filter((att) => att.id !== attachment.id && att.name !== attachment.name))],
        extracted_pdf_name: safeName,
        suggested_document_name: docName || item.suggested_document_name
      } : item))
      setSelectedPdfPreviewName(safeName)
      setSelectedPdfPreviewUrl(objectUrl)
      setServiceEmailScanNote(`Downloaded ${safeName}. Review it, then save/process it.`)
      return attachment
    } catch (error) {
      console.warn('Could not fetch eFile link directly:', error)
      if (options.openOnFail !== false) {
        window.open(link.url, '_blank', 'noopener,noreferrer')
        setServiceEmailScanNote(`Opened the eFile link in a new window because the browser blocked direct download here (${error.message || error}). If you manually save from that window, Chrome controls the Save As folder. To let Case Controller save directly, use Browse/set and a link that can be fetched by the browser or add a backend download helper later.`)
      } else {
        setServiceEmailScanNote(`Could not download the eFile PDF directly from the link: ${error.message || error}. The app did not open Save As because that would save to Chrome's default folder.`)
      }
      return null
    }
  }

  async function pickLocalServicePdfAttachment(row) {
    try {
      const targetName = ensurePdfExtension(String(row?.suggested_document_name || makeServicePdfDocumentName(row, row?.extracted_pdf_name || 'efile-document.pdf')).trim())
      const targetFolder = serviceEmailSavePath(row) || '(the Matter efile folder shown on this row)'
      window.alert(`Case Controller could not directly read the eFile PDF link, so Chrome needs you to select the already-downloaded PDF as the SOURCE FILE.\n\nDo not type a new filename here. Pick the PDF that was downloaded from the eFile link.\n\nAfter you pick it, Case Controller will copy it as:\n${targetName}\n\nInto:\n${targetFolder}`)
      let file = null
      if (window.showOpenFilePicker) {
        const [handle] = await window.showOpenFilePicker({
          multiple: false,
          startIn: 'downloads',
          types: [{ description: 'PDF files', accept: { 'application/pdf': ['.pdf'] } }]
        })
        file = await handle.getFile()
      } else {
        file = await new Promise((resolve) => {
          const input = document.createElement('input')
          input.type = 'file'
          input.accept = 'application/pdf'
          input.style.display = 'none'
          input.onchange = () => resolve(input.files && input.files[0] ? input.files[0] : null)
          document.body.appendChild(input)
          input.click()
          setTimeout(() => { try { document.body.removeChild(input) } catch {} }, 1000)
        })
      }
      if (!file) return null
      const objectUrl = URL.createObjectURL(file)
      const safeName = bestServiceLocalPdfBaseName(row, file)
      const attachment = {
        id: `local-${Date.now()}`,
        name: safeName,
        content_type: file.type || 'application/pdf',
        size: file.size || 0,
        is_inline: false,
        content_url: objectUrl,
        content_loaded: true,
        blob: file
      }
      const docName = makeServicePdfDocumentName(row, safeName)
      setServiceEmailRows((rows) => rows.map((item) => item.id === row.id ? {
        ...item,
        has_attachments: true,
        attachments: [attachment, ...((item.attachments || []).filter((att) => att.id !== attachment.id && att.name !== attachment.name))],
        extracted_pdf_name: safeName,
        suggested_document_name: docName
      } : item))
      setSelectedPdfPreviewName(safeName)
      setSelectedPdfPreviewUrl(objectUrl)
      setServiceEmailScanNote(`Selected ${safeName}. The app can now save it to the matter efile folder.`)
      return attachment
    } catch (error) {
      if (error?.name !== 'AbortError') setServiceEmailScanNote(`Could not select the local PDF: ${error.message || error}`)
      return null
    }
  }

  async function ensureServiceEmailDirectoryHandle(row) {
    const matterHandleKey = row?.suggested_matter_id ? String(row.suggested_matter_id) : ''
    const rowHandleKey = row?.id ? String(row.id) : ''
    let directoryHandle = (rowHandleKey && serviceEmailRowFolderHandlesRef.current[rowHandleKey])
      || (matterHandleKey && matterEfileFolderHandlesRef.current[matterHandleKey])
      || (matterHandleKey && matterEfileFolderHandles[row.suggested_matter_id])
      || null

    const verifyHandle = async (handle) => {
      if (!handle?.getFileHandle) return false
      try {
        if (handle.queryPermission) {
          let permission = await handle.queryPermission({ mode: 'readwrite' })
          if (permission !== 'granted' && handle.requestPermission) permission = await handle.requestPermission({ mode: 'readwrite' })
          return permission === 'granted'
        }
        return true
      } catch {
        return false
      }
    }

    if (await verifyHandle(directoryHandle)) return directoryHandle

    if (!window.showDirectoryPicker) {
      throw new Error('Chrome did not provide folder access. Use Chrome or Edge and click Browse/set to choose the actual matter efile folder.')
    }

    const displayPath = serviceEmailSavePath(row) || (row?.suggested_matter_id ? `C:\\Users\\bever\\OneDrive - Beveridge Law Firm, PLLC\\All Matters\\1. Open Cases\\${matterLabel(row.suggested_matter_id)}\\efile` : '')
    const shouldPick = window.confirm(`Choose the actual matter efile folder where this PDF should be saved.\n\nMatter:\n${row?.suggested_matter_id ? matterLabel(row.suggested_matter_id) : '(matter not selected)'}\n\nDisplay path:\n${displayPath || '(not set)'}`)
    if (!shouldPick) throw new Error('No matter efile folder was selected.')
    directoryHandle = await window.showDirectoryPicker({ mode: 'readwrite' })
    rememberServiceEfileFolderHandle(row?.suggested_matter_id, row?.id, directoryHandle)

    if (row?.suggested_matter_id) {
      const nextPath = window.prompt(
        `Chrome allowed Case Controller to write to the selected folder: ${directoryHandle?.name || 'selected folder'}.\n\nFor the row display, settings, and log, paste or confirm the full Windows path for this matter efile folder. This text does not control where Chrome writes; the selected folder permission does.`,
        displayPath
      ) || displayPath
      const cleanPath = sanitizeServiceEfilePath(nextPath, row)
      if (cleanPath) {
        setMatterEfileFolders((folders) => ({ ...folders, [row.suggested_matter_id]: cleanPath }))
        setServiceEmailRows((rows) => rows.map((item) => item.id === row.id ? { ...item, suggested_save_path: cleanPath } : item))
      }
    }
    return directoryHandle
  }

  async function saveDownloadedServicePdf(row, providedAttachment = null, options = {}) {
    const currentRow = serviceEmailRows.find((item) => item.id === row?.id) || row
    if (!currentRow) return false

    // Online hosting workflow: do not require the old local Node helper.
    // The app now uses Microsoft Graph/browser file access first. The local helper
    // remains available only as an optional legacy fallback if it is explicitly enabled
    // in serviceGraphConfig.useLocalHelper.
    const shouldUseLegacyLocalHelper = serviceGraphConfig?.useLocalHelper === true && options.preferLocalHelper === true
    if (!providedAttachment && shouldUseLegacyLocalHelper && primaryServiceFilingLink(currentRow)?.url) {
      try {
        return await saveServicePdfViaLocalHelper(currentRow)
      } catch (helperError) {
        console.warn('Optional local PDF save helper failed:', helperError)
        if (options.localHelperOnly) throw helperError
        setServiceEmailScanNote(`Optional local helper was unavailable, so Case Controller will use the browser/Graph save flow instead: ${helperError.message || helperError}`)
      }
    }

    let attachment = providedAttachment || primaryServicePdfAttachment(currentRow)

    // If the row has a real Graph PDF attachment but the bytes are not loaded yet,
    // load it before falling back to any file picker. This lets Save PDF + move
    // use the row's existing PDF, row document name, and row matter folder directly.
    if (attachment?.id && !attachment?.blob && !attachment?.file && !attachment?.content_url && currentRow?.outlook_message_id) {
      try {
        const source = serviceEmailSource(currentRow.source_id) || currentRow
        const base = graphMailboxBase(currentRow.mailbox_email || source.mailbox_email)
        attachment = await loadMessageAttachmentContent(base, currentRow.outlook_message_id, attachment)
      } catch (error) {
        console.warn('Could not load Graph PDF attachment before save:', error)
      }
    }

    // Accepted/service emails usually contain a Tyler/eFile link plus helper files. If the actual
    // PDF content is not already loaded, let the user choose the PDF they just downloaded/opened.
    // Browser security does not let a normal React page silently read files from Downloads.
    if (!attachment?.blob && !attachment?.file && !attachment?.content_url && options.tryDirectDownload === true && primaryServiceFilingLink(currentRow)) {
      attachment = await downloadServiceFilingLink(currentRow, { openOnFail: false })
    }
    if (!attachment?.blob && !attachment?.file && !attachment?.content_url && options.allowPick !== false) {
      attachment = await pickLocalServicePdfAttachment(currentRow)
    }
    if (!attachment?.blob && !attachment?.file && !attachment?.content_url) {
      setServiceEmailScanNote('The PDF was not saved because no PDF was selected or loaded. Click the PDF link/open eFile PDF first if needed, then click Save PDF + move and choose that PDF. Case Controller will rename it and copy it into the selected matter efile folder.')
      return false
    }

    // Build the target name ONLY from the row's document name / eFile PDF name. Do not keep
    // Chrome's downloaded filename if the row already knows the right date-prefixed filename.
    const attachmentSourceName = attachment?.name || attachment?.file?.name || attachment?.blob?.name || ''
    const bestBaseName = cleanServicePdfBaseName(
      currentRow.extracted_pdf_name ||
      attachmentSourceName ||
      currentRow.suggested_document_name ||
      'efile-document.pdf'
    )
    const rowDocName = String(currentRow.suggested_document_name || '').trim()
    const rowDocNameIsUsable = /^\d{2}\.\d{2}\.\d{2}\s+.+\.pdf$/i.test(rowDocName)
      && !/viewdocuments\.aspx|efile[- ]?document|download|select the pdf/i.test(rowDocName)
    const fileName = ensurePdfExtension(rowDocNameIsUsable ? rowDocName : makeServicePdfDocumentName(currentRow, bestBaseName))
      .replace(/[\\/:*?"<>|]/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()

    let blob = attachment.blob || attachment.file || null
    if (!blob && attachment.content_url) {
      const response = await fetch(attachment.content_url)
      if (!response.ok) throw new Error(`Could not read selected PDF content (${response.status}).`)
      blob = await response.blob()
    }
    if (!blob) {
      setServiceEmailScanNote('The PDF was not saved because the selected PDF file could not be read.')
      return false
    }

    try {
      const directoryHandle = await ensureServiceEmailDirectoryHandle(currentRow)
      if (!directoryHandle?.getFileHandle) throw new Error('No folder permission was available after Browse/set.')

      // IMPORTANT: Do not use Chrome's Save As dialog here. It ignores/changes the target folder
      // too often and confuses the filename. We already have permission to the selected efile
      // folder, so write the PDF directly there with the exact row filename.
      const targetHandle = await directoryHandle.getFileHandle(fileName, { create: true })
      const writable = await targetHandle.createWritable()
      await writable.write(blob)
      await writable.close()

      await createServiceEmailDocumentRecord({
        ...currentRow,
        suggested_document_name: fileName,
        extracted_pdf_name: bestBaseName,
        document_tag_ids: serviceEmailDocumentTagIds(currentRow)
      }, fileName, blob)

      setServiceEmailRows((rows) => rows.map((item) => item.id === currentRow.id ? {
        ...item,
        extracted_pdf_name: bestBaseName,
        suggested_document_name: fileName,
        saved_pdf_name: fileName,
        saved_pdf_at: new Date().toISOString(),
        has_attachments: true,
        attachments: [attachment, ...((item.attachments || []).filter((att) => (att.id || att.name) !== (attachment.id || attachment.name)))]
      } : item))
      setServiceEmailScanNote(`Saved ${fileName} to the selected matter efile folder and added it to Documents with tag: ${serviceEmailDocumentTagLabel(currentRow)}.`)
      return true
    } catch (error) {
      if (error?.name !== 'AbortError') setServiceEmailScanNote(`Could not save PDF to the selected matter folder: ${error.message || error}`)
      return false
    }
  }

  async function openServiceRowPdf(row) {
    if (!row) return
    let attachment = primaryServicePdfAttachment(row)
    if (!attachment?.content_url && (serviceEmailRowCategory(row) === 'accepted' || serviceEmailRowCategory(row) === 'notification_service')) {
      attachment = await ensureAcceptedRowPdf(row.id)
    }
    if (attachment?.content_url) {
      openServiceAttachmentPreview(row.id, attachment)
    } else if (attachment?.name) {
      setSelectedPdfPreviewName(attachment.name)
      setSelectedPdfPreviewUrl('')
      setServiceEmailScanNote('Found the PDF name. The PDF content was not returned by Microsoft Graph yet, so the viewer cannot open it yet.')
    } else {
      const link = primaryServiceFilingLink(row)
      if (link?.url) {
        await downloadServiceFilingLink(row)
      } else {
        setServiceEmailScanNote('No PDF attachment or eFile download link was found for this email yet. Open the email in Outlook to inspect the filing link.')
      }
    }
  }

  function updateServiceEmailRowMatter(rowId, matterId) {
    setServiceEmailRows((rows) => rows.map((row) => {
      if (row.id !== rowId) return row
      const matterPath = matterId ? matterEfileFolders[matterId] : ''
      return { ...row, suggested_matter_id: matterId, suggested_save_path: matterPath || '' }
    }))
  }

  function updateServiceEmailRowSavePath(rowId, value) {
    setServiceEmailRows((rows) => rows.map((row) => {
      if (row.id !== rowId) return row
      if (row.suggested_matter_id && value) {
        setMatterEfileFolders((folders) => ({ ...folders, [row.suggested_matter_id]: value }))
      }
      return { ...row, suggested_save_path: value }
    }))
  }

  function serviceEmailRowMailboxLabel(row) {
    const source = serviceEmailSource(row.source_id)
    return source?.account_label || row.account_label || row.mailbox_email || serviceEmailMailboxAddress(row.source_id) || ''
  }

  function serviceEmailRowFolderLabel(row) {
    const source = serviceEmailSource(row.source_id)
    return source?.outlook_folder_name || row.outlook_folder_name || 'Inbox'
  }

  function serviceEmailPhaseLabel(value) {
    if (value === 'response_mark_read' || value === 'response_non_client' || value === 'client_response') return 'Respond / mark as Read'
    if (value === 'accepted' || value === 'filing_review') return 'Accepted'
    if (value === 'notification_service') return 'Notification of service'
    return 'No response / mark as Read'
  }

  function serviceEmailPhaseDescription(value) {
    if (value === 'response_mark_read' || value === 'response_non_client' || value === 'client_response') return 'Emails that need a response. Review/edit the draft rows, then send the response and move/mark as Read.'
    if (value === 'accepted' || value === 'filing_review') return 'Accepted e-filed filings filed by this office. Review the email/PDF/save path, then process and move to Read.'
    if (value === 'notification_service') return 'Notifications of service filed by someone else and served on this office. Review for matter match, PDFs, deadlines, and save path.'
    return 'Emails that do not need a response. Review the guess, then mark/move them to Read.'
  }

  const serviceEmailCategoryValues = ['no_response', 'response_mark_read', 'accepted', 'notification_service']

  function serviceEmailCategoryColor(value) {
    if (value === 'response_mark_read' || value === 'response_non_client' || value === 'client_response') return '#fff7ed'
    if (value === 'accepted' || value === 'filing_review') return '#eff6ff'
    if (value === 'notification_service') return '#f0fdf4'
    return '#f3f4f6'
  }

  function normalizedServiceEmailActionGroup(value) {
    if (value === 'response_non_client' || value === 'client_response') return 'response_mark_read'
    if (value === 'filing_review') return 'accepted'
    if (value === 'notification_service') return 'notification_service'
    if (value === 'accepted') return 'accepted'
    if (value === 'no_response') return 'no_response'
    return ''
  }

  function serviceEmailRowCategory(row) {
    const raw = row?.category_checked ?? row?.action_group ?? ''
    return normalizedServiceEmailActionGroup(raw) || 'no_response'
  }

  function clearServiceEmailRowCategory(rowId) {
    setServiceEmailRowCategory(rowId, 'no_response')
  }

  function updateServiceEmailRow(rowId, patch) {
    setServiceEmailRows((rows) => rows.map((row) => row.id === rowId ? { ...row, ...patch } : row))
  }

  function toggleServiceEmailSelected(rowId, checked) {
    updateServiceEmailRow(rowId, { selected: checked })
  }


  function toggleServiceEmailPhaseSelected(rowId, checked) {
    updateServiceEmailRow(rowId, { phase_selected: checked })
  }

  function setVisibleServiceEmailSelected(checked) {
    const visibleIds = new Set(serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed').map((row) => row.id))
    setServiceEmailRows((rows) => rows.map((row) => visibleIds.has(row.id) ? { ...row, selected: checked } : row))
  }

  function setVisibleServiceEmailPhaseSelected(checked) {
    const visibleIds = new Set(serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed').map((row) => row.id))
    setServiceEmailRows((rows) => rows.map((row) => visibleIds.has(row.id) ? { ...row, phase_selected: checked } : row))
  }

  function changeSelectedServiceEmailPhase(actionGroup) {
    const normalizedActionGroup = normalizedServiceEmailActionGroup(actionGroup)
    const visibleIds = new Set(serviceEmailRowsForCurrentView().filter((row) => row.phase_selected && row.status !== 'completed').map((row) => row.id))
    if (!visibleIds.size) {
      setServiceInboxPhase(normalizedActionGroup)
      return
    }
    setServiceEmailRows((rows) => rows.map((row) => {
      if (!visibleIds.has(row.id)) return row
      const noResponse = normalizedActionGroup === 'no_response'
      const needsResponse = normalizedActionGroup === 'response_mark_read'
      return {
        ...row,
        action_group: normalizedActionGroup,
        category_checked: normalizedActionGroup,
        selected: noResponse,
        phase_selected: false,
        billing_minutes: noResponse ? 0 : (row.billing_minutes || 6),
        draft_response: needsResponse ? (row.draft_response || `Thank you for your email. I have received it and will review it.\n\nBen`) : '',
        suggested_action: serviceEmailPhaseDescription(normalizedActionGroup),
        proposed_actions: [
          { id: `move-${row.outlook_message_id || row.id}`, type: 'move_email', label: `Move Outlook email to ${serviceEmailReadFolder(row.source_id) || 'Read'}`, approved: true, completed: false }
        ]
      }
    }))
    setServiceInboxPhase('all')
    setServiceEmailScanNote(`Changed ${visibleIds.size} selected email(s) to ${serviceEmailPhaseLabel(normalizedActionGroup)}.`)
  }


  function setServiceEmailRowCategory(rowId, actionGroup) {
    const normalized = normalizedServiceEmailActionGroup(actionGroup)
    if (!normalized) {
      clearServiceEmailRowCategory(rowId)
      return
    }
    setServiceEmailRows((rows) => rows.map((row) => {
      if (row.id !== rowId) return row
      const noResponse = normalized === 'no_response'
      return {
        ...row,
        action_group: normalized,
        category_checked: normalized,
        selected: noResponse,
        billing_minutes: noResponse ? 0 : (row.billing_minutes || 6),
        draft_response: normalized === 'response_mark_read' ? (row.draft_response || `Thank you for your email. I have received it and will review it.\n\nBen`) : '',
        suggested_action: serviceEmailPhaseDescription(normalized)
      }
    }))
  }


  function handleServiceEmailCategoryCheckbox(rowId, category, checked) {
    if (checked) {
      setServiceEmailRowCategory(rowId, category)
    } else {
      // Keep one category checked on every row. If a checked category is cleared,
      // put the email back in the safe default no-response bucket.
      setServiceEmailRowCategory(rowId, 'no_response')
    }
  }

  function setServiceEmailRowsCategory(rowIds, actionGroup) {
    const ids = new Set(rowIds)
    const normalized = normalizedServiceEmailActionGroup(actionGroup)
    setServiceEmailRows((rows) => rows.map((row) => {
      if (!ids.has(row.id) || row.status === 'completed') return row
      if (!normalized) {
        const noResponse = true
        return {
          ...row,
          action_group: 'no_response',
          category_checked: 'no_response',
          selected: noResponse,
          billing_minutes: 0,
          suggested_action: serviceEmailPhaseDescription('no_response')
        }
      }
      const noResponse = normalized === 'no_response'
      return {
        ...row,
        action_group: normalized,
        category_checked: normalized,
        selected: noResponse,
        billing_minutes: noResponse ? 0 : (row.billing_minutes || 6),
        draft_response: normalized === 'response_mark_read' ? (row.draft_response || `Thank you for your email. I have received it and will review it.\n\nBen`) : '',
        suggested_action: serviceEmailPhaseDescription(normalized)
      }
    }))
    setServiceEmailScanNote(normalized ? `Changed ${ids.size} visible email(s) to ${serviceEmailPhaseLabel(normalized)}.` : `Cleared category on ${ids.size} visible email(s).`)
  }

  function selectedRowsForCategory(actionGroup) {
    const normalized = normalizedServiceEmailActionGroup(actionGroup)
    return serviceEmailRowsForCurrentView().filter((row) => row.selected && row.status !== 'completed' && serviceEmailRowCategory(row) === normalized)
  }

  function openAcceptedExtractionReview(actionGroup = 'accepted') {
    const normalized = normalizedServiceEmailActionGroup(actionGroup)
    const rows = selectedRowsForCategory(normalized).length ? selectedRowsForCategory(normalized) : serviceEmailRowsForCurrentView().filter((row) => serviceEmailRowCategory(row) === normalized)
    if (!rows.length) {
      setServiceEmailScanNote(`No ${serviceEmailPhaseLabel(normalized)} emails to review for PDFs.`)
      return
    }
    setServiceInboxPhase(normalized)
    setShowAcceptedExtractionWindow(true)
    setSelectedPdfPreviewName(rows[0]?.suggested_document_name || rows[0]?.subject || '')
  }

  function updateServiceEmailAction(rowId, actionId, patch) {
    setServiceEmailRows((rows) => rows.map((row) => {
      if (row.id !== rowId) return row
      return {
        ...row,
        proposed_actions: (row.proposed_actions || []).map((action) => action.id === actionId ? { ...action, ...patch } : action)
      }
    }))
  }

  function serviceEmailRowsForCurrentView() {
    return serviceEmailRows
      .filter((row) => {
        if (row.moved_to_read) return false
        if (serviceInboxFilter !== 'all' && row.status !== serviceInboxFilter) return false
        const rowMailbox = row.mailbox_email || serviceEmailMailboxAddress(row.source_id)
        if (!serviceInboxMailboxMatches(rowMailbox)) return false
        if (serviceInboxFolderFilter !== 'all' && row.source_id !== serviceInboxFolderFilter) return false
        if (serviceInboxPhase !== 'all' && serviceEmailRowCategory(row) !== normalizedServiceEmailActionGroup(serviceInboxPhase)) return false
        return true
      })
      .sort((a, b) => new Date(b.received_at || 0) - new Date(a.received_at || 0))
  }

  function completeServiceEmailRows(rowIds, note, options = {}) {
    const ids = new Set(rowIds)
    setServiceEmailRows((rows) => {
      if (options.removeFromActiveList) return rows.filter((row) => !ids.has(row.id))
      return rows.map((row) => {
        if (!ids.has(row.id)) return row
        return {
          ...row,
          status: 'completed',
          moved_to_read: true,
          selected: false,
          response_sent: serviceEmailRowCategory(row) === 'response_mark_read' ? true : row.response_sent,
          completed_at: new Date().toISOString(),
          proposed_actions: (row.proposed_actions || []).map((action) => action.approved !== false ? { ...action, completed: true } : action)
        }
      })
    })
    setServiceEmailScanNote(note)
  }

  function approveServiceEmailRow(rowId) {
    completeServiceEmailRows([rowId], 'Approved mock actions and moved the email to the configured Read folder.')
  }

  function rejectServiceEmailRow(rowId) {
    setServiceEmailRows((rows) => rows.map((row) => row.id === rowId ? { ...row, status: 'rejected', moved_to_read: false, selected: false, rejected_at: new Date().toISOString() } : row))
  }

  async function moveSingleServiceEmailToRead(row, options = {}) {
    if (!row) return false
    const label = options.label || 'Moved individual no-response email to Read'
    setServiceEmailScanNote(`${label}: ${row.subject || ''}`)
    try {
      if (serviceGraphConfig.mode === 'live' && serviceGraphAuth.connected) {
        await moveLiveRowToRead(row)
      }
      maybeCreateServiceEmailBillingEntry(row, options.billingDescription || 'Service email no-response review')
      recordServiceEmailAction(options.actionType || 'move_to_read', row, {
        result: 'completed',
        notes: label,
        billing_minutes: row.billing_minutes || 0
      })
      setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
      setServiceEmailScanNote(`${label}. Removed from this review queue.`)
      return true
    } catch (error) {
      if (isGraphItemNotFound(error)) {
        recordServiceEmailAction(options.actionType || 'move_to_read', row, { result: 'already_removed', notes: error.message || String(error) })
        setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
        setServiceEmailScanNote(`${label}. Outlook says the email is already gone from the source folder, so it was removed from this queue.`)
        return true
      }
      recordServiceEmailAction(options.actionType || 'move_to_read', row, { result: 'failed', notes: error.message || String(error) })
      setServiceEmailScanNote(`${label} failed: ${error.message || error}`)
      alert(`${label} failed: ${error.message || error}`)
      return false
    }
  }

  async function processSingleFilingServiceEmail(row) {
    if (!row) return false
    const label = serviceEmailRowCategory(row) === 'accepted' ? 'Saved accepted PDF and moved email to Read' : 'Processed notification of service and moved email to Read'
    setServiceGraphBusy(true)
    try {
      setServiceEmailScanNote(`Saving PDF for ${row.subject || 'email'} using Microsoft Graph/browser folder access...`)
      const savedPdf = await saveDownloadedServicePdf(row, null, { tryDirectDownload: true, allowPick: true })
      if (!savedPdf) throw new Error('The PDF was not saved. Confirm the matter efile folder, allow folder access when prompted, and choose the PDF if the browser cannot fetch it automatically.')
      const savedInfo = typeof savedPdf === 'object' ? savedPdf : {}
      const billingEntry = maybeCreateServiceEmailBillingEntry(row, serviceEmailRowCategory(row) === 'accepted' ? 'Accepted e-filing review' : 'Notification of service review')
      if (serviceGraphConfig.mode === 'live' && serviceGraphAuth.connected) await moveLiveRowToRead(row)
      recordServiceEmailAction('save_pdf_and_move_to_read', row, {
        result: 'completed',
        notes: `${label}. PDF saved${billingEntry ? ', billing added' : ''}.`,
        billing_minutes: row.billing_minutes || 0,
        document_name: savedInfo.fileName || row.suggested_document_name || row.extracted_pdf_name || '',
        save_path: savedInfo.savedPath || serviceEmailSavePath(row)
      })
      setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
      setServiceEmailScanNote(`${label}. Removed from this review queue.`)
      return true
    } catch (error) {
      if (isGraphItemNotFound(error)) {
        recordServiceEmailAction('save_pdf_and_move_to_read', row, { result: 'already_removed', notes: error.message || String(error) })
        setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
        setServiceEmailScanNote('Email was already gone from the source folder, so it was removed from this queue.')
        return true
      }
      recordServiceEmailAction('save_pdf_and_move_to_read', row, { result: 'failed', notes: error.message || String(error), document_name: row.suggested_document_name || '' })
      setServiceEmailScanNote(`Save PDF / move failed: ${error.message || error}`)
      alert(`Save PDF / move failed: ${error.message || error}`)
      return false
    } finally {
      setServiceGraphBusy(false)
    }
  }

  async function sendSingleServiceEmailAndMove(row) {
    if (!row) return false
    setServiceGraphBusy(true)
    try {
      if (serviceGraphConfig.mode === 'live' && serviceGraphAuth.connected) await sendLiveServiceEmailResponse(row)
      maybeCreateServiceEmailBillingEntry(row, 'Service email response')
      if (serviceGraphConfig.mode === 'live' && serviceGraphAuth.connected) await moveLiveRowToRead(row)
      recordServiceEmailAction('send_response_and_move_to_read', row, { result: 'completed', notes: 'Sent response and moved email to Read.', billing_minutes: row.billing_minutes || 0 })
      setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
      setServiceEmailScanNote('Sent response, logged billing, moved email to Read, and removed it from this queue.')
      return true
    } catch (error) {
      recordServiceEmailAction('send_response_and_move_to_read', row, { result: 'failed', notes: error.message || String(error), billing_minutes: row.billing_minutes || 0 })
      setServiceEmailScanNote(`Send/move failed: ${error.message || error}`)
      alert(`Send/move failed: ${error.message || error}`)
      return false
    } finally {
      setServiceGraphBusy(false)
    }
  }

  async function moveSelectedServiceEmailsToRead() {
    const rows = serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed' && serviceEmailRowCategory(row) === 'no_response')

    if (!rows.length) {
      setServiceEmailScanNote('No visible no-response emails to move. Check the no-response column for any emails you want moved, then try again.')
      return
    }

    if (serviceGraphConfig.mode !== 'live' || !serviceGraphAuth.connected) {
      completeServiceEmailRows(rows.map((row) => row.id), `Moved ${rows.length} selected mock email(s) to Read.`, { removeFromActiveList: true })
      return
    }

    setServiceGraphBusy(true)
    let moved = 0
    const movedIds = []
    const failures = []
    const total = rows.length

    try {
      for (let index = 0; index < rows.length; index += 1) {
        const row = rows[index]
        setServiceEmailScanNote(`Moving ${index + 1} of ${total} to Read... ${row.subject || ''}`)
        try {
          const ok = await moveLiveRowToRead(row)
          if (ok) {
            moved += 1
            movedIds.push(row.id)
            maybeCreateServiceEmailBillingEntry(row, 'Service email no-response review')
            recordServiceEmailAction('bulk_move_to_read', row, { result: 'completed', notes: `Bulk move ${index + 1} of ${total}`, billing_minutes: row.billing_minutes || 0 })
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            failures.push(`${row.subject || row.id}: missing Outlook message ID or source mailbox`)
          }
        } catch (error) {
          if (isGraphItemNotFound(error)) {
            moved += 1
            movedIds.push(row.id)
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            failures.push(`${row.subject || row.id}: ${error.message || error}`)
          }
        }
      }

      if (failures.length) {
        console.error('Move to Read failures:', failures)
        const message = `Moved/cleared ${moved} email(s). ${failures.length} failed. First failure: ${failures[0]}`
        setServiceEmailScanNote(message)
        alert(message)
      } else {
        setServiceEmailScanNote(`Moved/cleared ${moved} live Outlook email(s) to Read and removed them from this queue.`)
      }
    } finally {
      setServiceGraphBusy(false)
    }
  }

  async function sendSelectedResponsesAndMoveToRead() {
    const rows = serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed' && serviceEmailRowCategory(row) === 'response_mark_read')
    if (!rows.length) {
      setServiceEmailScanNote('No visible response-required emails to send. Check the response column for any emails you want handled, then try again.')
      return
    }
    if (serviceGraphConfig.mode !== 'live' || !serviceGraphAuth.connected) {
      completeServiceEmailRows(rows.map((row) => row.id), `Sent ${rows.length} mock response(s), added approved billing entries, and moved the email(s) to Read.`, { removeFromActiveList: true })
      return
    }
    setServiceGraphBusy(true)
    let sent = 0
    let moved = 0
    const movedIds = []
    const failures = []
    try {
      for (let index = 0; index < rows.length; index += 1) {
        const row = rows[index]
        setServiceEmailScanNote(`Sending/moving ${index + 1} of ${rows.length}... ${row.subject || ''}`)
        try {
          if (await sendLiveServiceEmailResponse(row)) sent += 1
          if (await moveLiveRowToRead(row)) {
            moved += 1
            movedIds.push(row.id)
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          }
        } catch (error) {
          if (isGraphItemNotFound(error)) {
            moved += 1
            movedIds.push(row.id)
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            failures.push(`${row.subject || row.id}: ${error.message || error}`)
          }
        }
      }
      if (failures.length) {
        console.error('Send/move failures:', failures)
        const message = `Sent ${sent} response(s), moved/cleared ${moved} email(s). ${failures.length} failed. First failure: ${failures[0]}`
        setServiceEmailScanNote(message)
        alert(message)
      } else {
        setServiceEmailScanNote(`Sent ${sent} live response(s), moved/cleared ${moved} email(s), and removed them from this queue.`)
      }
    } finally {
      setServiceGraphBusy(false)
    }
  }

  async function approveSelectedFilingActions() {
    const rows = serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed' && ['accepted', 'notification_service'].includes(serviceEmailRowCategory(row)))
    if (!rows.length) {
      setServiceEmailScanNote('No visible accepted/notification emails to approve. Check the accepted or notification column for the emails you want handled, then try again.')
      return
    }
    if (serviceGraphConfig.mode !== 'live' || !serviceGraphAuth.connected) {
      rows.forEach((row, index) => {
        maybeCreateServiceEmailBillingEntry(row, serviceEmailRowCategory(row) === 'accepted' ? 'Accepted e-filing review' : 'Notification of service review')
        recordServiceEmailAction('bulk_process_filing_email', row, {
          result: 'completed',
          notes: `Mock bulk process ${index + 1} of ${rows.length}`,
          billing_minutes: row.billing_minutes || 0,
          document_name: row.suggested_document_name || row.extracted_pdf_name || '',
          save_path: serviceEmailSavePath(row)
        })
      })
      completeServiceEmailRows(rows.map((row) => row.id), `Completed approved filing actions for ${rows.length} mock email(s), logged billing/actions, and moved them to Read.`, { removeFromActiveList: true })
      return
    }

    setServiceGraphBusy(true)
    let processed = 0
    let moved = 0
    let saved = 0
    let billed = 0
    const failures = []
    const total = rows.length

    try {
      for (let index = 0; index < rows.length; index += 1) {
        const row = rows[index]
        const category = serviceEmailRowCategory(row)
        const description = category === 'accepted' ? 'Accepted e-filing review' : 'Notification of service review'
        const rowLabel = row.subject || row.extracted_pdf_name || row.id
        setServiceEmailScanNote(`Processing filing/service email ${index + 1} of ${total}: ${rowLabel}`)

        try {
          // Online version: use Microsoft Graph/browser folder access instead of the old
          // local Node helper. The browser writes directly to the selected matter efile
          // folder with the row's Document name after the user grants folder access.
          const savedPdf = await saveDownloadedServicePdf(row, null, { tryDirectDownload: true, allowPick: true })
          if (!savedPdf) throw new Error('PDF was not saved. Confirm folder access and select the PDF if prompted.')
          const savedInfo = typeof savedPdf === 'object' ? savedPdf : {}
          saved += 1

          const billingEntry = maybeCreateServiceEmailBillingEntry(row, description)
          if (billingEntry) billed += 1

          if (await moveLiveRowToRead(row)) {
            moved += 1
            processed += 1
            recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
              result: 'completed',
              notes: `Bulk processed ${index + 1} of ${total}: saved PDF${billingEntry ? ', added billing entry' : ''}, and moved email to Read.`,
              billing_minutes: row.billing_minutes || 0,
              document_name: savedInfo.fileName || row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
              save_path: savedInfo.savedPath || serviceEmailSavePath(row)
            })
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            throw new Error('Outlook did not confirm the email moved to the Read folder.')
          }
        } catch (error) {
          if (isGraphItemNotFound(error)) {
            processed += 1
            moved += 1
            recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
              result: 'already_removed',
              notes: `Email was already gone from the source folder after PDF save attempt: ${error.message || error}`,
              billing_minutes: row.billing_minutes || 0,
              document_name: row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
              save_path: serviceEmailSavePath(row)
            })
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
              result: 'failed',
              notes: error.message || String(error),
              billing_minutes: row.billing_minutes || 0,
              document_name: row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
              save_path: serviceEmailSavePath(row)
            })
            failures.push(`${rowLabel}: ${error.message || error}`)
          }
        }
      }

      if (failures.length) {
        console.error('Bulk filing/service failures:', failures)
        const message = `Processed ${processed} of ${total}. Saved ${saved} PDF(s), moved ${moved} email(s), logged ${billed} billing entr${billed === 1 ? 'y' : 'ies'}. ${failures.length} failed. First failure: ${failures[0]}`
        setServiceEmailScanNote(message)
        alert(message)
      } else {
        setServiceEmailScanNote(`Bulk complete. Saved ${saved} PDF(s), moved ${moved} email(s) to Read, added/logged billing where minutes were set, added document records/tags, and removed processed rows from this queue.`)
      }
    } finally {
      setServiceGraphBusy(false)
    }
  }

  function resetServiceEmailDemo() {
    setServiceEmailRows(defaultServiceEmailIntakeRows)
    setServiceEmailSources(defaultServiceEmailSources)
    setSelectedServiceEmailId('sei-service-001')
    setServiceInboxFilter('needs_review')
    setServiceInboxMailboxFilter('all')
    setServiceInboxPhase('no_response')
    setServiceInboxViewMode('grouped')
    setServiceInboxFolderFilter('all')
    setServiceInboxSortMode('folder_date')
    setServiceInboxRowDensity('normal')
    setCollapsedServiceInboxSections({})
    setServiceEmailScanNote('Reset to the mock Outlook review queue with three mailboxes and service-folder sections.')
  }

  function scanServiceEmailMock() {
    setServiceEmailRows((rows) => {
      const existing = new Set(rows.map((row) => row.id))
      const nextRows = [...rows]
      defaultServiceEmailIntakeRows.forEach((row) => {
        if (!existing.has(row.id)) nextRows.push(row)
      })
      return nextRows
    })
    setServiceEmailScanNote('Mock scan complete. Live Microsoft Graph connection can later replace these mock emails with real Outlook messages and OneDrive actions.')
  }

  function updateServiceEmailSource(sourceId, field, value) {
    setServiceEmailSources((sources) => sources.map((source) => source.id === sourceId ? { ...source, [field]: value } : source))
  }

  function addServiceEmailSource() {
    const id = `src-${Date.now()}`
    setServiceEmailSources((sources) => [
      ...sources,
      {
        id,
        account_label: 'New email',
        mailbox_email: 'service@beveridgelawfirm.com',
        outlook_folder_name: 'New Outlook Folder',
        monitor_section: 'New section',
        filing_category: 'Incoming Service',
        default_onedrive_folder: 'C:\\Users\\bever\\OneDrive - Beveridge Law Firm, PLLC\\All Matters\\1. Open Cases\\{Matter}\\efile',
        read_folder_name: 'New Outlook Folder / Read',
        default_billing_minutes: 6,
        discovery_response_days: 30,
        roll_deadlines_forward: true,
        enabled: true
      }
    ])
  }

  function removeServiceEmailSource(sourceId) {
    setServiceEmailSources((sources) => sources.filter((source) => source.id !== sourceId))
  }

