  function renderServiceInboxTable(rows, title) {
    const collapsed = collapsedServiceInboxSections[title]
    const showAccountColumns = serviceInboxSortMode === 'date' || serviceInboxViewMode === 'all'
    const activeRows = rows.filter((row) => row.status !== 'completed')
    const allActionSelected = activeRows.length > 0 && activeRows.every((row) => row.selected)
    const allPhaseSelected = activeRows.length > 0 && activeRows.every((row) => row.phase_selected)

    return (
      <section key={title} style={{ border: '1px solid #d5dce3', borderRadius: 8, overflow: 'hidden', background: 'white', marginBottom: 14 }}>
        <div style={{ background: '#f1f5f9', padding: '9px 12px', display: 'flex', justifyContent: 'space-between', gap: 10, alignItems: 'center' }}>
          <button
            type="button"
            onClick={() => setCollapsedServiceInboxSections((current) => ({ ...current, [title]: !current[title] }))}
            style={{ margin: 0, fontWeight: 800, background: 'transparent', border: 0, cursor: 'pointer', textAlign: 'left', fontSize: 18 }}
          >
            {collapsed ? '▶' : '▼'} {title}
          </button>
          <span style={{ color: '#64748b' }}>{rows.length} email(s)</span>
        </div>
        {!collapsed && (
          <div style={{ overflowX: 'auto' }}>
            <table cellPadding="0" style={{ borderCollapse: 'collapse', width: '100%', minWidth: showAccountColumns ? 1780 : 1540 }}>
              <thead>
                <tr style={{ background: '#f8fafc' }}>
                  {serviceEmailCategoryValues.map((category) => {
                    const allCategorySelected = activeRows.length > 0 && activeRows.every((row) => serviceEmailRowCategory(row) === category)
                    return (
                      <th key={category} style={{ padding: 6, width: 96, textAlign: 'center', background: serviceEmailCategoryColor(category), fontSize: 12 }}>
                        {serviceEmailPhaseLabel(category)}<br />
                        <input
                          type="checkbox"
                          title={`Check to mark all visible emails in this section as ${serviceEmailPhaseLabel(category)}. Uncheck to clear this category back to no-response.`}
                          checked={allCategorySelected}
                          onChange={(e) => {
                            const ids = e.target.checked
                              ? activeRows.map((row) => row.id)
                              : activeRows.filter((row) => serviceEmailRowCategory(row) === category).map((row) => row.id)
                            if (ids.length) setServiceEmailRowsCategory(ids, e.target.checked ? category : '')
                          }}
                        />
                      </th>
                    )
                  })}
                  {showAccountColumns && <th style={{ padding: 8, textAlign: 'left' }}>Email account</th>}
                  {showAccountColumns && <th style={{ padding: 8, textAlign: 'left' }}>Folder/section</th>}
                  <th style={{ padding: 8, textAlign: 'left' }}>Received</th>
                  <th style={{ padding: 8, textAlign: 'left' }}>Sender</th>
                  <th style={{ padding: 8, textAlign: 'left' }}>Subject / content / suggested action</th>
                  <th style={{ padding: 8, textAlign: 'left' }}>Matter / billing</th>
                  <th style={{ padding: 8, textAlign: 'left' }}>Status</th>
                  <th style={{ padding: 8, textAlign: 'left' }}>Row action</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((row) => renderServiceEmailRow(row))}
                {!rows.length && <tr><td colSpan={showAccountColumns ? 12 : 10} style={{ padding: 16, color: '#64748b', textAlign: 'center' }}>No emails in this section.</td></tr>}
              </tbody>
            </table>
          </div>
        )}
      </section>
    )
  }


  async function saveVisibleFilingPdfsAndMoveToRead() {
    const rows = serviceEmailRowsForCurrentView().filter((row) => row.status !== 'completed' && ['accepted', 'notification_service'].includes(serviceEmailRowCategory(row)))
    if (!rows.length) {
      setServiceEmailScanNote('No accepted/notification emails are visible to save and move.')
      return
    }
    if (!window.confirm(`Save/process ${rows.length} filing/service email(s), log billing/actions, then move them to Read?`)) return

    setServiceGraphBusy(true)
    let saved = 0
    let moved = 0
    let billed = 0
    const failures = []
    const total = rows.length

    try {
      for (let index = 0; index < rows.length; index += 1) {
        const row = rows[index]
        const category = serviceEmailRowCategory(row)
        const description = category === 'accepted' ? 'Accepted e-filing review' : 'Notification of service review'
        const rowLabel = row.subject || row.suggested_document_name || row.id
        setServiceEmailScanNote(`Bulk saving ${index + 1} of ${total}: ${rowLabel}`)

        try {
          // Online version: use Microsoft Graph/browser folder access instead of the old
          // local Node helper. Do not use Chrome's Save As dialog; write directly to
          // the selected matter efile folder with the row's Document name.
          const savedPdf = await saveDownloadedServicePdf(row, null, { tryDirectDownload: true, allowPick: true })
          if (!savedPdf) throw new Error('PDF was not saved. Confirm folder access and select the PDF if prompted.')
          const savedInfo = typeof savedPdf === 'object' ? savedPdf : {}
          saved += 1

          const billingEntry = maybeCreateServiceEmailBillingEntry(row, description)
          if (billingEntry) billed += 1

          if (serviceGraphConfig.mode === 'live' && serviceGraphAuth.connected) {
            await moveLiveRowToRead(row)
          }
          moved += 1

          recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
            result: 'completed',
            notes: `Bulk processed ${index + 1} of ${total}: saved PDF${billingEntry ? ', added billing entry' : ''}, and moved email to Read.`,
            billing_minutes: row.billing_minutes || 0,
            document_name: savedInfo.fileName || row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
            save_path: savedInfo.savedPath || serviceEmailSavePath(row)
          })
          setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
        } catch (error) {
          if (isGraphItemNotFound(error)) {
            moved += 1
            recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
              result: 'already_removed',
              notes: `Email was already gone from the source folder after save attempt: ${error.message || error}`,
              billing_minutes: row.billing_minutes || 0,
              document_name: row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
              save_path: serviceEmailSavePath(row)
            })
            setServiceEmailRows((current) => current.filter((item) => item.id !== row.id))
          } else {
            recordServiceEmailAction('bulk_save_pdf_and_move_to_read', row, {
              result: 'failed',
              notes: error.message || String(error),
              billing_minutes: row.billing_minutes || 0,
              document_name: row.suggested_document_name || row.saved_pdf_name || row.extracted_pdf_name || '',
              save_path: serviceEmailSavePath(row)
            })
            failures.push(`${rowLabel}: ${error.message || error}`)
          }
        }
      }

      const message = failures.length
        ? `Bulk processed ${saved} PDF(s), moved/cleared ${moved} email(s), logged ${billed} billing entr${billed === 1 ? 'y' : 'ies'}. ${failures.length} failed. First failure: ${failures[0]}`
        : `Bulk complete. Saved ${saved} PDF(s) only to the selected matter efile folders, moved ${moved} email(s) to Read, logged ${billed} billing entr${billed === 1 ? 'y' : 'ies'}, and wrote the Service email action log.`
      setServiceEmailScanNote(message)
      if (failures.length) alert(message)
    } finally {
      setServiceGraphBusy(false)
    }
  }

